import React, { createContext, useContext, useState, useEffect } from 'react';
import { Project, Client, User, ODTContextType, ProjectComment } from './types';

// Mocking Firebase Realtime Database behavior for the environment
// In a real scenario, you'd use 'import { ref, onValue, update, push } from "firebase/database"'
const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [loading, setLoading] = useState(true);

  // 1. Persistencia: Cargar usuario desde localStorage
  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        setUser(JSON.parse(savedSession));
      } catch (e) {
        console.error("Error parsing session", e);
      }
    }
  }, []);

  // 2. Sincronización Real-time (Simulated Firebase onValue)
  useEffect(() => {
    // This would be ref(db, 'projects') and onValue(...)
    const initialProjects: Project[] = [
      {
        id: 'ODT-2024-001',
        empresa: 'TechCorp Global',
        marca: 'Zenith',
        producto: 'Lanzamiento Q3',
        etapa_actual: 'Diseño Creativo',
        status: 'En Proceso',
        createdAt: new Date(Date.now() - 80 * 60 * 60 * 1000).toISOString(), // > 72h ago
        updatedAt: new Date(Date.now() - 10 * 60 * 60 * 1000).toISOString(),
        areas_seleccionadas: ['Diseño'],
        asignaciones: [],
        tracking: [],
        comentarios: [],
        monto_proyectado: 50000
      },
      {
        id: 'ODT-2024-002',
        empresa: 'BioHealth Solutions',
        marca: 'LifeGen',
        producto: 'QA Test',
        etapa_actual: 'Revisión QA',
        status: 'QA',
        createdAt: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(),
        updatedAt: new Date(Date.now() - 25 * 60 * 60 * 1000).toISOString(), // > 24h ago
        areas_seleccionadas: ['Branding'],
        asignaciones: [],
        tracking: [],
        comentarios: [],
        monto_proyectado: 12500
      }
    ];

    const initialClients: Client[] = [
      { id: 'C001', name: 'TechCorp Global', ownerId: 'U002' },
      { id: 'C002', name: 'BioHealth Solutions', ownerId: 'U003' }
    ];

    setProjects(initialProjects);
    setClients(initialClients);
    setLoading(false);
  }, []);

  // 3. SLA Audit: Lógica de Alerta
  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);

    const hoursInProduction = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hoursInQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);

    if (project.status === 'En Proceso' && hoursInProduction > 72) {
      return { isAlert: true, reason: 'Excede 72h en Producción' };
    }
    if (project.status === 'QA' && hoursInQA > 24) {
      return { isAlert: true, reason: 'Excede 24h en QA' };
    }
    return { isAlert: false };
  };

  // 4. Sistema de Log & Actualización
  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    const project = projects.find(p => p.id === projectId);
    if (!project || !user) return;

    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `CAMBIO DE ESTADO: de "${project.status}" a "${newStatus}". Motivo: ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const updatedProject: Project = {
      ...project,
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...project.comentarios]
    };

    // Firebase simulation: update(ref(db, `projects/${projectId}`), updatedProject)
    setProjects(prev => prev.map(p => p.id === projectId ? updatedProject : p));
  };

  // 5. Reasignación: Update ownerId in client
  const reassignAccount = async (clientId: string, newOwnerId: string) => {
    // Update Client Folder Owner
    setClients(prev => prev.map(c => c.id === clientId ? { ...c, ownerId: newOwnerId } : c));

    // Log in related projects if needed
    const relatedProjects = projects.filter(p => p.empresa === clients.find(c => c.id === clientId)?.name);

    for (const p of relatedProjects) {
      const logEntry: ProjectComment = {
        id: `sys-reassign-${Date.now()}`,
        authorId: user?.id || 'system',
        authorName: 'SISTEMA',
        text: `REASIGNACIÓN DE CUENTA: Nuevo responsable ID: ${newOwnerId}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      };
      setProjects(prev => prev.map(proj => proj.id === p.id ? { ...proj, comentarios: [logEntry, ...proj.comentarios] } : proj));
    }
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, loading, updateProjectStatus, reassignAccount, checkSLA }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (context === undefined) {
    throw new Error('useODT must be used within an ODTProvider');
  }
  return context;
};

