export interface ProjectComment {
  id: string;
  authorId: string;
  authorName: string;
  text: string;
  createdAt: string;
  isSystemEvent?: boolean;
}

export interface ProjectAssignment {
  area: string;
  usuarioId: string;
  status: 'pendiente' | 'en_progreso' | 'completado';
}

export interface Project {
  id: string;
  empresa: string;
  marca: string;
  producto: string;
  etapa_actual: string;
  status: 'Borrador' | 'En Proceso' | 'Correcciones' | 'QA' | 'Finalizado' | 'Cancelado';
  correccion_ok?: boolean;
  areas_seleccionadas: string[];
  asignaciones: ProjectAssignment[];
  tracking: any[];
  comentarios: ProjectComment[];
  monto_proyectado: number;
  facturado?: boolean;
  justificacion_no_facturado?: string;
  ownerId?: string; // Executive ID
  createdAt: string;
  updatedAt: string;
}

export interface Client {
  id: string;
  name: string;
  notes?: string;
  ownerId: string;
}

export type ViewState = 
  | 'login' 
  | 'dashboard' 
  | 'leader-dashboard'
  | 'my-projects' 
  | 'clients' 
  | 'users' 
  | 'qa-box' 
  | 'finances' 
  | 'project-detail';

export interface ODTContextType {
  user: User | null;
  projects: Project[];
  clients: Client[];
  users: User[];
  loading: boolean;
  login: (username: string, pass: string) => Promise<boolean>;
  logout: () => void;
  updateProjectStatus: (projectId: string, newStatus: Project['status'], comment: string) => Promise<void>;
  updateBilling: (projectId: string, facturado: boolean, justification?: string) => Promise<void>;
  checkSLA: (project: Project) => { isAlert: boolean; reason?: string };
  delegateProject: (projectId: string, area: string, userId: string) => Promise<void>;
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Project, Client, User, ODTContextType, ProjectComment, UserRole } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const MOCK_USERS: User[] = [
  { id: 'U001', nombre: 'Admin Master', usuario: 'admin', nivel: UserRole.Admin, departamento: 'Gerencia' },
  { id: 'U002', nombre: 'QA Specialist', usuario: 'qa', nivel: UserRole.QA, departamento: 'Calidad' },
  { id: 'U003', nombre: 'Finanzas Lead', usuario: 'money', nivel: UserRole.Finanzas, departamento: 'Contabilidad' },
  { id: 'U004', nombre: 'Carlos Cuentas', usuario: 'cuentas', nivel: UserRole.Cuentas_Opera, departamento: 'Cuentas' },
  { id: 'U005', nombre: 'Elena Diseño', usuario: 'diseno', nivel: UserRole.Diseno_Opera, departamento: 'Creativo' },
  { id: 'U006', nombre: 'Pedro Creativo', usuario: 'pedro', nivel: UserRole.Creativo_Opera, departamento: 'Creativo' },
  { id: 'U007', nombre: 'Sofía Lider', usuario: 'sofia', nivel: UserRole.Creativo_Lider, departamento: 'Creativo' },
  { id: 'U008', nombre: 'Juan Diseño Lider', usuario: 'juan', nivel: UserRole.Diseno_Lider, departamento: 'Creativo' },
];

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        setUser(JSON.parse(savedSession));
      } catch (e) {
        console.error("Error parsing session", e);
      }
    }

    const initialProjects: Project[] = [
      {
        id: 'ODT-2024-001',
        empresa: 'TechCorp',
        marca: 'Zenith',
        producto: 'Launch',
        etapa_actual: 'Producción',
        status: 'En Proceso',
        createdAt: new Date(Date.now() - 90 * 60 * 60 * 1000).toISOString(),
        updatedAt: new Date().toISOString(),
        areas_seleccionadas: ['Diseño', 'Creativo'],
        asignaciones: [{ area: 'Diseño', usuarioId: 'U005', status: 'pendiente' }],
        tracking: [],
        comentarios: [],
        monto_proyectado: 50000,
        facturado: false,
        ownerId: 'U004'
      },
      {
        id: 'ODT-2024-002',
        empresa: 'BioHealth',
        marca: 'Life',
        producto: 'Test',
        etapa_actual: 'QA',
        status: 'QA',
        createdAt: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(),
        updatedAt: new Date(Date.now() - 30 * 60 * 60 * 1000).toISOString(),
        areas_seleccionadas: ['Branding'],
        asignaciones: [],
        tracking: [],
        comentarios: [],
        monto_proyectado: 12500,
        facturado: false,
        ownerId: 'U004'
      },
      {
        id: 'ODT-2024-003',
        empresa: 'Global Media',
        marca: 'Stream',
        producto: 'Ad Campaign',
        etapa_actual: 'Diseño',
        status: 'En Proceso',
        createdAt: new Date(Date.now() - 12 * 60 * 60 * 1000).toISOString(),
        updatedAt: new Date().toISOString(),
        areas_seleccionadas: ['Creativo'],
        asignaciones: [{ area: 'Creativo', usuarioId: 'U006', status: 'en_progreso' }],
        tracking: [],
        comentarios: [],
        monto_proyectado: 22000,
        facturado: true,
        ownerId: 'U001'
      }
    ];
    setProjects(initialProjects);
    setClients([{ id: 'C001', name: 'TechCorp', ownerId: 'U004' }]);
    setLoading(false);
  }, []);

  const login = async (username: string, pass: string): Promise<boolean> => {
    const foundUser = MOCK_USERS.find(u => u.usuario === username && pass === '123');
    if (foundUser) {
      setUser(foundUser);
      localStorage.setItem('apc_session', JSON.stringify(foundUser));
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hoursInProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hoursInQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);

    if (project.status === 'En Proceso' && hoursInProd > 72) return { isAlert: true, reason: 'Prod > 72h' };
    if (project.status === 'QA' && hoursInQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    setProjects(prev => prev.map(p => p.id === projectId ? { 
      ...p, status: newStatus, updatedAt: new Date().toISOString(), comentarios: [systemComment, ...p.comentarios] 
    } : p));
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    setProjects(prev => prev.map(p => p.id === projectId ? {
      ...p, facturado, justificacion_no_facturado: justification, updatedAt: new Date().toISOString()
    } : p));
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: Área ${area} asignada a ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    setProjects(prev => prev.map(p => {
      if (p.id !== projectId) return p;
      const filteredAsignaciones = p.asignaciones.filter(a => a.area !== area);
      return {
        ...p,
        asignaciones: [...filteredAsignaciones, { area, usuarioId: userId, status: 'pendiente' }],
        comentarios: [systemComment, ...p.comentarios],
        updatedAt: new Date().toISOString()
      };
    }));
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, users, loading, login, logout, updateProjectStatus, updateBilling, checkSLA, delegateProject }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState, useMemo } from 'react';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const AdminDashboard: React.FC = () => {
  const { projects, users } = useODT();
  const [executiveFilter, setExecutiveFilter] = useState('all');
  const [periodFilter, setPeriodFilter] = useState('this-month');

  const executives = useMemo(() => 
    users.filter(u => u.nivel === UserRole.Cuentas_Opera || u.nivel === UserRole.Cuentas_Lider), 
  [users]);

  const filteredProjects = useMemo(() => {
    let filtered = projects;
    if (executiveFilter !== 'all') {
      filtered = filtered.filter(p => p.ownerId === executiveFilter);
    }
    // Simple period simulation logic
    return filtered;
  }, [projects, executiveFilter, periodFilter]);

  const saturationData = useMemo(() => {
    const counts: Record<string, number> = {
      'Creativo': 0,
      'Diseño': 0,
      'Cuentas': 0,
      'QA': 0,
      'Finanzas': 0
    };

    projects.forEach(p => {
      if (p.status !== 'Finalizado' && p.status !== 'Cancelado') {
        p.areas_seleccionadas.forEach(area => {
          if (counts[area] !== undefined) counts[area]++;
          else if (area === 'Social Media') counts['Diseño']++; // Grouping example
        });
      }
    });

    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [projects]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900">Dashboard Administrativo</h1>
          <p className="text-slate-500 font-medium">Análisis de rendimiento y saturación operativa</p>
        </div>

        <div className="flex flex-wrap gap-2">
          <select 
            className="bg-white border rounded-lg px-3 py-2 text-xs font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
            value={executiveFilter}
            onChange={(e) => setExecutiveFilter(e.target.value)}
          >
            <option value="all">TODOS LOS EJECUTIVOS</option>
            {executives.map(e => <option key={e.id} value={e.id}>{e.nombre.toUpperCase()}</option>)}
          </select>

          <select 
            className="bg-white border rounded-lg px-3 py-2 text-xs font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
            value={periodFilter}
            onChange={(e) => setPeriodFilter(e.target.value)}
          >
            <option value="this-month">ESTE MES</option>
            <option value="last-month">MES PASADO</option>
            <option value="this-year">ESTE AÑO</option>
          </select>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border shadow-sm">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6">Saturación por Departamento (ODTs Activas)</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={saturationData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                    dataKey="name" 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} 
                />
                <YAxis 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}}
                />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                  {saturationData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.value > 5 ? '#ef4444' : '#3b82f6'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-slate-900 p-6 rounded-2xl text-white shadow-xl">
             <h3 className="text-blue-400 text-[10px] font-black uppercase tracking-widest mb-4">Monto Proyectado</h3>
             <p className="text-4xl font-black mb-1">${filteredProjects.reduce((a, b) => a + b.monto_proyectado, 0).toLocaleString()}</p>
             <p className="text-xs text-slate-400">Basado en {filteredProjects.length} ODTs filtradas</p>
          </div>

          <div className="bg-white p-6 rounded-2xl border shadow-sm">
             <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-4">Mix de Estados</h3>
             <div className="space-y-3">
                <StatusRow label="En Proceso" count={filteredProjects.filter(p => p.status === 'En Proceso').length} color="blue" />
                <StatusRow label="QA / Revisión" count={filteredProjects.filter(p => p.status === 'QA').length} color="amber" />
                <StatusRow label="Finalizados" count={filteredProjects.filter(p => p.status === 'Finalizado').length} color="emerald" />
                <StatusRow label="Cancelados" count={filteredProjects.filter(p => p.status === 'Cancelado').length} color="rose" />
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatusRow = ({ label, count, color }: any) => (
  <div className="flex justify-between items-center text-sm">
    <span className="font-semibold text-slate-600">{label}</span>
    <span className={`px-2 py-0.5 rounded-full bg-${color}-50 text-${color}-600 font-black text-xs border border-${color}-100`}>{count}</span>
  </div>
);

export default AdminDashboard;

import React, { useMemo } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Project } from './types';

const LeaderDashboard: React.FC = () => {
  const { user, projects, users, checkSLA, delegateProject } = useODT();

  const teamMembers = useMemo(() => {
    if (!user) return [];
    // If Creativo Lider, show Creative team. If Diseno Lider, show Design team.
    const targetDept = user.departamento;
    return users.filter(u => u.departamento === targetDept && u.id !== user.id);
  }, [user, users]);

  const memberStats = useMemo(() => {
    return teamMembers.map(m => {
      const assignedProjects = projects.filter(p => 
        p.asignaciones.some(a => a.usuarioId === m.id)
      );
      const total = assignedProjects.length;
      const delayed = assignedProjects.filter(p => checkSLA(p).isAlert).length;
      const onTime = total - delayed;

      return { ...m, total, onTime, delayed };
    });
  }, [teamMembers, projects, checkSLA]);

  // Projects pending delegation in this lead's area
  const pendingProjects = useMemo(() => {
    if (!user) return [];
    const area = user.nivel === UserRole.Creativo_Lider ? 'Creativo' : 'Diseño';
    return projects.filter(p => 
      p.areas_seleccionadas.includes(area) && 
      !p.asignaciones.some(a => a.area === area) &&
      p.status !== 'Finalizado'
    );
  }, [user, projects]);

  return (
    <div className="space-y-8 animate-fadeIn">
      <header>
        <h1 className="text-3xl font-black text-slate-900">Gestión de Equipo</h1>
        <p className="text-slate-500 font-medium">Control de cargas de trabajo y delegación ISO 9001</p>
      </header>

      <section className="space-y-4">
        <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">Monitoreo de Colaboradores</h2>
        <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
              <tr>
                <th className="px-6 py-4">Integrante</th>
                <th className="px-6 py-4 text-center">Total ODTs</th>
                <th className="px-6 py-4 text-center">En Tiempo</th>
                <th className="px-6 py-4 text-center">Atrasadas</th>
                <th className="px-6 py-4">Status de Carga</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {memberStats.map(m => (
                <tr key={m.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-500 text-[10px]">{m.nombre.substring(0,2)}</div>
                      <div className="font-bold text-slate-800">{m.nombre}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-center font-black">{m.total}</td>
                  <td className="px-6 py-4 text-center">
                    <span className="text-emerald-600 font-bold">{m.onTime}</span>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <span className={`${m.delayed > 0 ? 'text-rose-500 font-bold' : 'text-slate-300'}`}>{m.delayed}</span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="w-full bg-slate-100 rounded-full h-1.5 max-w-[100px]">
                      <div className={`h-1.5 rounded-full ${m.total > 5 ? 'bg-rose-500' : 'bg-blue-500'}`} style={{width: `${Math.min(100, (m.total/10)*100)}%`}}></div>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <section className="space-y-4">
        <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">Delegación Pendiente</h2>
        {pendingProjects.length === 0 ? (
          <div className="p-8 bg-slate-100 rounded-2xl border-2 border-dashed border-slate-200 text-center text-slate-400 italic text-sm">
            Todas las ODTs de tu área han sido delegadas correctamente.
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {pendingProjects.map(p => (
              <div key={p.id} className="bg-white p-5 rounded-2xl border shadow-sm flex flex-col justify-between gap-4">
                <div>
                  <div className="flex justify-between items-start mb-2">
                    <span className="text-[10px] font-black text-blue-600 font-mono tracking-tighter">{p.id}</span>
                    <span className="text-[10px] bg-amber-50 text-amber-600 px-2 py-0.5 rounded-full font-bold border border-amber-100 uppercase">Sin Delegar</span>
                  </div>
                  <h4 className="font-bold text-slate-800 truncate">{p.empresa}</h4>
                  <p className="text-xs text-slate-500 mb-2">{p.producto}</p>
                </div>

                <div className="flex items-center gap-2 pt-4 border-t border-slate-50">
                   <select 
                    className="flex-1 bg-slate-50 border rounded-lg px-3 py-2 text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500"
                    onChange={(e) => {
                      const area = user?.nivel === UserRole.Creativo_Lider ? 'Creativo' : 'Diseño';
                      if(e.target.value) delegateProject(p.id, area, e.target.value);
                    }}
                    defaultValue=""
                   >
                     <option value="" disabled>SELECCIONAR INTEGRANTE...</option>
                     {teamMembers.map(m => <option key={m.id} value={m.id}>{m.nombre.toUpperCase()}</option>)}
                   </select>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>
    </div>
  );
};

export default LeaderDashboard;

import React, { useState, useEffect } from 'react';
import { useODT } from './ODTContext';
import { UserRole, ViewState } from './types';
import { Icons } from './constants';

const Login: React.FC = () => {
  const { login } = useODT();
  const [u, setU] = useState('');
  const [p, setP] = useState('');
  const [error, setError] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const success = await login(u, p);
    if (!success) setError(true);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 p-6">
      <div className="w-full max-w-md animate-fadeIn">
        <div className="bg-white rounded-2xl shadow-2xl overflow-hidden">
          <div className="bg-blue-600 p-8 text-center">
            <div className="w-16 h-16 bg-white/20 rounded-2xl mx-auto flex items-center justify-center text-white text-3xl font-black mb-4">ISO</div>
            <h1 className="text-white text-2xl font-bold tracking-tight">ODT Manager</h1>
            <p className="text-blue-100 text-sm mt-1">Gestión Normativa ISO 9001:2015</p>
          </div>
          <form className="p-8 space-y-6" onSubmit={handleSubmit}>
            {error && <div className="p-3 bg-rose-50 text-rose-600 text-xs font-bold rounded-lg border border-rose-100">Credenciales incorrectas (tip: admin/123)</div>}
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Usuario</label>
              <input value={u} onChange={e => setU(e.target.value)} type="text" className="w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="ej. admin" required />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Contraseña</label>
              <input value={p} onChange={e => setP(e.target.value)} type="password" className="w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="••••••••" required />
            </div>
            <button type="submit" className="w-full py-4 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transform active:scale-[0.98] transition-all shadow-xl">
              Iniciar Sesión
            </button>
          </form>
          <div className="px-8 pb-8 text-center">
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">SISTEMA AUDITADO BAJO ESTÁNDAR DE CALIDAD QMS-2024</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export const AppRouter: React.FC<{ 
  renderView: (view: ViewState) => React.ReactNode 
}> = ({ renderView }) => {
  const { user, logout } = useODT();
  const [view, setView] = useState<ViewState>('dashboard');

  useEffect(() => {
    if (!user) return;
    if (user.nivel === UserRole.QA) setView('qa-box');
    else if (user.nivel === UserRole.Finanzas) setView('finances');
    else if (user.nivel === UserRole.Creativo_Lider || user.nivel === UserRole.Diseno_Lider) setView('leader-dashboard');
    else if (user.nivel === UserRole.Creativo_Opera || user.nivel === UserRole.Diseno_Opera) setView('my-projects');
    else setView('dashboard');
  }, [user]);

  if (!user) return <Login />;

  const canSee = (roles: UserRole[]) => roles.includes(user.nivel) || user.nivel === UserRole.Admin;

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 fixed h-full p-6 flex flex-col gap-8 shadow-2xl z-50 overflow-y-auto">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl">ISO</div>
          <div className="leading-tight"><h2 className="text-white font-bold tracking-tighter">ODT Manager</h2><span className="text-slate-500 text-[10px] uppercase font-bold tracking-widest">v1.2</span></div>
        </div>
        <nav className="flex flex-col gap-2 flex-1">
          {canSee([UserRole.Cuentas_Lider, UserRole.Trafico]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Adm." active={view === 'dashboard'} onClick={() => setView('dashboard')} />}
          {canSee([UserRole.Creativo_Lider, UserRole.Diseno_Lider]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Lider" active={view === 'leader-dashboard'} onClick={() => setView('leader-dashboard')} />}
          {canSee([UserRole.Cuentas_Opera, UserRole.Creativo_Opera, UserRole.Diseno_Opera]) && <SidebarItem icon={<Icons.Project />} label="Bandeja de Entrada" active={view === 'my-projects'} onClick={() => setView('my-projects')} />}
          {canSee([UserRole.QA]) && <SidebarItem icon={<Icons.Ai />} label="Caja de QA" active={view === 'qa-box'} onClick={() => setView('qa-box')} />}
          {canSee([UserRole.Finanzas]) && <SidebarItem icon={<Icons.Clients />} label="Facturación" active={view === 'finances'} onClick={() => setView('finances')} />}
          {canSee([UserRole.Admin]) && <SidebarItem icon={<Icons.Users />} label="Usuarios" active={view === 'users'} onClick={() => setView('users')} />}
        </nav>
        <div className="p-4 bg-slate-800/50 rounded-xl border border-slate-700/50">
          <div className="flex items-center gap-3 mb-3">
            <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-xs font-bold text-white uppercase">{user.nombre.substring(0,2)}</div>
            <div className="overflow-hidden"><p className="text-xs font-bold text-white truncate">{user.nombre}</p><p className="text-[10px] text-slate-500 font-medium truncate">{user.nivel}</p></div>
          </div>
          <button onClick={logout} className="w-full py-2 text-[10px] uppercase tracking-widest font-bold text-slate-400 hover:text-white transition-colors border border-slate-700 rounded-md">Cerrar Sesión</button>
        </div>
      </aside>
      <main className="flex-1 ml-64 p-8">{renderView(view)}</main>
    </div>
  );
};

const SidebarItem: React.FC<{ icon: any, label: string, active: boolean, onClick: () => void }> = ({ icon: Icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${active ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
    {typeof Icon === 'function' ? <Icon /> : Icon} <span className="font-medium text-sm">{label}</span>
  </button>
);

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
