                <div><span className="text-slate-400 block uppercase text-[10px] font-black tracking-widest mb-1">Estado Operativo</span> <span className={`font-black uppercase px-2 py-0.5 rounded text-xs ${selectedProject.status === 'Finalizado' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>{selectedProject.status}</span></div>
              </div>
            </div>
            <div className="bg-white p-8 rounded-2xl border shadow-sm">
               <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-[0.2em] border-b pb-2">Logs de Trazabilidad ISO 9001</h3>
               <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2">
                 {selectedProject.comentarios.map(c => (
                   <div key={c.id} className={`p-4 rounded-xl text-xs border ${c.isSystemEvent ? 'bg-slate-50 border-dashed border-slate-200' : 'bg-white border-slate-100'} flex flex-col gap-2`}>
