              <h3 className="flex items-center gap-2 font-black mb-6 text-blue-400 uppercase text-xs tracking-widest"><Icons.Ai /> IA ISO AUDIT</h3>
              <p className="text-slate-400 text-xs mb-6">Auditoría automática de trazabilidad y riesgos bajo estándar ISO 9001:2015.</p>
              <button 
                onClick={async () => setAuditResult(await auditProjectISO(selectedProject))}
                className="w-full py-4 bg-blue-600 rounded-xl font-black hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
              >EJECUTAR AUDITORÍA</button>
              {auditResult && (
                <div className="mt-8 p-6 bg-white/5 rounded-2xl border border-white/10 space-y-6 text-xs animate-fadeIn">
                  <div className="flex justify-between items-end">
                    <span className="font-bold text-slate-400">PUNTAJE DE CALIDAD:</span> 
                    <span className={`text-3xl font-black ${auditResult.score > 80 ? 'text-emerald-400' : 'text-amber-400'}`}>{auditResult.score}%</span>
                  </div>
                  <div className="space-y-2">
                    <p className="font-black text-blue-400 uppercase text-[9px] tracking-widest">HALLAZGOS</p>
                    <ul className="space-y-1 pl-2 border-l border-white/10">
                      {auditResult.findings.map((f: any, i: number) => <li key={i} className="text-slate-300">• {f}</li>)}
                    </ul>
                  </div>
                  <div className="text-[9px] text-slate-500 italic uppercase font-bold text-right">Referencia: {auditResult.isoClause}</div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderView = (view: ViewState) => {
    if (selectedProject) return renderProjectDetail();
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

