  createdAt: string;
  updatedAt: string;
}

export interface Client {
  id: string;
  name: string;
  notes?: string;
  ownerId: string;
}

export type ViewState = 
  | 'login' 
  | 'dashboard' 
  | 'leader-dashboard'
  | 'my-projects' 
  | 'clients' 
  | 'users' 
  | 'qa-box' 
  | 'finances' 
  | 'project-detail';

export interface ODTContextType {
  user: User | null;
  projects: Project[];
  clients: Client[];
  users: User[];
  loading: boolean;
  login: (username: string, pass: string) => Promise<boolean>;
  logout: () => void;
  updateProjectStatus: (projectId: string, newStatus: Project['status'], comment: string) => Promise<void>;
  updateBrief: (projectId: string, content: string) => Promise<void>;
  processQA: (projectId: string, approved: boolean, feedback: string) => Promise<void>;
  updateBilling: (projectId: string, facturado: boolean, justification?: string) => Promise<void>;
  checkSLA: (project: Project) => { isAlert: boolean; reason?: string };
  delegateProject: (projectId: string, area: string, userId: string) => Promise<void>;
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Project, Client, User, ODTContextType, ProjectComment, UserRole } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const MOCK_USERS: User[] = [
  { id: 'U001', nombre: 'Admin Master', usuario: 'admin', nivel: UserRole.Admin, departamento: 'Gerencia' },
  { id: 'U002', nombre: 'QA Specialist', usuario: 'qa', nivel: UserRole.QA, departamento: 'Calidad' },
  { id: 'U003', nombre: 'Finanzas Lead', usuario: 'money', nivel: UserRole.Finanzas, departamento: 'Contabilidad' },
  { id: 'U004', nombre: 'Carlos Cuentas', usuario: 'cuentas', nivel: UserRole.Cuentas_Opera, departamento: 'Cuentas' },
  { id: 'U005', nombre: 'Elena Diseño', usuario: 'diseno', nivel: UserRole.Diseno_Opera, departamento: 'Creativo' },
  { id: 'U006', nombre: 'Pedro Creativo', usuario: 'pedro', nivel: UserRole.Creativo_Opera, departamento: 'Creativo' },
  { id: 'U007', nombre: 'Sofía Lider', usuario: 'sofia', nivel: UserRole.Creativo_Lider, departamento: 'Creativo' },
  { id: 'U008', nombre: 'Juan Diseño Lider', usuario: 'juan', nivel: UserRole.Diseno_Lider, departamento: 'Creativo' },
];

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        setUser(JSON.parse(savedSession));
      } catch (e) {
        console.error("Error parsing session", e);
      }
    }

    const initialProjects: Project[] = [
      {
        id: 'ODT-2024-001',
        empresa: 'TechCorp',
        marca: 'Zenith',
        producto: 'Launch Campaign',
        etapa_actual: 'Producción',
        status: 'En Proceso',
        correccion_ok: false,
        createdAt: new Date(Date.now() - 90 * 60 * 60 * 1000).toISOString(),
        updatedAt: new Date().toISOString(),
        areas_seleccionadas: ['Diseño', 'Creativo'],
        asignaciones: [{ area: 'Diseño', usuarioId: 'U005', status: 'pendiente' }],
        tracking: [],
        comentarios: [],
        monto_proyectado: 50000,
        brief: '<h1>Brief Maestro</h1><p>Definición del proyecto...</p>',
        facturado: false,
        ownerId: 'U004'
      },
      {
        id: 'ODT-2024-002',
        empresa: 'BioHealth',
        marca: 'Life',
        producto: 'Regulatory QA',
        etapa_actual: 'QA',
        status: 'QA',
        correccion_ok: false,
        createdAt: new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString(),
        updatedAt: new Date(Date.now() - 30 * 60 * 60 * 1000).toISOString(),
        areas_seleccionadas: ['Branding'],
        asignaciones: [],
        tracking: [],
        comentarios: [],
        monto_proyectado: 12500,
        brief: '<p>Requerimientos técnicos...</p>',
        facturado: false,
        ownerId: 'U004'
      }
    ];
    setProjects(initialProjects);
    setClients([{ id: 'C001', name: 'TechCorp', ownerId: 'U004' }]);
    setLoading(false);
  }, []);

  const login = async (username: string, pass: string): Promise<boolean> => {
    const foundUser = MOCK_USERS.find(u => u.usuario === username && pass === '123');
    if (foundUser) {
      setUser(foundUser);
      localStorage.setItem('apc_session', JSON.stringify(foundUser));
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hoursInProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hoursInQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);

    if (project.status === 'En Proceso' && hoursInProd > 72) return { isAlert: true, reason: 'Prod > 72h' };
    if (project.status === 'QA' && hoursInQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    setProjects(prev => prev.map(p => p.id === projectId ? { 
      ...p, status: newStatus, updatedAt: new Date().toISOString(), comentarios: [systemComment, ...p.comentarios] 
    } : p));
  };

  const updateBrief = async (projectId: string, content: string) => {
    setProjects(prev => prev.map(p => p.id === projectId ? { ...p, brief: content, updatedAt: new Date().toISOString() } : p));
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `RESULTADO QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. Feedback: ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    setProjects(prev => prev.map(p => p.id === projectId ? {
      ...p,
      correccion_ok: approved,
      status: approved ? (p.status === 'QA' ? 'Finalizado' : p.status) : 'Correcciones',
      comentarios: [systemComment, ...p.comentarios],
      updatedAt: new Date().toISOString()
    } : p));
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    setProjects(prev => prev.map(p => p.id === projectId ? {
      ...p, facturado, justificacion_no_facturado: justification, updatedAt: new Date().toISOString()
    } : p));
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: Área ${area} asignada a ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    setProjects(prev => prev.map(p => {
      if (p.id !== projectId) return p;
      const filteredAsignaciones = p.asignaciones.filter(a => a.area !== area);
      return {
        ...p,
        asignaciones: [...filteredAsignaciones, { area, usuarioId: userId, status: 'pendiente' }],
        comentarios: [systemComment, ...p.comentarios],
        updatedAt: new Date().toISOString()
      };
    }));
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, users, loading, login, logout, updateProjectStatus, updateBrief, processQA, updateBilling, checkSLA, delegateProject }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, checkSLA, updateProjectStatus, updateBrief, processQA } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [auditResult, setAuditResult] = useState<any>(null);
  const [isAuditing, setIsAuditing] = useState(false);

  const sla = checkSLA(project);

  const handleSaveBrief = () => {
    updateBrief(project.id, briefContent);
    alert("Brief Maestro guardado exitosamente.");
  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  // Roles in Production Area
  const isProductionRole = [
    UserRole.Creativo_Opera, 
    UserRole.Diseno_Opera, 
    UserRole.Creativo_Lider, 
    UserRole.Diseno_Lider
  ].includes(user?.nivel as UserRole);

  const isQAUser = user?.nivel === UserRole.QA;

  const roadmapStages = ['Briefing', 'Producción', 'QA / Revisión', 'Facturación', 'Finalizado'];
  const getCurrentStageIndex = () => {
    if (project.status === 'Finalizado') return 4;
    if (project.status === 'QA') return 2;
    if (project.status === 'Borrador') return 0;
    return 1; // En Proceso / Correcciones
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-20">
      <header className="flex items-center gap-4">
        <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500">
           <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
        </button>
        <div>
          <h1 className="text-2xl font-black text-slate-900">{project.id}</h1>
          <p className="text-sm text-slate-500 font-medium">{project.empresa} - {project.producto}</p>
        </div>
      </header>

      {/* Hoja de Ruta */}
      <div className="bg-white p-6 rounded-2xl border shadow-sm">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Hoja de Ruta del Proyecto</h3>
        <div className="relative flex justify-between items-center">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-100 -translate-y-1/2 -z-10"></div>
          {roadmapStages.map((stage, idx) => {
            const currentIdx = getCurrentStageIndex();
            const isActive = idx === currentIdx;
            const isCompleted = idx < currentIdx;
            return (
              <div key={stage} className="flex flex-col items-center gap-2 bg-white px-2">
                <div className={`w-8 h-8 rounded-full border-4 flex items-center justify-center transition-all ${
                  isActive ? 'bg-blue-600 border-blue-200 shadow-lg scale-110' : 
                  isCompleted ? 'bg-emerald-500 border-emerald-100' : 'bg-slate-100 border-white'
                }`}>
                  {isCompleted ? (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                  ) : <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white' : 'bg-slate-300'}`}></div>}
                </div>
                <span className={`text-[9px] font-black uppercase tracking-tighter ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>{stage}</span>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          {/* Brief Maestro */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Icons.Project /> Brief Maestro
              </h3>
              <button onClick={handleSaveBrief} className="px-4 py-2 bg-blue-600 text-white text-xs font-bold rounded-lg hover:bg-blue-700 transition-all">
                GUARDAR BRIEF
              </button>
            </div>
            <ReactQuill 
              theme="snow" 
              value={briefContent} 
              onChange={(content) => setBriefContent(typeof content === 'string' ? content : '')} 
              modules={{
                toolbar: [
                  [{ 'header': [1, 2, false] }],
                  ['bold', 'italic', 'underline', 'strike'],
                  [{ 'list': 'ordered'}, { 'list': 'bullet' }],
                  ['link', 'image', 'video'],
                  ['clean']
                ],
              }}
            />
          </div>

          {/* Logs de Trazabilidad */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad ISO 9001</h3>
            <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
              {project.comentarios.map(c => (
                <div key={c.id} className={`p-4 rounded-xl text-xs border ${c.isSystemEvent ? 'bg-slate-50 border-dashed border-slate-200' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between mb-2">
                    <span className="font-black uppercase text-[9px] text-blue-500">{c.authorName}</span>
                    <span className="text-slate-400 font-mono text-[9px]">{new Date(c.createdAt).toLocaleString()}</span>
                  </div>
                  <p className="text-slate-700 font-medium">{c.text}</p>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {/* QA Box / Compuerta de Calidad */}
          {isQAUser ? (
            <div className="bg-white p-6 rounded-2xl border-2 border-amber-200 shadow-xl space-y-4">
              <h3 className="font-black text-amber-600 text-xs uppercase tracking-widest flex items-center gap-2">
                <Icons.Ai /> Caja de Corrección (QA)
              </h3>
              <p className="text-xs text-slate-500">Revisa la trazabilidad y el brief antes de aprobar o rechazar el proyecto.</p>
              <textarea 
                placeholder="Feedback obligatorio para el equipo..."
                className="w-full bg-slate-50 border rounded-xl p-3 text-xs outline-none focus:ring-2 focus:ring-amber-500 h-24"
                value={qaFeedback}
                onChange={(e) => setQaFeedback(e.target.value)}
              />
              <div className="grid grid-cols-2 gap-3">
                <button 
                  disabled={!qaFeedback}
                  onClick={() => { processQA(project.id, true, qaFeedback); setQaFeedback(''); }}
                  className="py-3 bg-emerald-600 text-white font-black text-xs rounded-xl hover:bg-emerald-700 disabled:opacity-50 transition-all"
                >APROBAR</button>
                <button 
                  disabled={!qaFeedback}
                  onClick={() => { processQA(project.id, false, qaFeedback); setQaFeedback(''); }}
                  className="py-3 bg-rose-600 text-white font-black text-xs rounded-xl hover:bg-rose-700 disabled:opacity-50 transition-all"
                >RECHAZAR</button>
              </div>
            </div>
          ) : (
            <div className="bg-slate-900 p-6 rounded-2xl text-white shadow-xl space-y-4">
              <h3 className="text-blue-400 font-black text-xs uppercase tracking-widest flex items-center gap-2">
                <Icons.Plus /> Gestión de Etapas
              </h3>
              <p className="text-[10px] text-slate-400 uppercase font-bold">Estado actual: <span className="text-white">{project.status}</span></p>

              <button 
                disabled={isProductionRole && !project.correccion_ok && project.status !== 'Borrador'}
                onClick={() => updateProjectStatus(project.id, project.status === 'QA' ? 'Finalizado' : 'QA', 'Traspaso de etapa manual')}
                className="w-full py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 transition-all disabled:bg-slate-800 disabled:text-slate-600"
              >
                {project.status === 'QA' ? 'FINALIZAR PROYECTO' : 'ENVIAR A REVISIÓN QA'}
              </button>

              {isProductionRole && !project.correccion_ok && project.status !== 'Borrador' && (
                <div className="p-3 bg-rose-900/50 border border-rose-800 rounded-lg flex gap-2 items-center">
                   <div className="text-rose-500"><Icons.Ai /></div>
                   <p className="text-[10px] text-rose-200 font-medium">COMPUERTA DE CALIDAD: Avance bloqueado hasta aprobación QA.</p>
                </div>
              )}
            </div>
          )}

          {/* AI Audit Center */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm group">
            <h3 className="flex items-center gap-2 font-black text-xs mb-4 text-blue-600 uppercase tracking-widest"><Icons.Ai /> IA ISO AUDIT</h3>
            <button 
              onClick={handleAudit}
              disabled={isAuditing}
              className="w-full py-3 bg-slate-900 text-white rounded-xl font-black text-xs hover:bg-slate-800 transition-all flex items-center justify-center gap-2"
            >
              {isAuditing ? <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : 'AUDITAR ODT'}
            </button>
            {auditResult && (
              <div className="mt-4 p-4 bg-slate-50 rounded-xl border space-y-4 text-xs animate-fadeIn">
                <div className="flex justify-between items-end">
                  <span className="font-bold text-slate-400">SCORE:</span> 
                  <span className={`text-2xl font-black ${auditResult.score > 80 ? 'text-emerald-600' : 'text-amber-600'}`}>{auditResult.score}%</span>
                </div>
                <div className="text-[9px] text-slate-500 font-bold uppercase">Cláusula: {auditResult.isoClause}</div>
              </div>
            )}
          </div>

          {/* SLA Alert Pin */}
          {sla.isAlert && (
             <div className="p-4 bg-pink-50 border border-pink-100 rounded-2xl shadow-lg shadow-pink-100/50 flex flex-col gap-1 animate-pulse">
                <span className="text-pink-600 font-black text-[10px] uppercase tracking-widest flex items-center gap-1">⚠️ ALERTA DE SLA</span>
                <p className="text-pink-800 text-xs font-bold leading-tight">{sla.reason}</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProjectDetail;

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ODTProvider, useODT } from './ODTContext';
import { AppRouter } from './AppRouter';
import AdminDashboard from './AdminDashboard';
import LeaderDashboard from './LeaderDashboard';
import ProjectDetail from './ProjectDetail';

const AppContent: React.FC = () => {
  const { user, projects, checkSLA, updateBilling } = useODT();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  const renderMyInbox = () => {
    const myProjects = projects.filter(p => 
      p.asignaciones.some(a => a.usuarioId === user?.id) || 
      (p.ownerId === user?.id)
    );
    return (
      <div className="space-y-6">
        <header><h1 className="text-3xl font-black">Bandeja de Entrada</h1></header>
        <div className="bg-white p-6 rounded-xl border-2 border-dashed border-slate-200">
           {myProjects.length === 0 ? (
             <p className="text-slate-400 italic text-center py-10">No tienes tareas asignadas por el momento.</p>
           ) : (
             <ProjectTable projects={myProjects} onView={setSelectedProject} checkSLA={checkSLA} />
           )}
        </div>
      </div>
    );
  };

  const renderQABox = () => {
    const qaProjects = projects.filter(p => p.status === 'QA');
    return (
      <div className="space-y-6">
        <header><h1 className="text-3xl font-black">Caja de Corrección (QA)</h1></header>
        {qaProjects.length === 0 ? (
