        ) : (
           <ProjectTable projects={qaProjects} onView={setSelectedProject} checkSLA={checkSLA} />
        )}
      </div>
    );
  };

  const renderFinances = () => (
    <div className="space-y-6">
      <header><h1 className="text-3xl font-black">Gestión de Facturación</h1></header>
      <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
