              <th className="px-6 py-4">ODT</th>
              <th className="px-6 py-4">Cliente</th>
              <th className="px-6 py-4">Monto</th>
              <th className="px-6 py-4 text-center">Facturado</th>
              <th className="px-6 py-4">Justificación</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {projects.map(p => (
              <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-mono font-black text-blue-600">{p.id}</td>
                <td className="px-6 py-4 font-medium text-slate-700">{p.empresa}</td>
                <td className="px-6 py-4 font-black text-slate-900">${p.monto_proyectado.toLocaleString()}</td>
                <td className="px-6 py-4 text-center">
                  <input type="checkbox" checked={p.facturado} onChange={e => updateBilling(p.id, e.target.checked)} className="w-5 h-5 accent-blue-600 cursor-pointer" />
                </td>
                <td className="px-6 py-4">
                  {!p.facturado && (
                    <input 
                      className="w-full bg-rose-50 border-rose-100 border rounded px-3 py-1.5 text-xs outline-none focus:ring-1 focus:ring-rose-500 placeholder:text-rose-300"
                      placeholder="Indica motivo del retraso..."
                      value={p.justificacion_no_facturado || ''}
                      onChange={e => updateBilling(p.id, false, e.target.value)}
                    />
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderView = (view: ViewState) => {
    if (selectedProject) return <ProjectDetail project={selectedProject} onBack={() => setSelectedProject(null)} />;
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

const ProjectTable = ({ projects, onView, checkSLA }: any) => (
  <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
    <table className="w-full text-sm text-left">
      <thead className="bg-slate-50 text-slate-500 font-black text-[10px] uppercase tracking-widest">
        <tr>
          <th className="px-6 py-5">ODT ID</th>
          <th className="px-6 py-5">Proyecto / Cliente</th>
          <th className="px-6 py-5">Status</th>
