import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, push, set } from 'firebase/database';
import { db } from './firebase';
import { Project, Client, User, ODTContextType, ProjectComment, UserRole } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // 1. Persistencia: Cargar usuario desde localStorage
  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        setUser(JSON.parse(savedSession));
      } catch (e) {
        console.error("Error parsing session", e);
      }
    }
  }, []);

  // 2. Sincronización Real-time con Firebase
  useEffect(() => {
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let projectsLoaded = false;
    let usersLoaded = false;
    let clientsLoaded = false;

    const checkLoading = () => {
      if (projectsLoaded && usersLoaded && clientsLoaded) {
        setLoading(false);
      }
    };

    const unsubProjects = onValue(projectsRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.keys(data).map(key => ({ ...data[key], id: key }));
        setProjects(list);
      } else {
        setProjects([]);
      }
      projectsLoaded = true;
      checkLoading();
    });

    const unsubUsers = onValue(usersRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.keys(data).map(key => ({ ...data[key], id: key }));
        setUsers(list);
      }
      usersLoaded = true;
      checkLoading();
    });

    const unsubClients = onValue(clientsRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list = Object.keys(data).map(key => ({ ...data[key], id: key }));
        setClients(list);
      }
      clientsLoaded = true;
      checkLoading();
    });

    return () => {
      unsubProjects();
      unsubUsers();
      unsubClients();
    };
  }, []);

  const login = async (username: string, pass: string): Promise<boolean> => {
    // Note: In production, use Firebase Auth. This is a simulation using the Realtime Database users node.
    const foundUser = users.find(u => u.usuario === username && pass === '123');
    if (foundUser) {
      setUser(foundUser);
      localStorage.setItem('apc_session', JSON.stringify(foundUser));
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hoursInProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hoursInQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);

    if (project.status === 'En Proceso' && hoursInProd > 72) return { isAlert: true, reason: 'Prod > 72h' };
    if (project.status === 'QA' && hoursInQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    await update(ref(db, `projects/${projectId}`), {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...(project.comentarios || [])]
    });
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), {
      brief: content,
      updatedAt: new Date().toISOString()
    });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `RESULTADO QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. Feedback: ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    await update(ref(db, `projects/${projectId}`), {
      correccion_ok: approved,
      status: approved ? (project.status === 'QA' ? 'Finalizado' : project.status) : 'Correcciones',
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), {
      facturado,
      justificacion_no_facturado: justification || "",
      updatedAt: new Date().toISOString()
    });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: Área ${area} asignada a ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const filteredAsignaciones = (project.asignaciones || []).filter(a => a.area !== area);
    const newAsignaciones = [...filteredAsignaciones, { area, usuarioId: userId, status: 'pendiente' }];

    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, users, loading, login, logout, updateProjectStatus, updateBrief, processQA, updateBilling, checkSLA, delegateProject }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

