      const snapshot = await get(userRef);

      const exists = snapshot.exists();
      console.log(`¿Usuario encontrado?: [${exists ? 'si' : 'no'}]`);

      if (!exists) {
        return { success: false, error: 'Usuario no encontrado en el nodo /users de APC.' };
      }

      const userData = snapshot.val();
      const passMatch = userData.password === pass;
      console.log(`¿Contraseña coincide?: [${passMatch ? 'si' : 'no'}]`);

      if (!passMatch) {
        return { success: false, error: 'Contraseña incorrecta. Verifique sus credenciales.' };
      }

      // Estructura compatible v11: La clave del nodo es el ID
      const authenticatedUser: User = {
        ...userData,
        id: username,
        usuario: username
      };

      setUser(authenticatedUser);
      localStorage.setItem('apc_session', JSON.stringify(authenticatedUser));
      return { success: true };
    } catch (error) {
      console.error("Error fatal en login:", error);
      return { success: false, error: 'Fallo de conexión con Firebase. Intente de nuevo.' };
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
    console.log('Cierre de sesión exitoso.');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hoursInProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hoursInQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);

    if (project.status === 'En Proceso' && hoursInProd > 72) return { isAlert: true, reason: 'Prod > 72h' };
    if (project.status === 'QA' && hoursInQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    await update(ref(db, `projects/${projectId}`), {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...(project.comentarios || [])]
    });
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), {
      brief: content,
      updatedAt: new Date().toISOString()
    });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `RESULTADO QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. Feedback: ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    await update(ref(db, `projects/${projectId}`), {
      correccion_ok: approved,
      status: approved ? (project.status === 'QA' ? 'Finalizado' : project.status) : 'Correcciones',
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), {
      facturado,
      justificacion_no_facturado: justification || "",
      updatedAt: new Date().toISOString()
    });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: Área ${area} asignada a ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const filteredAsignaciones = (project.asignaciones || []).filter(a => a.area !== area);
    const newAsignaciones = [...filteredAsignaciones, { area, usuarioId: userId, status: 'pendiente' }];

    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, users, loading, login, logout, updateProjectStatus, updateBrief, processQA, updateBilling, checkSLA, delegateProject }}>
      {children}
    </ODTContext.Provider>
  );
};

