        const allUsersSnap = await get(ref(db, 'users'));
        if (allUsersSnap.exists()) {
          console.log('ESTRUCTURA ACTUAL DE /users (Claves encontradas):', Object.keys(allUsersSnap.val()));
        } else {
          console.error('EL NODO /users PARECE ESTAR VACÍO O NO EXISTE EN ESTA URL.');
        }
        return { success: false, error: `El usuario "${cleanUsername}" no existe en el nodo /users.` };
      }

      const userData = snapshot.val();
      const passMatch = userData.password === pass;
      console.log(`¿Contraseña coincide?: [${passMatch ? 'si' : 'no'}]`);

      if (!passMatch) {
        return { success: false, error: 'Contraseña incorrecta para este usuario.' };
      }

      const authUser: User = {
        ...userData,
        id: cleanUsername,
        usuario: cleanUsername
      };

      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };

    } catch (error: any) {
      console.error("ERROR FATAL EN LOGIN:", error);
      return { success: false, error: 'Error de comunicación: ' + error.message };
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);
    if (project.status === 'En Proceso' && hProd > 72) return { isAlert: true, reason: 'Prod > 72h' };
    if (project.status === 'QA' && hQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    await update(ref(db, `projects/${projectId}`), {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...(project.comentarios || [])]
    });
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `QA: ${approved ? 'OK' : 'RECHAZADO'}. ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    await update(ref(db, `projects/${projectId}`), {
      correccion_ok: approved,
      status: approved ? (project.status === 'QA' ? 'Finalizado' : project.status) : 'Correcciones',
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: ${area} -> ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const current = project.asignaciones || [];
    const filtered = current.filter(a => a.area !== area);
    const newAsignaciones = [...filtered, { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), { asignaciones: newAsignaciones, comentarios: [systemComment, ...(project.comentarios || [])], updatedAt: new Date().toISOString() });
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, users, loading, login, logout, updateProjectStatus, updateBrief, processQA, updateBilling, checkSLA, delegateProject }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState, useMemo, useEffect } from 'react';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const AdminDashboard: React.FC = () => {
  const { projects, users } = useODT();
  const [executiveFilter, setExecutiveFilter] = useState('all');
  const [periodFilter, setPeriodFilter] = useState('this-month');
  const [isMounted, setIsMounted] = useState(false);

  // Asegurar que Recharts solo se cargue cuando el componente esté montado en el DOM
  useEffect(() => {
    setIsMounted(true);
  }, []);

  const executives = useMemo(() => 
    users.filter(u => u.nivel === UserRole.Cuentas_Opera || u.nivel === UserRole.Cuentas_Lider), 
  [users]);

  const filteredProjects = useMemo(() => {
    let filtered = projects;
    if (executiveFilter !== 'all') {
      filtered = filtered.filter(p => p.ownerId === executiveFilter);
    }
    return filtered;
  }, [projects, executiveFilter]);

  const saturationData = useMemo(() => {
    const counts: Record<string, number> = {
      'Creativo': 0,
      'Diseño': 0,
      'Cuentas': 0,
      'QA': 0,
      'Finanzas': 0
    };

    projects.forEach(p => {
      if (p.status !== 'Finalizado' && p.status !== 'Cancelado') {
        p.areas_seleccionadas?.forEach(area => {
          if (counts[area] !== undefined) counts[area]++;
          else if (area === 'Social Media') counts['Diseño']++;
        });
      }
    });

    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [projects]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900">Dashboard Administrativo</h1>
          <p className="text-slate-500 font-medium text-sm">Análisis de rendimiento ISO 9001:2015</p>
        </div>

        <div className="flex flex-wrap gap-2">
          <select 
            className="bg-white border rounded-lg px-3 py-2 text-[10px] font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
            value={executiveFilter}
            onChange={(e) => setExecutiveFilter(e.target.value)}
          >
            <option value="all">TODOS LOS EJECUTIVOS</option>
            {executives.map(e => <option key={e.id} value={e.id}>{e.nombre.toUpperCase()}</option>)}
          </select>

          <select 
            className="bg-white border rounded-lg px-3 py-2 text-[10px] font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
            value={periodFilter}
            onChange={(e) => setPeriodFilter(e.target.value)}
          >
            <option value="this-month">ESTE MES</option>
            <option value="last-month">MES PASADO</option>
          </select>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border shadow-sm min-h-[400px]">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">Saturación por Departamento (ODTs Activas)</h3>

          {!isMounted || projects.length === 0 ? (
            <div className="h-[300px] flex items-center justify-center bg-slate-50 rounded-xl border border-dashed border-slate-200">
               <div className="text-center">
                  <div className="w-8 h-8 border-4 border-t-blue-500 border-blue-100 rounded-full animate-spin mx-auto mb-3"></div>
                  <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Sincronizando con base de datos...</p>
               </div>
            </div>
          ) : (
            <div className="h-[300px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={saturationData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis 
                      dataKey="name" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} 
                  />
                  <YAxis 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}}
                  />
                  <Tooltip 
                    cursor={{fill: '#f8fafc'}}
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                  />
                  <Bar dataKey="value" radius={[6, 6, 0, 0]}>
                    {saturationData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.value > 5 ? '#ef4444' : '#3b82f6'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}
        </div>

        <div className="space-y-6">
          <div className="bg-slate-900 p-6 rounded-2xl text-white shadow-xl">
             <h3 className="text-blue-400 text-[10px] font-black uppercase tracking-widest mb-4">Monto Proyectado</h3>
             <p className="text-4xl font-black mb-1">${filteredProjects.reduce((a, b) => a + (b.monto_proyectado || 0), 0).toLocaleString()}</p>
             <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Filtrado en {filteredProjects.length} ODTs</p>
          </div>

          <div className="bg-white p-6 rounded-2xl border shadow-sm">
             <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-6 border-b pb-2">Mix de Estados</h3>
             <div className="space-y-4">
                <StatusRow label="En Proceso" count={filteredProjects.filter(p => p.status === 'En Proceso').length} color="blue" />
                <StatusRow label="QA / Revisión" count={filteredProjects.filter(p => p.status === 'QA').length} color="amber" />
                <StatusRow label="Finalizados" count={filteredProjects.filter(p => p.status === 'Finalizado').length} color="emerald" />
                <StatusRow label="Cancelados" count={filteredProjects.filter(p => p.status === 'Cancelado').length} color="rose" />
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatusRow = ({ label, count, color }: any) => {
  const colorMap: any = {
    blue: 'bg-blue-50 text-blue-600 border-blue-100',
    amber: 'bg-amber-50 text-amber-600 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-600 border-emerald-100',
    rose: 'bg-rose-50 text-rose-600 border-rose-100'
  };
  return (
    <div className="flex justify-between items-center text-sm">
      <span className="font-bold text-slate-600">{label}</span>
      <span className={`px-2.5 py-0.5 rounded-full font-black text-[10px] border ${colorMap[color]}`}>{count}</span>
    </div>
  );
};

export default AdminDashboard;

