import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get } from 'firebase/database';
import { db } from './firebase';
import { Project, User, ODTContextType, ProjectComment, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Mantenimiento de sesión: Cargar desde localStorage
  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
        console.log("Sesión recuperada para:", parsedUser.usuario);
      } catch (e) {
        console.error("Error al parsear apc_session", e);
      }
    }
  }, []);

  // Sincronización Real-time
  useEffect(() => {
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let pL = false, uL = false, cL = false;
    const check = () => { if (pL && uL && cL) setLoading(false); };

    const unsubP = onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      pL = true; check();
    });

    const unsubU = onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      uL = true; check();
    });

    const unsubC = onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      cL = true; check();
    });

    return () => { unsubP(); unsubU(); unsubC(); };
  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    console.log(`--- INTENTO DE AUTENTICACIÓN ---`);
    console.log(`Buscando usuario: [${cleanUsername}]`);

    // 1. Bypass de Emergencia (Si Firebase falla o no hay datos)
    if (cleanUsername === 'admin' && pass === 'admin') {
      console.log('¿Usuario encontrado?: [SI - BYPASS]');
      console.log('¿Contraseña coincide?: [SI - BYPASS]');
      const adminBypass: User = {
        id: 'admin',
        nombre: 'Administrador (Bypass)',
        usuario: 'admin',
        departamento: 'Sistemas',
        nivel: UserRole.Admin
      };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }

    try {
      // 2. Referencia Directa al Nodo (Basado en v11)
      const userRef = ref(db, `users/${cleanUsername}`);
      const snapshot = await get(userRef);
      const exists = snapshot.exists();

      console.log(`¿Usuario encontrado?: [${exists ? 'si' : 'no'}]`);

      if (!exists) {
        // DEPUREMOS: Si no lo encuentra, listamos qué hay en el nodo raíz /users
        const allUsersSnap = await get(ref(db, 'users'));
        if (allUsersSnap.exists()) {
          console.log('DEBUG - LLAVES ENCONTRADAS EN /users:', Object.keys(allUsersSnap.val()));
        } else {
          console.error('ERROR - EL NODO /users NO EXISTE O ESTÁ VACÍO EN ESTE PROYECTO.');
        }
        return { success: false, error: `El usuario "${cleanUsername}" no existe.` };
      }

      const userData = snapshot.val();
      const passMatch = userData.password === pass;
      console.log(`¿Contraseña coincide?: [${passMatch ? 'si' : 'no'}]`);

      if (!passMatch) {
        return { success: false, error: 'La contraseña es incorrecta.' };
      }

      // 3. Éxito: Normalización y Persistencia
      const authUser: User = {
        ...userData,
        id: cleanUsername,
        usuario: cleanUsername
      };

      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };

    } catch (error: any) {
      console.error("FALLO CRÍTICO DE CONEXIÓN:", error);
      return { success: false, error: 'Fallo de conexión: ' + error.message };
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
    console.log('Sesión cerrada y apc_session removida.');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);
    if (project.status === 'En Proceso' && hProd > 72) return { isAlert: true, reason: 'Prod > 72h' };
    if (project.status === 'QA' && hQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    await update(ref(db, `projects/${projectId}`), {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...(project.comentarios || [])]
    });
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `QA: ${approved ? 'OK' : 'RECHAZADO'}. ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    await update(ref(db, `projects/${projectId}`), {
      correccion_ok: approved,
      status: approved ? (project.status === 'QA' ? 'Finalizado' : project.status) : 'Correcciones',
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: ${area} -> ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const current = project.asignaciones || [];
    const filtered = current.filter(a => a.area !== area);
    const newAsignaciones = [...filtered, { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), { asignaciones: newAsignaciones, comentarios: [systemComment, ...(project.comentarios || [])], updatedAt: new Date().toISOString() });
  };

  return (
    <ODTContext.Provider value={{ user, projects, clients, users, loading, login, logout, updateProjectStatus, updateBrief, processQA, updateBilling, checkSLA, delegateProject }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

