    let pL = false, uL = false, cL = false;

    // Función de seguridad para desbloquear la UI si Firebase tarda o devuelve nulo
    const check = () => { 
      if (pL && uL && cL) {
        setLoading(false); 
      }
    };

    // Timeout de seguridad: Si en 6 segundos no hay respuesta, forzamos la carga (posible base de datos vacía)
    const safetyTimeout = setTimeout(() => {
