const AdminDashboard: React.FC = () => {
  const { projects, users } = useODT();
  const [executiveFilter, setExecutiveFilter] = useState('all');
  const [periodFilter, setPeriodFilter] = useState('all');
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  // Lista de ejecutivos para el filtro
  const executives = useMemo(() => 
    users?.filter(u => u?.nivel === UserRole.Cuentas_Opera || u?.nivel === UserRole.Cuentas_Lider) || [], 
  [users]);

  // Lógica de filtrado por Ejecutivo y Rango de Fecha (Periodo)
  const filteredProjects = useMemo(() => {
    if (!projects) return [];

    let filtered = [...projects];

    // Filtro por Ejecutivo
    if (executiveFilter !== 'all') {
      filtered = filtered.filter(p => p?.ownerId === executiveFilter);
    }

    // Filtro por Periodo
    const now = new Date();
    if (periodFilter === 'this-month') {
      filtered = filtered.filter(p => {
        const pDate = new Date(p?.createdAt);
        return pDate.getMonth() === now.getMonth() && pDate.getFullYear() === now.getFullYear();
      });
    } else if (periodFilter === 'last-month') {
      const lastMonth = now.getMonth() === 0 ? 11 : now.getMonth() - 1;
      const year = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear();
      filtered = filtered.filter(p => {
        const pDate = new Date(p?.createdAt);
        return pDate.getMonth() === lastMonth && pDate.getFullYear() === year;
      });
    }

    return filtered;
  }, [projects, executiveFilter, periodFilter]);

  // Datos de Saturación por Departamento (Solo ODTs activas del set filtrado)
  const saturationData = useMemo(() => {
    const counts: Record<string, number> = {
      'Creativo': 0,
      'Diseño': 0,
      'Cuentas': 0,
      'QA': 0,
      'Finanzas': 0
    };

    filteredProjects?.forEach(p => {
      if (p?.status !== 'Finalizado' && p?.status !== 'Cancelado') {
        p?.areas_seleccionadas?.forEach(area => {
          if (counts[area] !== undefined) counts[area]++;
          else if (area === 'Social Media') counts['Diseño']++;
        });
      }
    });

    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [filteredProjects]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Panel de Control Maestro</h1>
          <p className="text-slate-500 font-medium text-sm flex items-center gap-2">
            <span className="w-2 h-2 bg-emerald-500 rounded-full"></span>
            Métricas de Cumplimiento ISO 9001:2015
          </p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="flex flex-col gap-1">
            <span className="text-[9px] font-black text-slate-400 uppercase ml-1">Ejecutivo de Cuenta</span>
            <select 
              className="bg-white border-2 border-slate-100 rounded-xl px-4 py-2.5 text-xs font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500 transition-all"
              value={executiveFilter}
              onChange={(e) => setExecutiveFilter(e.target.value)}
            >
              <option value="all">TODOS LOS EJECUTIVOS</option>
              {executives.map(e => <option key={e?.id} value={e?.id}>{e?.nombre?.toUpperCase()}</option>)}
            </select>
          </div>

          <div className="flex flex-col gap-1">
            <span className="text-[9px] font-black text-slate-400 uppercase ml-1">Rango de Fecha</span>
            <select 
              className="bg-white border-2 border-slate-100 rounded-xl px-4 py-2.5 text-xs font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500 transition-all"
              value={periodFilter}
              onChange={(e) => setPeriodFilter(e.target.value)}
            >
              <option value="all">HISTÓRICO TOTAL</option>
              <option value="this-month">ESTE MES</option>
              <option value="last-month">MES ANTERIOR</option>
            </select>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Gráfico de Saturación */}
        <div className="lg:col-span-2 bg-white p-8 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 min-h-[450px] flex flex-col">
          <div className="flex justify-between items-start mb-10">
            <div>
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Carga Operativa</h3>
              <p className="text-sm text-slate-600 font-medium">Distribución de ODTs activas por área técnica</p>
            </div>
          </div>

          <div className="flex-1 w-full min-h-[300px]">
            {!isMounted || !projects?.length ? (
              <div className="h-full flex items-center justify-center bg-slate-50/50 rounded-2xl border-2 border-dashed border-slate-100">
                 <div className="text-center">
                    <div className="w-10 h-10 border-4 border-t-blue-500 border-slate-200 rounded-full animate-spin mx-auto mb-4"></div>
                    <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Aguardando datos de sincronización...</p>
                 </div>
              </div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={saturationData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="8 8" vertical={false} stroke="#f8fafc" />
                  <XAxis 
                      dataKey="name" 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{fill: '#64748b', fontSize: 11, fontWeight: 800}} 
                      dy={10}
                  />
                  <YAxis 
                      axisLine={false} 
                      tickLine={false} 
                      tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 600}}
                  />
                  <Tooltip 
                    cursor={{fill: '#f1f5f9', radius: 8}}
                    contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', padding: '12px'}}
                    itemStyle={{fontWeight: 900, fontSize: '12px'}}
                  />
                  <Bar dataKey="value" radius={[10, 10, 10, 10]} barSize={40}>
                    {saturationData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry?.value > 8 ? '#f43f5e' : entry?.value > 4 ? '#f59e0b' : '#3b82f6'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>

        {/* Resumen de Métricas */}
        <div className="space-y-6">
          <div className="bg-slate-900 p-8 rounded-3xl text-white shadow-2xl relative overflow-hidden group">
             <div className="absolute -right-10 -top-10 w-40 h-40 bg-blue-500/10 rounded-full blur-3xl group-hover:bg-blue-500/20 transition-all duration-700"></div>
             <h3 className="text-blue-400 text-[10px] font-black uppercase tracking-widest mb-6 flex items-center gap-2">
               <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-pulse"></span>
               Inversión Proyectada
             </h3>
             <p className="text-5xl font-black mb-2 tracking-tighter">
               <span className="text-blue-500 text-2xl mr-1">$</span>
               {filteredProjects?.reduce((a, b) => a + (b?.monto_proyectado || 0), 0).toLocaleString()}
             </p>
             <div className="flex items-center justify-between mt-6 pt-6 border-t border-white/10">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{filteredProjects?.length} Órdenes de Trabajo</p>
                <span className="text-[10px] bg-white/10 px-2 py-1 rounded-md font-bold text-white uppercase">Sincronizado</span>
             </div>
          </div>

          <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50">
             <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-8 border-b border-slate-50 pb-4">Desglose de Trazabilidad</h3>
             <div className="space-y-5">
                <StatusRow label="En Producción" count={filteredProjects?.filter(p => p?.status === 'En Proceso').length} color="blue" />
                <StatusRow label="En Revisión QA" count={filteredProjects?.filter(p => p?.status === 'QA').length} color="amber" />
                <StatusRow label="Finalizados" count={filteredProjects?.filter(p => p?.status === 'Finalizado').length} color="emerald" />
                <StatusRow label="Cancelados" count={filteredProjects?.filter(p => p?.status === 'Cancelado').length} color="rose" />
             </div>
          </div>

          {/* SLA Quick Alert Area */}
          {filteredProjects?.some(p => p?.status === 'En Proceso' || p?.status === 'QA') && (
            <div className="p-6 bg-rose-50 rounded-3xl border border-rose-100">
               <div className="flex items-center gap-3 mb-2">
                 <div className="w-8 h-8 bg-rose-500 rounded-xl flex items-center justify-center text-white">
                   <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>
                 </div>
                 <h4 className="text-rose-600 font-black text-xs uppercase">Alerta de Riesgo ISO</h4>
               </div>
               <p className="text-[10px] text-rose-700 font-bold leading-relaxed">
                 Hay {filteredProjects?.filter(p => p?.status === 'En Proceso')?.length} proyectos que requieren supervisión inmediata para no comprometer los tiempos de entrega pactados.
               </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const StatusRow = ({ label, count, color }: any) => {
  const colorMap: any = {
    blue: 'bg-blue-50 text-blue-600 border-blue-100',
    amber: 'bg-amber-50 text-amber-600 border-amber-100',
    emerald: 'bg-emerald-50 text-emerald-600 border-emerald-100',
    rose: 'bg-rose-50 text-rose-600 border-rose-100'
  };
  return (
    <div className="flex justify-between items-center group cursor-default">
      <div className="flex items-center gap-2">
        <div className={`w-1.5 h-1.5 rounded-full ${color === 'blue' ? 'bg-blue-500' : color === 'amber' ? 'bg-amber-500' : color === 'emerald' ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>
        <span className="font-bold text-slate-600 text-sm group-hover:text-slate-900 transition-colors">{label}</span>
      </div>
      <span className={`px-3 py-1 rounded-xl font-black text-[11px] border shadow-sm ${colorMap[color]}`}>{count}</span>
    </div>
  );
};

export default AdminDashboard;

