export enum UserRole {
  Admin = 'Admin',
  Cuentas_Lider = 'Cuentas_Lider',
  Cuentas_Opera = 'Cuentas_Opera',
  Creativo_Lider = 'Creativo_Lider',
  Creativo_Opera = 'Creativo_Opera',
  Diseno_Lider = 'Diseno_Lider',
  Diseno_Opera = 'Diseno_Opera',
  QA = 'QA',
  Finanzas = 'Finanzas',
  Trafico = 'Trafico'
}

export interface User {
  id: string;
  nombre: string;
  usuario: string;
  password?: string;
  departamento: string;
  nivel: UserRole;
}

export interface ProjectComment {
  id: string;
  authorId: string;
  authorName: string;
  text: string;
  createdAt: string;
  isSystemEvent?: boolean;
}

export interface ProjectAssignment {
  area: string;
  usuarioId: string;
  status: 'pendiente' | 'en_progreso' | 'completado';
}

export interface Project {
  id: string;
  empresa: string;
  marca: string;
  producto: string;
  etapa_actual: string;
  status: 'Borrador' | 'En Proceso' | 'Correcciones' | 'QA' | 'Finalizado' | 'Cancelado';
  correccion_ok: boolean; // Flag to enable/disable progression
  areas_seleccionadas: string[];
  asignaciones: ProjectAssignment[];
  tracking: any[];
  comentarios: ProjectComment[];
  monto_proyectado: number;
  brief: string; // The Quill HTML content
  facturado?: boolean;
  justificacion_no_facturado?: string;
  ownerId?: string;
  createdAt: string;
  updatedAt: string;
}

export interface Client {
  id: string;
  name: string;
  notes?: string;
  ownerId: string;
}

export type ViewState = 
  | 'login' 
  | 'dashboard' 
  | 'leader-dashboard'
  | 'my-projects' 
  | 'clients' 
  | 'users' 
  | 'qa-box' 
  | 'finances' 
  | 'project-detail';

export interface LoginResult {
  success: boolean;
  error?: string;
}

export interface ODTContextType {
  user: User | null;
  projects: Project[];
  clients: Client[];
  users: User[];
  loading: boolean;
  login: (username: string, pass: string) => Promise<LoginResult>;
  logout: () => void;
  updateProjectStatus: (projectId: string, newStatus: Project['status'], comment: string) => Promise<void>;
  updateBrief: (projectId: string, content: string) => Promise<void>;
  processQA: (projectId: string, approved: boolean, feedback: string) => Promise<void>;
  updateBilling: (projectId: string, facturado: boolean, justification?: string) => Promise<void>;
  checkSLA: (project: Project) => { isAlert: boolean; reason?: string };
  delegateProject: (projectId: string, area: string, userId: string) => Promise<void>;
  reassignProjectAndFolder: (projectId: string, companyName: string, newOwnerId: string) => Promise<void>;
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get } from 'firebase/database';
import { db } from './firebase';
import { Project, User, ODTContextType, ProjectComment, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Mantenimiento de sesión: Cargar desde localStorage
  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión persistente", e);
      }
    }
  }, []);

  // Sincronización Real-time de los nodos principales
  useEffect(() => {
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let pL = false, uL = false, cL = false;

    // Función de seguridad para desbloquear la UI si Firebase tarda o devuelve nulo
    const check = () => { 
      if (pL && uL && cL) {
        setLoading(false); 
      }
    };

    // Timeout de seguridad: Si en 6 segundos no hay respuesta, forzamos la carga (posible base de datos vacía)
    const safetyTimeout = setTimeout(() => {
      if (loading) {
        console.warn("Firebase tardó demasiado en responder. Forzando acceso...");
        setLoading(false);
      }
    }, 6000);

    const unsubP = onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      pL = true; check();
    }, (err) => {
      console.error("Error en proyectos:", err);
      pL = true; check();
    });

    const unsubU = onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      uL = true; check();
    }, (err) => {
      console.error("Error en usuarios:", err);
      uL = true; check();
    });

    const unsubC = onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      cL = true; check();
    }, (err) => {
      console.error("Error en clientes:", err);
      cL = true; check();
    });

    return () => { 
      unsubP(); 
      unsubU(); 
      unsubC(); 
      clearTimeout(safetyTimeout);
    };
  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();

    // Bypass de Emergencia admin:admin
    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = {
        id: 'admin',
        nombre: 'Administrador (Bypass)',
        usuario: 'admin',
        departamento: 'Sistemas',
        nivel: UserRole.Admin
      };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }

    try {
      const userRef = ref(db, `users/${cleanUsername}`);
      const snapshot = await get(userRef);

      if (!snapshot.exists()) {
        // Diagnóstico por consola si no se encuentra
        const allUsersSnap = await get(ref(db, 'users'));
        if (allUsersSnap.exists()) {
          console.log('USUARIOS DISPONIBLES EN DB:', Object.keys(allUsersSnap.val()));
        }
        return { success: false, error: `El usuario "${cleanUsername}" no existe.` };
      }

      const userData = snapshot.val();
      if (userData.password !== pass) {
        return { success: false, error: 'Contraseña incorrecta.' };
      }

      const authUser: User = {
        ...userData,
        id: cleanUsername,
        usuario: cleanUsername
      };

      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };

    } catch (error: any) {
      console.error("Fallo de comunicación:", error);
      return { success: false, error: 'Error de red con Firebase: ' + error.message };
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);
    if (project.status === 'En Proceso' && hProd > 72) return { isAlert: true, reason: 'Producción > 72h' };
    if (project.status === 'QA' && hQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    await update(ref(db, `projects/${projectId}`), {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...(project.comentarios || [])]
    });
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    await update(ref(db, `projects/${projectId}`), {
      correccion_ok: approved,
      status: approved ? (project.status === 'QA' ? 'Finalizado' : project.status) : 'Correcciones',
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: ${area} -> ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const current = project.asignaciones || [];
    const filtered = current.filter(a => a.area !== area);
    const newAsignaciones = [...filtered, { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), { asignaciones: newAsignaciones, comentarios: [systemComment, ...(project.comentarios || [])], updatedAt: new Date().toISOString() });
  };

  const reassignProjectAndFolder = async (projectId: string, companyName: string, newOwnerId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === newOwnerId);
    if (!targetUser) return;

    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const systemComment: ProjectComment = {
      id: `reassign-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `REASIGNACIÓN ESTRATÉGICA: ODT y Carpeta de Cliente transferidas a ${targetUser.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const updates: any = {};
    updates[`projects/${projectId}/ownerId`] = newOwnerId;
    updates[`projects/${projectId}/updatedAt`] = new Date().toISOString();
    updates[`projects/${projectId}/comentarios`] = [systemComment, ...(project.comentarios || [])];

    // Buscar la "Carpeta" (nodo Client) por nombre de empresa
    const clientFolder = clients.find(c => c.name.toLowerCase().trim() === companyName.toLowerCase().trim());
    if (clientFolder) {
      updates[`clients/${clientFolder.id}/ownerId`] = newOwnerId;
    } else {
      console.warn(`No se encontró carpeta para la empresa "${companyName}" para actualizar propiedad.`);
    }

    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, 
      checkSLA, delegateProject, reassignProjectAndFolder 
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, users, checkSLA, updateProjectStatus, updateBrief, processQA, reassignProjectAndFolder } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [auditResult, setAuditResult] = useState<any>(null);
  const [isAuditing, setIsAuditing] = useState(false);
  const [newOwnerId, setNewOwnerId] = useState(project.ownerId || '');

  const sla = checkSLA(project);

  const handleSaveBrief = () => {
    updateBrief(project.id, briefContent);
    alert("Brief Maestro guardado exitosamente.");
  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  const handleReassign = async () => {
    if (!newOwnerId) return;
    if (confirm(`¿Está seguro de transferir este proyecto y su carpeta de cliente al nuevo ejecutivo?`)) {
      await reassignProjectAndFolder(project.id, project.empresa, newOwnerId);
      alert("Propiedad reasignada correctamente.");
    }
  };

  // Roles in Production Area
  const isProductionRole = [
    UserRole.Creativo_Opera, 
    UserRole.Diseno_Opera, 
    UserRole.Creativo_Lider, 
    UserRole.Diseno_Lider
  ].includes(user?.nivel as UserRole);

  const isQAUser = user?.nivel === UserRole.QA;
  const isAdminOrLead = user?.nivel === UserRole.Admin || user?.nivel === UserRole.Cuentas_Lider;

  const accountsUsers = useMemo(() => 
    users.filter(u => u.nivel === UserRole.Cuentas_Opera || u.nivel === UserRole.Cuentas_Lider),
    [users]
  );

  const roadmapStages = ['Briefing', 'Producción', 'QA / Revisión', 'Facturación', 'Finalizado'];
  const getCurrentStageIndex = () => {
    if (project.status === 'Finalizado') return 4;
    if (project.status === 'QA') return 2;
    if (project.status === 'Borrador') return 0;
    return 1; // En Proceso / Correcciones
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-20">
      <header className="flex items-center gap-4">
        <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500">
           <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
        </button>
        <div>
          <h1 className="text-2xl font-black text-slate-900">{project.id}</h1>
          <p className="text-sm text-slate-500 font-medium">{project.empresa} - {project.producto}</p>
        </div>
      </header>

      {/* Hoja de Ruta */}
      <div className="bg-white p-6 rounded-2xl border shadow-sm">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Hoja de Ruta del Proyecto</h3>
        <div className="relative flex justify-between items-center">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-100 -translate-y-1/2 -z-10"></div>
          {roadmapStages.map((stage, idx) => {
            const currentIdx = getCurrentStageIndex();
            const isActive = idx === currentIdx;
            const isCompleted = idx < currentIdx;
            return (
              <div key={stage} className="flex flex-col items-center gap-2 bg-white px-2">
                <div className={`w-8 h-8 rounded-full border-4 flex items-center justify-center transition-all ${
                  isActive ? 'bg-blue-600 border-blue-200 shadow-lg scale-110' : 
                  isCompleted ? 'bg-emerald-500 border-emerald-100' : 'bg-slate-100 border-white'
                }`}>
                  {isCompleted ? (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                  ) : <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white' : 'bg-slate-300'}`}></div>}
                </div>
                <span className={`text-[9px] font-black uppercase tracking-tighter ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>{stage}</span>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          {/* Brief Maestro */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Icons.Project /> Brief Maestro
              </h3>
              <button onClick={handleSaveBrief} className="px-4 py-2 bg-blue-600 text-white text-xs font-bold rounded-lg hover:bg-blue-700 transition-all">
                GUARDAR BRIEF
              </button>
            </div>
            <ReactQuill 
              theme="snow" 
              value={briefContent} 
              onChange={(content) => setBriefContent(typeof content === 'string' ? content : '')} 
              modules={{
                toolbar: [
                  [{ 'header': [1, 2, false] }],
                  ['bold', 'italic', 'underline', 'strike'],
                  [{ 'list': 'ordered'}, { 'list': 'bullet' }],
                  ['link', 'image', 'video'],
                  ['clean']
                ],
              }}
            />
          </div>

          {/* Logs de Trazabilidad */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad ISO 9001</h3>
            <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
              {project.comentarios.map(c => (
                <div key={c.id} className={`p-4 rounded-xl text-xs border ${c.isSystemEvent ? 'bg-slate-50 border-dashed border-slate-200' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between mb-2">
                    <span className="font-black uppercase text-[9px] text-blue-500">{c.authorName}</span>
                    <span className="text-slate-400 font-mono text-[9px]">{new Date(c.createdAt).toLocaleString()}</span>
                  </div>
                  <p className="text-slate-700 font-medium">{c.text}</p>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {/* Reasignación de Propietario (Nuevo) */}
          {isAdminOrLead && (
            <div className="bg-white p-6 rounded-2xl border border-blue-100 shadow-sm space-y-4">
              <h3 className="text-blue-600 font-black text-xs uppercase tracking-widest flex items-center gap-2">
                <Icons.Users /> Control de Propiedad
              </h3>
              <p className="text-[10px] text-slate-500 font-medium uppercase">Asignar ODT y Carpeta a:</p>
              <select 
                className="w-full bg-slate-50 border rounded-xl px-3 py-2.5 text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500"
                value={newOwnerId}
                onChange={(e) => setNewOwnerId(e.target.value)}
              >
                <option value="" disabled>Seleccionar Ejecutivo...</option>
                {accountsUsers.map(u => <option key={u.id} value={u.id}>{u.nombre.toUpperCase()}</option>)}
              </select>
              <button 
                onClick={handleReassign}
                disabled={newOwnerId === project.ownerId}
                className="w-full py-2.5 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-slate-800 disabled:bg-slate-100 disabled:text-slate-400 transition-all"
              >
                Reasignar Maestro
              </button>
            </div>
          )}

          {/* QA Box / Compuerta de Calidad */}
          {isQAUser ? (
            <div className="bg-white p-6 rounded-2xl border-2 border-amber-200 shadow-xl space-y-4">
              <h3 className="font-black text-amber-600 text-xs uppercase tracking-widest flex items-center gap-2">
                <Icons.Ai /> Caja de Corrección (QA)
              </h3>
              <p className="text-xs text-slate-500">Revisa la trazabilidad y el brief antes de aprobar o rechazar el proyecto.</p>
              <textarea 
                placeholder="Feedback obligatorio para el equipo..."
                className="w-full bg-slate-50 border rounded-xl p-3 text-xs outline-none focus:ring-2 focus:ring-amber-500 h-24"
                value={qaFeedback}
                onChange={(e) => setQaFeedback(e.target.value)}
              />
              <div className="grid grid-cols-2 gap-3">
                <button 
                  disabled={!qaFeedback}
                  onClick={() => { processQA(project.id, true, qaFeedback); setQaFeedback(''); }}
                  className="py-3 bg-emerald-600 text-white font-black text-xs rounded-xl hover:bg-emerald-700 disabled:opacity-50 transition-all"
                >APROBAR</button>
                <button 
                  disabled={!qaFeedback}
                  onClick={() => { processQA(project.id, false, qaFeedback); setQaFeedback(''); }}
                  className="py-3 bg-rose-600 text-white font-black text-xs rounded-xl hover:bg-rose-700 disabled:opacity-50 transition-all"
                >RECHAZAR</button>
              </div>
            </div>
          ) : (
            <div className="bg-slate-900 p-6 rounded-2xl text-white shadow-xl space-y-4">
              <h3 className="text-blue-400 font-black text-xs uppercase tracking-widest flex items-center gap-2">
                <Icons.Plus /> Gestión de Etapas
              </h3>
              <p className="text-[10px] text-slate-400 uppercase font-bold">Estado actual: <span className="text-white">{project.status}</span></p>

              <button 
                disabled={isProductionRole && !project.correccion_ok && project.status !== 'Borrador'}
                onClick={() => updateProjectStatus(project.id, project.status === 'QA' ? 'Finalizado' : 'QA', 'Traspaso de etapa manual')}
                className="w-full py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 transition-all disabled:bg-slate-800 disabled:text-slate-600"
              >
                {project.status === 'QA' ? 'FINALIZAR PROYECTO' : 'ENVIAR A REVISIÓN QA'}
              </button>

              {isProductionRole && !project.correccion_ok && project.status !== 'Borrador' && (
                <div className="p-3 bg-rose-900/50 border border-rose-800 rounded-lg flex gap-2 items-center">
                   <div className="text-rose-500"><Icons.Ai /></div>
                   <p className="text-[10px] text-rose-200 font-medium">COMPUERTA DE CALIDAD: Avance bloqueado hasta aprobación QA.</p>
                </div>
              )}
            </div>
          )}

          {/* AI Audit Center */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm group">
            <h3 className="flex items-center gap-2 font-black text-xs mb-4 text-blue-600 uppercase tracking-widest"><Icons.Ai /> IA ISO AUDIT</h3>
            <button 
              onClick={handleAudit}
              disabled={isAuditing}
              className="w-full py-3 bg-slate-900 text-white rounded-xl font-black text-xs hover:bg-slate-800 transition-all flex items-center justify-center gap-2"
            >
              {isAuditing ? <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : 'AUDITAR ODT'}
            </button>
            {auditResult && (
              <div className="mt-4 p-4 bg-slate-50 rounded-xl border space-y-4 text-xs animate-fadeIn">
                <div className="flex justify-between items-end">
                  <span className="font-bold text-slate-400">SCORE:</span> 
                  <span className={`text-2xl font-black ${auditResult.score > 80 ? 'text-emerald-600' : 'text-amber-600'}`}>{auditResult.score}%</span>
                </div>
                <div className="text-[9px] text-slate-500 font-bold uppercase">Cláusula: {auditResult.isoClause}</div>
              </div>
            )}
          </div>

          {/* SLA Alert Pin */}
          {sla.isAlert && (
             <div className="p-4 bg-pink-50 border border-pink-100 rounded-2xl shadow-lg shadow-pink-100/50 flex flex-col gap-1 animate-pulse">
                <span className="text-pink-600 font-black text-[10px] uppercase tracking-widest flex items-center gap-1">⚠️ ALERTA DE SLA</span>
                <p className="text-pink-800 text-xs font-bold leading-tight">{sla.reason}</p>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

