import React, { useMemo } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Project } from './types';

const LeaderDashboard: React.FC = () => {
  const { user, projects, users, checkSLA, delegateProject } = useODT();

  // 1. Filtrar miembros del equipo (mismo departamento, excluyendo al líder)
  const teamMembers = useMemo(() => {
    if (!user) return [];
    return users.filter(u => u.departamento === user.departamento && u.id !== user.id);
  }, [user, users]);

  // 2. Calcular estadísticas por integrante basadas en SLA ISO
  const memberStats = useMemo(() => {
    return teamMembers.map(m => {
      const assignedProjects = projects.filter(p => 
        p.asignaciones?.some(a => a.usuarioId === m.id)
      );

      const total = assignedProjects.length;
      // El SLA de 72h ya viene validado en checkSLA para proyectos 'En Proceso'
      const delayed = assignedProjects.filter(p => checkSLA(p).isAlert).length;
      const onTime = total - delayed;

      return { ...m, total, onTime, delayed };
    });
  }, [teamMembers, projects, checkSLA]);

  // 3. ODTs que requieren intervención del área pero no han sido delegadas
  const pendingProjects = useMemo(() => {
    if (!user) return [];
    const area = user.nivel === UserRole.Creativo_Lider ? 'Creativo' : 'Diseño';
    return projects.filter(p => 
      p.areas_seleccionadas?.includes(area) && 
      !p.asignaciones?.some(a => a.area === area) &&
      p.status !== 'Finalizado' &&
      p.status !== 'Cancelado'
    );
  }, [user, projects]);

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex justify-between items-end border-b border-slate-200 pb-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Control de Operaciones</h1>
          <p className="text-slate-500 font-medium flex items-center gap-2">
            Área: <span className="text-blue-600 font-bold uppercase">{user?.departamento}</span>
          </p>
        </div>
        <div className="text-right">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Capacidad Instalada</p>
          <p className="text-2xl font-black text-slate-900">{teamMembers.length} <span className="text-sm text-slate-400">Integrantes</span></p>
        </div>
      </header>

      {/* Monitoreo de Colaboradores */}
      <section className="space-y-4">
        <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
          <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
          Rendimiento del Equipo vs SLA (72h)
        </h2>
        <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/40 overflow-hidden">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50/50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
              <tr>
                <th className="px-8 py-5">Colaborador</th>
                <th className="px-6 py-5 text-center">ODTs Totales</th>
                <th className="px-6 py-5 text-center">Al Día</th>
                <th className="px-6 py-5 text-center">Atrasadas</th>
                <th className="px-8 py-5">Nivel de Saturación</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {memberStats.map(m => (
                <tr key={m.id} className="hover:bg-blue-50/30 transition-colors group">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-2xl bg-slate-900 text-white flex items-center justify-center font-black text-xs shadow-lg group-hover:scale-110 transition-transform">
                        {m.nombre.substring(0,2).toUpperCase()}
                      </div>
                      <div>
                        <div className="font-bold text-slate-900">{m.nombre}</div>
                        <div className="text-[10px] text-slate-400 font-black uppercase tracking-tighter">{m.usuario}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-5 text-center font-black text-slate-900 text-lg">{m.total}</td>
                  <td className="px-6 py-5 text-center">
                    <span className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full font-black text-xs border border-emerald-100">{m.onTime}</span>
                  </td>
                  <td className="px-6 py-5 text-center">
                    <span className={`px-3 py-1 rounded-full font-black text-xs border transition-all ${
                      m.delayed > 0 
                        ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' 
                        : 'bg-slate-50 text-slate-300 border-slate-100'
                    }`}>
                      {m.delayed}
                    </span>
                  </td>
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className="flex-1 bg-slate-100 rounded-full h-2.5 overflow-hidden">
                        <div 
                          className={`h-full rounded-full transition-all duration-1000 ${m.total > 7 ? 'bg-rose-500' : m.total > 4 ? 'bg-amber-500' : 'bg-blue-500'}`} 
                          style={{width: `${Math.min(100, (m.total/10)*100)}%`}}
                        ></div>
                      </div>
                      <span className="text-[10px] font-black text-slate-400 w-8">{Math.min(100, (m.total/10)*100)}%</span>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      {/* Delegación Crítica */}
      <section className="space-y-4">
        <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
          <div className="w-2 h-2 bg-amber-500 rounded-full"></div>
          ODTs Pendientes de Asignación
        </h2>
        {pendingProjects.length === 0 ? (
          <div className="p-12 bg-white rounded-3xl border-2 border-dashed border-slate-100 text-center">
            <div className="w-16 h-16 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M20 6 9 17l-5-5"/></svg>
            </div>
            <p className="text-slate-400 font-bold text-sm">Flujo de trabajo al día. No hay pendientes de delegación.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {pendingProjects.map(p => (
              <div key={p.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/30 flex flex-col justify-between hover:border-blue-200 transition-all group">
                <div>
                  <div className="flex justify-between items-start mb-4">
                    <span className="text-[11px] font-black text-blue-600 font-mono bg-blue-50 px-2 py-1 rounded-md">{p.id}</span>
                    <span className="text-[9px] bg-amber-50 text-amber-600 px-2 py-1 rounded-full font-black border border-amber-100 uppercase tracking-tighter">Acción Requerida</span>
                  </div>
                  <h4 className="font-black text-slate-800 text-lg leading-tight mb-1 group-hover:text-blue-600 transition-colors">{p.empresa}</h4>
                  <p className="text-xs text-slate-500 font-bold uppercase tracking-tight mb-4">{p.producto}</p>
                </div>

                <div className="pt-6 border-t border-slate-50">
                   <p className="text-[9px] font-black text-slate-400 uppercase mb-2 tracking-widest">Asignar Responsable:</p>
                   <select 
                    className="w-full bg-slate-50 border-2 border-transparent rounded-xl px-4 py-3 text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white transition-all appearance-none cursor-pointer"
                    onChange={(e) => {
                      const area = user?.nivel === UserRole.Creativo_Lider ? 'Creativo' : 'Diseño';
                      if(e.target.value) delegateProject(p.id, area, e.target.value);
                    }}
                    defaultValue=""
                   >
                     <option value="" disabled>SELECCIONAR...</option>
                     {teamMembers.map(m => <option key={m.id} value={m.id}>{m.nombre.toUpperCase()}</option>)}
                   </select>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>
    </div>
  );
};

