import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get, set, push } from 'firebase/database';
import { db } from './firebase';
import { Project, User, ODTContextType, ProjectComment, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión persistente", e);
      }
    }
  }, []);

  useEffect(() => {
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let pL = false, uL = false, cL = false;
    const check = () => { if (pL && uL && cL) setLoading(false); };

    const unsubP = onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      pL = true; check();
    });

    const unsubU = onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      uL = true; check();
    });

    const unsubC = onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      cL = true; check();
    });

    return () => { unsubP(); unsubU(); unsubC(); };
  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', nombre: 'Administrador (Bypass)', usuario: 'admin', departamento: 'Sistemas', nivel: UserRole.Admin };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }
    try {
      const userRef = ref(db, `users/${cleanUsername}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `El usuario "${cleanUsername}" no existe.` };
      const userData = snapshot.val();
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };
      const authUser: User = { ...userData, id: cleanUsername, usuario: cleanUsername };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de red con Firebase: ' + error.message };
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('apc_session');
  };

  const addClient = async (name: string, notes?: string) => {
    if (!user) return;
    const newClientRef = push(ref(db, 'clients'));
    await set(newClientRef, {
      name,
      notes: notes || '',
      ownerId: user.id,
      createdAt: new Date().toISOString()
    });
  };

  const addProject = async (projectData: Partial<Project>) => {
    if (!user) return;
    const projectId = projectData.id;
    if (!projectId) return;

    const initialComment: ProjectComment = {
      id: `sys-init-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `PROYECTO INICIADO: Etapa Cuentas. Apertura realizada por ${user.nombre}.`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };

    const newProject: any = {
      ...projectData,
      status: 'Borrador',
      etapa_actual: 'Cuentas',
      correccion_ok: false,
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [initialComment],
      asignaciones: []
    };

    await set(ref(db, `projects/${projectId}`), newProject);
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const createdDate = new Date(project.createdAt);
    const updatedDate = new Date(project.updatedAt);
    const hProd = (now.getTime() - createdDate.getTime()) / (1000 * 60 * 60);
    const hQA = (now.getTime() - updatedDate.getTime()) / (1000 * 60 * 60);
    if (project.status === 'En Proceso' && hProd > 72) return { isAlert: true, reason: 'Producción > 72h' };
    if (project.status === 'QA' && hQA > 24) return { isAlert: true, reason: 'QA > 24h' };
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const systemComment: ProjectComment = {
      id: `sys-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `ESTADO: ${newStatus}. ${commentText}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    await update(ref(db, `projects/${projectId}`), {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [systemComment, ...(project.comentarios || [])]
    });
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `qa-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA (QA)',
      text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    await update(ref(db, `projects/${projectId}`), {
      correccion_ok: approved,
      status: approved ? (project.status === 'QA' ? 'Finalizado' : project.status) : 'Correcciones',
      comentarios: [systemComment, ...(project.comentarios || [])],
      updatedAt: new Date().toISOString()
    });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === userId);
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `sys-del-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `DELEGACIÓN: ${area} -> ${targetUser?.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const current = project.asignaciones || [];
    const filtered = current.filter(a => a.area !== area);
    const newAsignaciones = [...filtered, { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), { asignaciones: newAsignaciones, comentarios: [systemComment, ...(project.comentarios || [])], updatedAt: new Date().toISOString() });
  };

  const reassignProjectAndFolder = async (projectId: string, companyName: string, newOwnerId: string) => {
    if (!user) return;
    const targetUser = users.find(u => u.id === newOwnerId);
    if (!targetUser) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const systemComment: ProjectComment = {
      id: `reassign-${Date.now()}`,
      authorId: user.id,
      authorName: 'SISTEMA',
      text: `REASIGNACIÓN ESTRATÉGICA: ODT y Carpeta de Cliente transferidas a ${targetUser.nombre}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    const updates: any = {};
    updates[`projects/${projectId}/ownerId`] = newOwnerId;
    updates[`projects/${projectId}/updatedAt`] = new Date().toISOString();
    updates[`projects/${projectId}/comentarios`] = [systemComment, ...(project.comentarios || [])];
    const clientFolder = clients.find(c => c.name.toLowerCase().trim() === companyName.toLowerCase().trim());
    if (clientFolder) updates[`clients/${clientFolder.id}/ownerId`] = newOwnerId;
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, 
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Client, UserRole, Project } from './types';
import { Icons } from './constants';

interface NewODTFormProps {
  client: Client;
  onClose: () => void;
}

const CATEGORIES: Record<string, string[]> = {
  'DIGITAL': ['Veeva', 'Mailing', 'Landing Page', 'Display Ads', 'App Mobile', 'E-commerce'],
  'IMPRESO': ['Folleto', 'Brochure', 'Panel / Gigantografía', 'Stand', 'Merchandising'],
  'EVENTO': ['Kick-off', 'Convención', 'Congreso', 'Lanzamiento'],
  'PARRILLA RRSS': ['Facebook', 'Instagram', 'LinkedIn', 'TikTok', 'YouTube']
};

const AREAS = [
  'Creativo', 'Medical', 'Diseño', 'Social Media', 'Desarrollo', 
  'Producción Audiovisual', 'Cuentas', 'QA', 'Finanzas', 'Tráfico'
];

const NewODTForm: React.FC<NewODTFormProps> = ({ client, onClose }) => {
  const { user, projects, addProject } = useODT();
  const [loading, setLoading] = useState(false);

  // Form State
  const [marca, setMarca] = useState('');
  const [producto, setProducto] = useState('');
  const [category, setCategory] = useState('');
  const [subCategory, setSubCategory] = useState('');
  const [hasBilling, setHasBilling] = useState(false);
  const [monto, setMonto] = useState(0);
  const [justification, setJustification] = useState('');
  const [selectedAreas, setSelectedAreas] = useState<string[]>([]);
  const [brief, setBrief] = useState('');
  const [links, setLinks] = useState<string[]>(['']);

  const generateODTId = () => {
    const year = new Date().getFullYear();
    const count = projects.filter(p => p.id.startsWith(`APC-${year}`)).length + 1;
    return `APC-${year}-${count.toString().padStart(3, '0')}`;
  };

  const handleAddLink = () => setLinks([...links, '']);
  const handleLinkChange = (idx: number, val: string) => {
    const newLinks = [...links];
    newLinks[idx] = val;
    setLinks(newLinks);
  };

  const toggleArea = (area: string) => {
    setSelectedAreas(prev => 
      prev.includes(area) ? prev.filter(a => a !== area) : [...prev, area]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const newProject: Partial<Project> = {
        id: generateODTId(),
        clientId: client.id,
        empresa: client.name,
        marca,
        producto,
        category,
        subCategory,
        monto_proyectado: hasBilling ? monto : 0,
        justificacion_no_facturado: !hasBilling ? justification : '',
        areas_seleccionadas: selectedAreas,
        referenceLinks: links.filter(l => l.trim() !== ''),
        brief,
        facturado: false
      };
      await addProject(newProject);
      alert(`ODT ${newProject.id} creada exitosamente.`);
      onClose();
    } catch (err) {
      alert("Error al crear la ODT.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-4xl max-h-[90vh] rounded-3xl shadow-2xl overflow-hidden flex flex-col animate-fadeIn">
        <header className="bg-slate-900 p-6 flex justify-between items-center text-white">
          <div>
            <h2 className="text-xl font-black tracking-tight">Apertura de ODT Master</h2>
            <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-1">ISO 9001:2015 - Carpeta: {client.name}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-xl transition-all">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M18 6 6 18M6 6l12 12"/></svg>
          </button>
        </header>

        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8">
          {/* Identificación Básica */}
          <section className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">ID Generado</label>
              <div className="px-4 py-3 bg-slate-100 rounded-xl font-mono font-black text-blue-600 border border-slate-200">{generateODTId()}</div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Marca</label>
              <input required value={marca} onChange={e => setMarca(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" placeholder="Ejem: Roche, Pfizer..." />
            </div>
            <div className="space-y-2">
