import React, { useState } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Client } from './types';
import { Icons } from './constants';
import NewODTForm from './NewODTForm';

const ClientsView: React.FC = () => {
  const { user, clients, projects, addClient } = useODT();
  const [isCreatingClient, setIsCreatingClient] = useState(false);
  const [newClientName, setNewClientName] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);

  const canCreateClient = user?.nivel === UserRole.Admin || user?.nivel === UserRole.Cuentas_Lider || user?.nivel === UserRole.Cuentas_Opera;

  const handleCreateClient = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClientName) return;
    await addClient(newClientName);
    setNewClientName('');
    setIsCreatingClient(false);
    alert(`Carpeta "${newClientName}" creada correctamente.`);
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Archivo de Clientes</h1>
          <p className="text-slate-500 font-medium text-sm flex items-center gap-2">
            <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
            Gestión de Carpetas Maestras ISO 9001
          </p>
        </div>

        {canCreateClient && (
          <button 
            onClick={() => setIsCreatingClient(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-black text-xs rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-200"
          >
            <Icons.Plus /> NUEVA CARPETA DE CLIENTE
          </button>
        )}
      </header>

      {/* Grid de Carpetas */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {clients.map(client => {
          const clientODTs = projects.filter(p => p.clientId === client.id);
          const activeODTs = clientODTs.filter(p => p.status !== 'Finalizado' && p.status !== 'Cancelado').length;

          return (
            <div key={client.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/30 hover:shadow-2xl hover:border-blue-100 transition-all group flex flex-col justify-between">
              <div>
                <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-white mb-6 group-hover:bg-blue-600 transition-colors">
                  <Icons.Clients />
                </div>
                <h3 className="text-xl font-black text-slate-800 leading-tight mb-2 truncate">{client.name}</h3>
                <div className="flex gap-4 mb-8">
                   <div>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Activas</p>
                     <p className="text-lg font-black text-slate-900">{activeODTs}</p>
                   </div>
                   <div className="w-px h-8 bg-slate-100"></div>
                   <div>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Histórico</p>
                     <p className="text-lg font-black text-slate-400">{clientODTs.length}</p>
                   </div>
                </div>
              </div>

              <button 
                onClick={() => setSelectedClient(client)}
                className="w-full py-3 bg-slate-50 text-slate-900 font-black text-[10px] uppercase tracking-widest rounded-xl border border-slate-100 hover:bg-slate-900 hover:text-white transition-all flex items-center justify-center gap-2"
              >
                <Icons.Plus /> ABRIR ODT MASTER
              </button>
            </div>
          );
        })}
      </div>

      {/* Modal Nueva Carpeta */}
      {isCreatingClient && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl animate-fadeIn">
            <h2 className="text-2xl font-black text-slate-900 mb-2">Nueva Carpeta</h2>
            <p className="text-xs text-slate-500 font-medium mb-6">El nombre debe coincidir exactamente con el nombre legal o comercial de la empresa.</p>
            <form onSubmit={handleCreateClient} className="space-y-4">
               <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Nombre de Empresa</label>
                  <input autoFocus value={newClientName} onChange={e => setNewClientName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" placeholder="Ejem: Laboratorios Roche S.A." />
               </div>
               <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setIsCreatingClient(false)} className="flex-1 py-3 text-xs font-black text-slate-400 uppercase hover:text-slate-600">Cancelar</button>
                  <button type="submit" className="flex-1 py-3 bg-slate-900 text-white font-black text-xs rounded-xl hover:bg-slate-800 transition-all shadow-xl shadow-slate-200">CREAR CARPETA</button>
               </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Nueva ODT Form */}
      {selectedClient && (
        <NewODTForm client={selectedClient} onClose={() => setSelectedClient(null)} />
      )}
    </div>
  );
};

export default ClientsView;

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ODTProvider, useODT } from './ODTContext';
import { AppRouter } from './AppRouter';
import AdminDashboard from './AdminDashboard';
import LeaderDashboard from './LeaderDashboard';
import ProjectDetail from './ProjectDetail';
import ClientsView from './ClientsView';

const AppContent: React.FC = () => {
  const { user, projects, checkSLA, updateBilling, loading } = useODT();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  if (loading) {
    return (
      <div className="bg-[#0a0a0a] h-screen w-screen flex flex-col items-center justify-center gap-6 animate-pulse">
        <div className="w-16 h-16 border-4 border-t-[#00f2ff] border-[#00f2ff]/10 rounded-full animate-spin"></div>
        <div className="text-center">
          <h1 className="text-[#00f2ff] font-black text-xl tracking-[0.3em] uppercase">Conectando con APC Servers</h1>
          <p className="text-slate-500 text-xs mt-2 font-bold tracking-widest uppercase">Seguridad ISO 9001:2015 en curso...</p>
        </div>
      </div>
    );
  }

  const renderMyInbox = () => {
    const myProjects = projects?.filter(p => 
      p?.asignaciones?.some(a => a?.usuarioId === user?.id) || 
      (p?.ownerId === user?.id)
    ) || [];

    return (
      <div className="space-y-6">
        <header className="flex justify-between items-end">
          <h1 className="text-3xl font-black">Bandeja de Entrada</h1>
        </header>
        <div className="bg-white p-6 rounded-xl border-2 border-dashed border-slate-200">
           {myProjects.length === 0 ? (
             <p className="text-slate-400 italic text-center py-10">No tienes tareas asignadas por el momento.</p>
           ) : (
             <ProjectTable projects={myProjects} onView={setSelectedProject} checkSLA={checkSLA} />
           )}
        </div>
      </div>
    );
  };

  const renderQABox = () => {
    const qaProjects = projects?.filter(p => p?.status === 'QA') || [];
    return (
      <div className="space-y-6">
        <header><h1 className="text-3xl font-black">Caja de Corrección (QA)</h1></header>
        {qaProjects.length === 0 ? (
           <div className="p-12 text-center bg-white rounded-2xl border border-dashed text-slate-400 italic">No hay proyectos pendientes de QA.</div>
        ) : (
           <ProjectTable projects={qaProjects} onView={setSelectedProject} checkSLA={checkSLA} />
        )}
      </div>
    );
  };

  const renderFinances = () => (
    <div className="space-y-6">
      <header><h1 className="text-3xl font-black">Gestión de Facturación</h1></header>
      <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
            <tr>
              <th className="px-6 py-4">ODT</th>
              <th className="px-6 py-4">Cliente</th>
              <th className="px-6 py-4">Monto</th>
              <th className="px-6 py-4 text-center">Facturado</th>
              <th className="px-6 py-4">Justificación</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {projects?.map(p => (
              <tr key={p?.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-mono font-black text-blue-600">{p?.id}</td>
                <td className="px-6 py-4 font-medium text-slate-700">{p?.empresa}</td>
                <td className="px-6 py-4 font-black text-slate-900">${p?.monto_proyectado?.toLocaleString()}</td>
                <td className="px-6 py-4 text-center">
                  <input type="checkbox" checked={p?.facturado} onChange={e => updateBilling(p?.id, e.target.checked)} className="w-5 h-5 accent-blue-600 cursor-pointer" />
                </td>
                <td className="px-6 py-4">
                  {!p?.facturado && (
                    <input 
                      className="w-full bg-rose-50 border-rose-100 border rounded px-3 py-1.5 text-xs outline-none focus:ring-1 focus:ring-rose-500 placeholder:text-rose-300"
                      placeholder="Indica motivo del retraso..."
                      value={p?.justificacion_no_facturado || ''}
                      onChange={e => updateBilling(p?.id, false, e.target.value)}
                    />
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderView = (view: ViewState) => {
    if (selectedProject) return <ProjectDetail project={selectedProject} onBack={() => setSelectedProject(null)} />;
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'clients': return <ClientsView />;
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

const ProjectTable = ({ projects, onView, checkSLA }: any) => (
  <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
    <table className="w-full text-sm text-left">
