import React, { useMemo, useState } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Project } from './types';

const LeaderDashboard: React.FC = () => {
  const { user, projects, users, checkSLA, delegateProject } = useODT();
  const [memberFilter, setMemberFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');

  // Área actual del líder
  const leaderArea = useMemo(() => {
    if (user?.nivel === UserRole.Creativo_Lider) return 'Creativo';
    if (user?.nivel === UserRole.Diseno_Lider) return 'Diseño';
    return '';
  }, [user]);

  // Miembros del equipo
  const teamMembers = useMemo(() => {
    if (!user) return [];
    return users.filter(u => u.departamento === user.departamento && u.id !== user.id);
  }, [user, users]);

  // Todas las ODTs que competen al área del líder
  const areaProjects = useMemo(() => {
    if (!leaderArea) return [];
    let filtered = projects.filter(p => p.areas_seleccionadas?.includes(leaderArea));

    if (memberFilter !== 'all') {
      filtered = filtered.filter(p => p.asignaciones?.some(a => a.usuarioId === memberFilter && a.area === leaderArea));
    }

    if (statusFilter !== 'all') {
      filtered = filtered.filter(p => p.status === statusFilter);
    }

    return filtered;
  }, [projects, leaderArea, memberFilter, statusFilter]);

  // Estadísticas de saturación
  const memberStats = useMemo(() => {
    return teamMembers.map(m => {
      const assignedProjects = projects.filter(p => 
        p.asignaciones?.some(a => a.usuarioId === m.id) &&
        p.status !== 'Finalizado' && p.status !== 'Cancelado'
      );
      const total = assignedProjects.length;
      const delayed = assignedProjects.filter(p => checkSLA(p).isAlert).length;
      return { ...m, total, delayed };
    });
  }, [teamMembers, projects, checkSLA]);

  // ODTs del área que no han sido delegadas aún
  const pendingProjects = useMemo(() => {
    return projects.filter(p => 
      p.areas_seleccionadas?.includes(leaderArea) && 
      !p.asignaciones?.some(a => a.area === leaderArea) &&
      p.status !== 'Finalizado' && p.status !== 'Cancelado'
    );
  }, [projects, leaderArea]);

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 border-b border-slate-200 pb-8">
        <div>
