import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get, set, push } from 'firebase/database';
import { db } from './firebase';
import { Project, User, ODTContextType, ProjectComment, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión", e);
      }
    }
  }, []);

  useEffect(() => {
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let pL = false, uL = false, cL = false;
    const check = () => { if (pL && uL && cL) setLoading(false); };
    const safetyTimeout = setTimeout(() => { if (loading) setLoading(false); }, 5000);

    const unsubP = onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      pL = true; check();
    }, () => { pL = true; check(); });

    const unsubU = onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      uL = true; check();
    }, () => { uL = true; check(); });

    const unsubC = onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      cL = true; check();
    }, () => { cL = true; check(); });

    return () => { unsubP(); unsubU(); unsubC(); clearTimeout(safetyTimeout); };
  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', nombre: 'Administrador (Bypass)', usuario: 'admin', departamento: 'Sistemas', nivel: UserRole.Admin, activo: true };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }
    try {
      const userRef = ref(db, `users/${cleanUsername}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `Usuario no encontrado.` };
      const userData = snapshot.val();
      if (!userData.activo) return { success: false, error: 'Esta cuenta ha sido desactivada.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };
      const authUser: User = { ...userData, id: cleanUsername, usuario: cleanUsername };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const manageUser = async (userData: Partial<User>) => {
    if (!userData.usuario) return;
    const cleanUsername = userData.usuario.toLowerCase().trim();
    const existingRef = ref(db, `users/${cleanUsername}`);
    const snapshot = await get(existingRef);

    const newUser = {
      ...snapshot.val(),
      ...userData,
      usuario: cleanUsername,
      activo: userData.activo ?? true
    };

    await set(ref(db, `users/${cleanUsername}`), newUser);
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    await update(ref(db, `users/${userId}`), { activo: active });
  };

  const addClient = async (name: string, notes?: string) => {
    if (!user) return;
    const newClientRef = push(ref(db, 'clients'));
    await set(newClientRef, { name, notes: notes || '', ownerId: user.id, createdAt: new Date().toISOString() });
  };

  const addProject = async (projectData: Partial<Project>) => {
    if (!user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    const newProject: any = {
      ...projectData,
      status: 'Borrador',
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `sys-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA',
        text: `PROYECTO CREADO por ${user.nombre}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }],
      asignaciones: [],
      pagado: false
    };
    await set(ref(db, `projects/${projectId}`), newProject);
  };

  const checkSLA = (project: Project) => {
    const now = new Date();
    const lastUpdate = new Date(project.updatedAt);
    const hoursInStage = (now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    if (project.status !== 'Finalizado' && project.status !== 'Cancelado' && hoursInStage > 72) {
      return { isAlert: true, reason: `Estancado > 72h` };
    }
    return { isAlert: false };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `sys-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA',
        text: `ESTADO: ${newStatus}. ${commentText}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }, ...(project.comentarios || [])]
    };
    if (newStatus === 'Finalizado') {
      updates.fecha_finalizado = new Date().toISOString();
    }
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBrief = async (projectId: string, content: string) => {
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      correccion_ok: approved,
      status: approved ? 'Finalizado' : 'Correcciones',
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `qa-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA (QA)',
        text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }, ...(project.comentarios || [])]
    };
    if (approved) updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    await update(ref(db, `projects/${projectId}`), { pagado, updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const target = users.find(u => u.id === userId);
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      status: 'En Proceso',
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `del-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA',
        text: `DELEGACIÓN: ${area} -> ${target?.nombre}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }, ...(project.comentarios || [])]
    });
  };

  const reassignProjectAndFolder = async (projectId: string, companyName: string, newOwnerId: string) => {
    if (!user) return;
    const updates: any = {};
    updates[`projects/${projectId}/ownerId`] = newOwnerId;
    updates[`projects/${projectId}/updatedAt`] = new Date().toISOString();
    const client = clients.find(c => c.name === companyName);
    if (client) updates[`clients/${client.id}/ownerId`] = newOwnerId;
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject,
      manageUser, toggleUserStatus
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ODTProvider, useODT } from './ODTContext';
import { AppRouter } from './AppRouter';
import AdminDashboard from './AdminDashboard';
import LeaderDashboard from './LeaderDashboard';
import ProjectDetail from './ProjectDetail';
import ClientsView from './ClientsView';
import UsersView from './UsersView';

const AppContent: React.FC = () => {
  const { user, projects, checkSLA, updateBilling, updatePaymentStatus, loading } = useODT();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  if (loading) {
    return (
      <div className="bg-[#0a0a0a] h-screen w-screen flex flex-col items-center justify-center gap-6 animate-pulse">
        <div className="w-16 h-16 border-4 border-t-[#00f2ff] border-[#00f2ff]/10 rounded-full animate-spin"></div>
        <div className="text-center">
          <h1 className="text-[#00f2ff] font-black text-xl tracking-[0.3em] uppercase">Conectando con APC Servers</h1>
          <p className="text-slate-500 text-xs mt-2 font-bold tracking-widest uppercase">Seguridad ISO 9001:2015 en curso...</p>
        </div>
      </div>
    );
  }

  const renderMyInbox = () => {
    // Lógica reformada: Los operativos solo ven donde están asignados directamente.
    // Los líderes y admins ven todo bajo su propiedad.
    const isLeadOrAdmin = user?.nivel === UserRole.Admin || user?.nivel.endsWith('_Lider');

    const myProjects = projects?.filter(p => {
      if (isLeadOrAdmin) return p.ownerId === user?.id || p.asignaciones?.some(a => a.usuarioId === user?.id);
      return p.asignaciones?.some(a => a.usuarioId === user?.id);
    }) || [];

    return (
      <div className="space-y-6">
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-black">Mi Bandeja Operativa</h1>
