            <form onSubmit={handleCreateClient} className="space-y-4">
               <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Nombre de Empresa</label>
                  <input 
                    autoFocus 
                    disabled={isSubmitting}
                    value={newClientName} 
                    onChange={e => setNewClientName(e.target.value)} 
                    className="w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold disabled:opacity-50" 
                    placeholder="Ejem: Laboratorios Roche S.A." 
                  />
               </div>
               <div className="flex gap-3 pt-4">
                  <button type="button" disabled={isSubmitting} onClick={() => setIsCreatingClient(false)} className="flex-1 py-3 text-xs font-black text-slate-400 uppercase hover:text-slate-600 disabled:opacity-50">Cancelar</button>
                  <button type="submit" disabled={isSubmitting} className="flex-1 py-3 bg-slate-900 text-white font-black text-xs rounded-xl hover:bg-slate-800 transition-all shadow-xl shadow-slate-200 flex items-center justify-center gap-2">
                    {isSubmitting ? (
                      <>
                        <div className="w-3 h-3 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
                        CREANDO...
                      </>
                    ) : 'CREAR CARPETA'}
                  </button>
               </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Nueva ODT Form */}
      {selectedClient && (
        <NewODTForm client={selectedClient} onClose={() => setSelectedClient(null)} />
      )}
    </div>
  );
};

export default ClientsView;

