import { db } from './firebase';
import { Project, User, ODTContextType, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  // Recuperar sesión persistente
  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión", e);
      }
    }
  }, []);

  // Timeout de seguridad Anti-Pantalla Blanca (4 segundos)
  useEffect(() => {
    const timer = setTimeout(() => {
      if (loading) {
        console.warn("Safety Timeout: Forzando carga tras 4 segundos sin respuesta de Firebase.");
        setLoading(false);
      }
    }, 4000);
    return () => clearTimeout(timer);
  }, [loading]);

  // Función para sembrar usuarios iniciales
  const seedUsers = async () => {
    if (!db) return;
    try {
      const usersRef = ref(db, 'users');
      const snapshot = await get(usersRef);
      if (!snapshot.exists()) {
        const usersToSeed: Record<string, any> = {
          'admin.apc': { nombre: 'Super Administrador', usuario: 'admin.apc', password: 'apc.password.2025', departamento: 'Sistemas', nivel: UserRole.Admin, activo: true, email: 'admin@apc.com' },
          'lider.cuentas': { nombre: 'Jefe de Cuentas', usuario: 'lider.cuentas', password: 'apc.password.2025', departamento: 'Cuentas', nivel: UserRole.Cuentas_Lider, activo: true, email: 'jefe.cuentas@apc.com' },
          'opera.cuentas': { nombre: 'Ejecutivo de Cuentas', usuario: 'opera.cuentas', password: 'apc.password.2025', departamento: 'Cuentas', nivel: UserRole.Cuentas_Opera, activo: true, email: 'opera.cuentas@apc.com' },
          'lider.creativo': { nombre: 'Director Creativo', usuario: 'lider.creativo', password: 'apc.password.2025', departamento: 'Creativo', nivel: UserRole.Creativo_Lider, activo: true, email: 'dir.creativo@apc.com' },
          'opera.creativo': { nombre: 'Redactor Creativo', usuario: 'opera.creativo', password: 'apc.password.2025', departamento: 'Creativo', nivel: UserRole.Creativo_Opera, activo: true, email: 'copy.creativo@apc.com' },
          'lider.diseno': { nombre: 'Director de Arte', usuario: 'lider.diseno', password: 'apc.password.2025', departamento: 'Diseño', nivel: UserRole.Diseno_Lider, activo: true, email: 'dir.arte@apc.com' },
          'opera.diseno': { nombre: 'Diseñador Senior', usuario: 'opera.diseno', password: 'apc.password.2025', departamento: 'Diseño', nivel: UserRole.Diseno_Opera, activo: true, email: 'senior.diseno@apc.com' },
          'qa.master': { nombre: 'Auditor de Calidad', usuario: 'qa.master', password: 'apc.password.2025', departamento: 'QA', nivel: UserRole.QA, activo: true, email: 'qa@apc.com' },
          'finanzas.apc': { nombre: 'Contralor Financiero', usuario: 'finanzas.apc', password: 'apc.password.2025', departamento: 'Finanzas', nivel: UserRole.Finanzas, activo: true, email: 'finanzas@apc.com' },
          'trafico.apc': { nombre: 'Control de Tráfico', usuario: 'trafico.apc', password: 'apc.password.2025', departamento: 'Sistemas', nivel: UserRole.Trafico, activo: true, email: 'trafico@apc.com' }
        };
        await set(usersRef, usersToSeed);
        console.log('Seed de usuarios completado.');
      }
    } catch (e) {
      console.error("Error en seedUsers:", e);
    }
  };

  useEffect(() => {
    if (!db) {
      setLoading(false);
      return;
    }

    seedUsers();

    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let pLoaded = false, uLoaded = false, cLoaded = false;
    const check = () => { if (pLoaded && uLoaded && cLoaded) setLoading(false); };

    // Manejadores con fallback a array vacío para evitar errores de .map()
    const unsubP = onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      pLoaded = true; check();
    }, (err) => { console.error("Error P:", err); pLoaded = true; check(); });

    const unsubU = onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      uLoaded = true; check();
    }, (err) => { console.error("Error U:", err); uLoaded = true; check(); });

    const unsubC = onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      cLoaded = true; check();
    }, (err) => { console.error("Error C:", err); cLoaded = true; check(); });

    return () => { unsubP(); unsubU(); unsubC(); };
  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', nombre: 'Admin Bypass', usuario: 'admin', departamento: 'Sistemas', nivel: UserRole.Admin, activo: true };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }
    try {
      const userRef = ref(db, `users/${cleanUsername}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `Usuario no encontrado.` };
      const userData = snapshot.val();
      if (!userData.activo) return { success: false, error: 'Cuenta inactiva.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };
      const authUser: User = { ...userData, id: cleanUsername, usuario: cleanUsername };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const manageUser = async (userData: Partial<User>) => {
    if (!db || !userData.usuario) return;
    const cleanUsername = userData.usuario.toLowerCase().trim();
    await update(ref(db, `users/${cleanUsername}`), userData);
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    if (!db) return;
    await update(ref(db, `users/${userId}`), { activo: active });
  };

  const addClient = async (name: string, notes?: string) => {
    if (!db || !user) return;
    const newId = `CL-${Date.now()}`;
    await set(ref(db, `clients/${newId}`), { 
      id: newId, name, notes: notes || '', ownerId: user.id, createdAt: new Date().toISOString() 
    });
  };

  const addProject = async (projectData: Partial<Project>) => {
    if (!db || !user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    const newProject = {
      ...projectData,
      status: 'Borrador',
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `sys-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA',
        text: `PROYECTO CREADO`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }],
      asignaciones: [],
      pagado: false
    };
    await set(ref(db, `projects/${projectId}`), newProject);
  };

  const checkSLA = (project: Project) => {
    const lastUpdate = new Date(project.updatedAt || project.createdAt);
    const hours = (new Date().getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    return { isAlert: project.status !== 'Finalizado' && hours > 72, reason: hours > 72 ? 'Estancado > 72h' : undefined };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `sys-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA',
        text: `ESTADO: ${newStatus}. ${commentText}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }, ...(project.comentarios || [])]
    };
    if (newStatus === 'Finalizado') updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBrief = async (projectId: string, content: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      correccion_ok: approved,
      status: approved ? 'Finalizado' : 'Correcciones',
      updatedAt: new Date().toISOString(),
      comentarios: [{
        id: `qa-${Date.now()}`,
        authorId: user.id,
        authorName: 'SISTEMA (QA)',
        text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`,
        createdAt: new Date().toISOString(),
        isSystemEvent: true
      }, ...(project.comentarios || [])]
    };
    if (approved) updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { pagado, updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      status: 'En Proceso',
      updatedAt: new Date().toISOString()
    });
  };

  const reassignProjectAndFolder = async (projectId: string, companyName: string, newOwnerId: string) => {
    if (!db) return;
    const updates: any = {};
    updates[`projects/${projectId}/ownerId`] = newOwnerId;
    const client = clients.find(c => c.name === companyName);
    if (client) updates[`clients/${client.id}/ownerId`] = newOwnerId;
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject,
      manageUser, toggleUserStatus
    }}>
      {children}
    </ODTContext.Provider>
  );
};

