import { Icons } from './constants';
import { ref, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';

const Login: React.FC = () => {
  const { login } = useODT();
  const [u, setU] = useState('');
  const [p, setP] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Test de conexión inmediata al montar el Login
  useEffect(() => {
    if (db) {
      const testRef = ref(db, 'conexion_test');
      set(testRef, { 
        fecha: new Date().toISOString(),
        agente: navigator.userAgent 
      })
        .then(() => console.log('%c¡CONEXIÓN REAL ESTABLECIDA CON FIREBASE!', 'background: #22c55e; color: white; padding: 4px; font-weight: bold;'))
        .catch(err => {
          console.error('%cERROR REAL DE ESCRITURA:', 'background: #ef4444; color: white; padding: 4px; font-weight: bold;', err);
        });
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);
    const result = await login(u, p);
    if (!result.success) {
      const msg = result.error || 'Ocurrió un error inesperado al iniciar sesión.';
      setErrorMsg(msg);
      alert(`FALLO DE AUTENTICACIÓN: ${msg}`);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 p-6">
      <div className="w-full max-w-md animate-fadeIn">
        <div className="bg-white rounded-2xl shadow-2xl overflow-hidden">
