      const userData = snapshot.val();
      if (!userData.activo) return { success: false, error: 'Cuenta inactiva.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };
      const authUser: User = { ...userData, id: cleanUsername, usuario: cleanUsername };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const manageUser = async (userData: Partial<User>) => {
    if (!db || !userData.usuario) throw new Error("Datos de usuario incompletos.");

    const cleanUsername = userData.usuario.toLowerCase().trim();
    const newUser = {
      nombre: userData.nombre,
      usuario: cleanUsername,
      password: userData.password,
      nivel: userData.nivel,
      departamento: userData.departamento,
      activo: userData.activo ?? true,
      createdAt: userData.createdAt || new Date().toISOString()
    };

    console.log('%c>>> INTENTANDO GUARDAR USUARIO:', 'color: #3b82f6; font-weight: bold;', newUser);

    try {
      await set(ref(db, `users/${cleanUsername}`), newUser);
    } catch (error: any) {
      console.error("ERROR AL GUARDAR USUARIO:", error);
      throw error;
    }
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    if (!db) return;
    await update(ref(db, `users/${userId}`), { activo: active });
  };

  const addClient = async (name: string, notes?: string) => {
    if (!db) return;
    const clientId = `CL-${Date.now()}`;
    await set(ref(db, `clients/${clientId}`), { 
      id: clientId, name: name.trim(), notes: notes || '', ownerId: user?.id || 'bypass', createdAt: new Date().toISOString() 
    });
  };

  const addProject = async (projectData: Partial<Project>) => {
    if (!db || !user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    await set(ref(db, `projects/${projectId}`), {
      ...projectData,
      status: 'Borrador',
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `PROYECTO CREADO`, createdAt: new Date().toISOString(), isSystemEvent: true }],
      asignaciones: [],
      pagado: false
    });
  };

  const checkSLA = (project: Project) => {
    const lastUpdate = new Date(project.updatedAt || project.createdAt);
    const hours = (new Date().getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    return { isAlert: project.status !== 'Finalizado' && hours > 72, reason: hours > 72 ? 'Estancado > 72h' : undefined };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `ESTADO: ${newStatus}. ${commentText}`, createdAt: new Date().toISOString(), isSystemEvent: true }, ...(project.comentarios || [])]
    };
    if (newStatus === 'Finalizado') updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBrief = async (projectId: string, content: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      correccion_ok: approved,
      status: approved ? 'Finalizado' : 'Correcciones',
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `qa-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA (QA)', text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`, createdAt: new Date().toISOString(), isSystemEvent: true }, ...(project.comentarios || [])]
    };
    if (approved) updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { pagado, updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      status: 'En Proceso',
      updatedAt: new Date().toISOString()
    });
  };

  const reassignProjectAndFolder = async (projectId: string, companyName: string, newOwnerId: string) => {
    if (!db) return;
    const updates: any = {};
    updates[`projects/${projectId}/ownerId`] = newOwnerId;
    const client = clients.find(c => c.name === companyName);
    if (client) updates[`clients/${client.id}/ownerId`] = newOwnerId;
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject,
      manageUser, toggleUserStatus
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

export enum UserRole {
  Admin = 'Admin',
  Cuentas_Lider = 'Cuentas_Lider',
  Cuentas_Opera = 'Cuentas_Opera',
  Lider_Operativo = 'Lider_Operativo',
  Operativo = 'Operativo',
  Correccion = 'Correccion'
}

export interface User {
  id: string; // Key sanitizada en Firebase
  name: string;
  username: string;
  password?: string;
  department: string;
  role: UserRole;
  active: boolean;
  createdAt?: string;
}

export interface ProjectComment {
  id: string;
  authorId: string;
  authorName: string;
  text: string;
  createdAt: string;
  isSystemEvent?: boolean;
}

export interface ProjectAssignment {
  area: string;
  usuarioId: string;
  status: 'pendiente' | 'en_progreso' | 'completado';
}

export interface Project {
  id: string;
  clientId: string;
  empresa: string;
  marca: string;
  producto: string;
  etapa_actual: string;
  category: string;
  subCategory: string;
  referenceLinks: string[];
  status: 'Borrador' | 'En Proceso' | 'Correcciones' | 'QA' | 'Finalizado' | 'Cancelado';
  correccion_ok: boolean;
  areas_seleccionadas: string[];
  asignaciones: ProjectAssignment[];
  tracking: any[];
  comentarios: ProjectComment[];
  monto_proyectado: number;
  brief: string;
  facturado?: boolean;
  pagado?: boolean;
  justificacion_no_facturado?: string;
  ownerId?: string;
  createdAt: string;
  updatedAt: string;
  fecha_finalizado?: string;
}

export interface Client {
  id: string;
  name: string;
  notes?: string;
  ownerId: string;
  createdAt: string;
}

export type ViewState = 
  | 'login' 
  | 'dashboard' 
  | 'leader-dashboard'
  | 'my-projects' 
  | 'clients' 
  | 'users' 
  | 'qa-box' 
  | 'finances' 
  | 'project-detail';

export interface LoginResult {
  success: boolean;
  error?: string;
}

export interface ODTContextType {
  user: User | null;
  projects: Project[];
  clients: Client[];
  users: User[];
  loading: boolean;
  login: (username: string, pass: string) => Promise<LoginResult>;
  logout: () => void;
  updateProjectStatus: (projectId: string, newStatus: Project['status'], comment: string) => Promise<void>;
  updateBrief: (projectId: string, content: string) => Promise<void>;
  processQA: (projectId: string, approved: boolean, feedback: string) => Promise<void>;
  updateBilling: (projectId: string, facturado: boolean, justification?: string) => Promise<void>;
  updatePaymentStatus: (projectId: string, pagado: boolean) => Promise<void>;
  checkSLA: (project: Project) => { isAlert: boolean; reason?: string };
  delegateProject: (projectId: string, area: string, userId: string) => Promise<void>;
  reassignProjectAndFolder: (projectId: string, companyName: string, newOwnerId: string) => Promise<void>;
  addClient: (name: string, notes?: string) => Promise<void>;
  addProject: (project: Partial<Project>) => Promise<void>;
  manageUser: (userData: Partial<User>) => Promise<void>;
  toggleUserStatus: (userId: string, active: boolean) => Promise<void>;
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';
import { Project, User, ODTContextType, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

// Función auxiliar para limpiar llaves de Firebase (prohíbe . # $ [ ])
const escapeFirebaseKey = (key: string) => key.toLowerCase().trim().replace(/[\.\#\$\/\[\]]/g, '_');

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión", e);
      }
    }
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (loading) setLoading(false);
    }, 4000);
    return () => clearTimeout(timer);
  }, [loading]);

  useEffect(() => {
    if (!db) {
      setLoading(false);
      return;
    }

    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    let pLoaded = false, uLoaded = false, cLoaded = false;
    const check = () => { if (pLoaded && uLoaded && cLoaded) setLoading(false); };

    onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      pLoaded = true; check();
    }, () => { pLoaded = true; check(); });

    onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      uLoaded = true; check();
    }, () => { uLoaded = true; check(); });

    onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      cLoaded = true; check();
    }, () => { cLoaded = true; check(); });

  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    const dbKey = escapeFirebaseKey(cleanUsername);

    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', name: 'Admin Bypass', username: 'admin', department: 'Sistemas', role: UserRole.Admin, active: true };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }

    try {
      const userRef = ref(db, `users/${dbKey}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `Usuario no encontrado.` };
      const userData = snapshot.val();
      if (!userData.active) return { success: false, error: 'Cuenta inactiva.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };

      const authUser: User = { ...userData, id: dbKey };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const manageUser = async (userData: Partial<User>) => {
    if (!db || !userData.username) throw new Error("Datos incompletos.");

    const dbKey = escapeFirebaseKey(userData.username);
    const newUser = {
      name: userData.name,
      username: userData.username.toLowerCase().trim(),
      password: userData.password,
      role: userData.role,
      department: userData.department,
      active: userData.active ?? true,
      createdAt: userData.createdAt || new Date().toISOString()
    };

    console.log('%c[FIREBASE] Objeto Usuario:', 'color: #3b82f6; font-weight: bold;', newUser);

    try {
      await set(ref(db, `users/${dbKey}`), newUser);
    } catch (error: any) {
      console.error("ERROR AL GUARDAR USUARIO:", error);
      alert(`FALLO TÉCNICO:\n\n${error.message}`);
      throw error;
    }
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    if (!db) return;
    await update(ref(db, `users/${userId}`), { active });
  };

  const addClient = async (name: string, notes?: string) => {
    if (!db) return;
    const clientId = `CL-${Date.now()}`;
    await set(ref(db, `clients/${clientId}`), { 
      id: clientId, name: name.trim(), notes: notes || '', ownerId: user?.id || 'system', createdAt: new Date().toISOString() 
    });
  };

  const addProject = async (projectData: Partial<Project>) => {
    if (!db || !user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    await set(ref(db, `projects/${projectId}`), {
      ...projectData,
      status: 'Borrador',
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `PROYECTO CREADO`, createdAt: new Date().toISOString(), isSystemEvent: true }],
      asignaciones: [],
      pagado: false
    });
  };

  const checkSLA = (project: Project) => {
    const lastUpdate = new Date(project.updatedAt || project.createdAt);
    const hours = (new Date().getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    return { isAlert: project.status !== 'Finalizado' && hours > 72, reason: hours > 72 ? 'Estancado > 72h' : undefined };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `ESTADO: ${newStatus}. ${commentText}`, createdAt: new Date().toISOString(), isSystemEvent: true }, ...(project.comentarios || [])]
    };
    if (newStatus === 'Finalizado') updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBrief = async (projectId: string, content: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      correccion_ok: approved,
      status: approved ? 'Finalizado' : 'Correcciones',
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `qa-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA (QA)', text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`, createdAt: new Date().toISOString(), isSystemEvent: true }, ...(project.comentarios || [])]
    };
    if (approved) updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { pagado, updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      status: 'En Proceso',
      updatedAt: new Date().toISOString()
    });
  };

  const reassignProjectAndFolder = async (projectId: string, companyName: string, newOwnerId: string) => {
    if (!db) return;
    const updates: any = {};
    updates[`projects/${projectId}/ownerId`] = newOwnerId;
    const client = clients.find(c => c.name === companyName);
    if (client) updates[`clients/${client.id}/ownerId`] = newOwnerId;
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject,
      manageUser, toggleUserStatus
    }}>
      {children}
    </ODTContext.Provider>
  );
};

