          <p className="text-slate-600 text-[8px] mt-4 font-bold tracking-widest uppercase">Protocolo ISO 9001:2015 en curso</p>
        </div>
      </div>
    );
  }

  const renderMyInbox = () => {
    // // Fixed: Property 'nivel' does not exist on type 'User'. Using 'role' instead.
    const isLeadOrAdmin = user?.role === UserRole.Admin || user?.role.endsWith('_Lider');

    const myProjects = projects?.filter(p => {
      if (isLeadOrAdmin) return p.ownerId === user?.id || p.asignaciones?.some(a => a.usuarioId === user?.id);
      return p.asignaciones?.some(a => a.usuarioId === user?.id);
    }) || [];

    return (
      <div className="space-y-6">
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-black">Mi Bandeja Operativa</h1>
