             <p className="text-slate-400 italic text-center py-10">No tiene tareas pendientes de ejecución.</p>
           ) : (
             <ProjectTable projects={myProjects} onView={setSelectedProject} checkSLA={checkSLA} />
           )}
        </div>
      </div>
    );
  };

  const renderQABox = () => {
    const qaProjects = projects?.filter(p => p?.status === 'QA') || [];
    return (
      <div className="space-y-6">
        <header><h1 className="text-3xl font-black">Caja de Corrección (QA)</h1></header>
        {qaProjects.length === 0 ? (
           <div className="p-12 text-center bg-white rounded-2xl border border-dashed text-slate-400 italic">No hay proyectos pendientes de QA.</div>
        ) : (
           <ProjectTable projects={qaProjects} onView={setSelectedProject} checkSLA={checkSLA} />
        )}
      </div>
    );
  };

  const renderFinances = () => {
    const now = new Date();
    return (
      <div className="space-y-6">
        <header>
          <h1 className="text-3xl font-black text-slate-900">Gestión de Cobranza</h1>
          <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">Supervisión de Facturación y Pagos</p>
        </header>
        <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
              <tr>
                <th className="px-6 py-4">ODT</th>
                <th className="px-6 py-4">Cliente / Entrega</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4 text-center">Fact.</th>
                <th className="px-6 py-4 text-center">Pagado</th>
                <th className="px-6 py-4">Alerta de Riesgo</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {projects?.filter(p => p.status === 'Finalizado' || p.monto_proyectado > 0).map(p => {
                const finishedAt = p.fecha_finalizado ? new Date(p.fecha_finalizado) : null;
                const daysDiff = finishedAt ? Math.floor((now.getTime() - finishedAt.getTime()) / (1000 * 60 * 60 * 24)) : 0;
                const isLatePayment = p.status === 'Finalizado' && daysDiff > 3 && !p.pagado;

                return (
                  <tr key={p?.id} className={`hover:bg-slate-50/50 transition-colors ${isLatePayment ? 'bg-rose-50 animate-pulse border-l-4 border-l-rose-500' : ''}`}>
                    <td className="px-6 py-4 font-mono font-black text-blue-600">{p?.id}</td>
                    <td className="px-6 py-4">
                      <div className="font-bold text-slate-800">{p?.empresa}</div>
                      <div className="text-[10px] text-slate-400 font-bold uppercase">Finalizado: {finishedAt ? finishedAt.toLocaleDateString() : 'N/A'}</div>
                    </td>
                    <td className="px-6 py-4 font-black text-slate-900">${p?.monto_proyectado?.toLocaleString()}</td>
                    <td className="px-6 py-4 text-center">
                      <input type="checkbox" checked={p?.facturado} onChange={e => updateBilling(p?.id, e.target.checked)} className="w-5 h-5 accent-blue-600 cursor-pointer" />
                    </td>
                    <td className="px-6 py-4 text-center">
                      <input type="checkbox" checked={p?.pagado} onChange={e => updatePaymentStatus(p?.id, e.target.checked)} className="w-5 h-5 accent-emerald-600 cursor-pointer" />
                    </td>
                    <td className="px-6 py-4">
                      {isLatePayment ? (
                        <span className="bg-rose-600 text-white text-[9px] font-black px-2 py-1 rounded flex items-center gap-1 w-fit">
                          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>
                          RIESGO DE COBRO (+3 DÍAS)
                        </span>
                      ) : (
                        <span className="text-[9px] text-slate-400 font-bold uppercase">Sin Alertas</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  const renderView = (view: ViewState) => {
    if (selectedProject) return <ProjectDetail project={selectedProject} onBack={() => setSelectedProject(null)} />;
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'clients': return <ClientsView />;
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      case 'users': return <UsersView />;
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

