        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Trazabilidad de Etapas</h3>
        <div className="relative flex justify-between items-center">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-100 -translate-y-1/2 -z-10"></div>
          {roadmapStages.map((stage, idx) => {
            const currentIdx = getCurrentStageIndex();
            const isActive = idx === currentIdx;
            const isCompleted = idx < currentIdx;
            return (
              <div key={stage} className="flex flex-col items-center gap-2 bg-white px-2">
                <div className={`w-8 h-8 rounded-full border-4 flex items-center justify-center transition-all ${
                  isActive ? 'bg-blue-600 border-blue-200 shadow-lg scale-110' : 
                  isCompleted ? 'bg-emerald-500 border-emerald-100' : 'bg-slate-100 border-white'
                }`}>
                  {isCompleted ? (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                  ) : <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white' : 'bg-slate-300'}`}></div>}
                </div>
                <span className={`text-[9px] font-black uppercase tracking-tighter ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>{stage}</span>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
