import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';
import { Project, User, ODTContextType, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

const escapeFirebaseKey = (key: string) => key.toLowerCase().trim().replace(/[\.\#\$\/\[\]]/g, '_');

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión", e);
      }
    }
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (loading) setLoading(false);
    }, 4000);
    return () => clearTimeout(timer);
  }, [loading]);

  useEffect(() => {
    if (!db) {
      setLoading(false);
      return;
    }

    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      if (users.length > 0 && clients.length > 0) setLoading(false);
    });

    onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      if (projects.length > 0 && clients.length > 0) setLoading(false);
    });

    onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      if (projects.length > 0 && users.length > 0) setLoading(false);
    });

  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    const dbKey = escapeFirebaseKey(cleanUsername);

    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', name: 'Admin Bypass', username: 'admin', department: 'Sistemas', role: UserRole.Admin, active: true };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }

    try {
      const userRef = ref(db, `users/${dbKey}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `Usuario no encontrado.` };
      const userData = snapshot.val();
      if (!userData.active) return { success: false, error: 'Cuenta inactiva.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };

      const authUser: User = { ...userData, id: dbKey };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const manageUser = async (userData: Partial<User>) => {
    if (!db || !userData.username) throw new Error("Datos incompletos.");
    const dbKey = escapeFirebaseKey(userData.username);
    const newUser = {
      name: userData.name,
      username: userData.username.toLowerCase().trim(),
      password: userData.password,
      role: userData.role,
      department: userData.department,
      active: userData.active ?? true,
      createdAt: userData.createdAt || new Date().toISOString()
    };
    try {
      await set(ref(db, `users/${dbKey}`), newUser);
    } catch (error: any) {
      alert(`FALLO TÉCNICO:\n\n${error.message}`);
      throw error;
    }
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    if (!db) return;
    await update(ref(db, `users/${userId}`), { active });
  };

  const addClient = async (name: string, notes?: string) => {
    if (!db) return;
    const clientId = `CL-${Date.now()}`;
    await set(ref(db, `clients/${clientId}`), { 
      id: clientId, name: name.trim(), notes: notes || '', ownerId: user?.id || 'system', createdAt: new Date().toISOString() 
    });
  };

  const addProject = async (projectData: Partial<Project>) => {
    if (!db || !user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    await set(ref(db, `projects/${projectId}`), {
      ...projectData,
      status: 'Borrador',
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `PROYECTO CREADO`, createdAt: new Date().toISOString(), isSystemEvent: true }],
      asignaciones: [],
      pagado: false
    });
  };

  const checkSLA = (project: Project) => {
    const lastUpdate = new Date(project.updatedAt || project.createdAt);
    const hours = (new Date().getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    return { isAlert: project.status !== 'Finalizado' && hours > 72, reason: hours > 72 ? 'Estancado > 72h' : undefined };
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      status: newStatus,
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `ESTADO: ${newStatus}. ${commentText}`, createdAt: new Date().toISOString(), isSystemEvent: true }, ...(project.comentarios || [])]
    };
    if (newStatus === 'Finalizado') updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBrief = async (projectId: string, content: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const updates: any = {
      correccion_ok: approved,
      status: approved ? 'Finalizado' : 'Correcciones',
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `qa-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA (QA)', text: `QA: ${approved ? 'APROBADO' : 'RECHAZADO'}. ${feedback}`, createdAt: new Date().toISOString(), isSystemEvent: true }, ...(project.comentarios || [])]
    };
    if (approved) updates.fecha_finalizado = new Date().toISOString();
    await update(ref(db, `projects/${projectId}`), updates);
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { pagado, updatedAt: new Date().toISOString() });
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), {
      asignaciones: newAsignaciones,
      status: 'En Proceso',
      updatedAt: new Date().toISOString()
    });
  };

  const reassignProjectAndFolder = async (projectId: string, clientId: string, newOwnerId: string, portfolio: boolean = false) => {
    if (!db || !user) return;
    const updates: any = {};
    const timestamp = new Date().toISOString();

    if (portfolio) {
      // Reasignación masiva (Cartera Completa)
      updates[`clients/${clientId}/ownerId`] = newOwnerId;
      projects.filter(p => p.clientId === clientId).forEach(p => {
        updates[`projects/${p.id}/ownerId`] = newOwnerId;
        updates[`projects/${p.id}/updatedAt`] = timestamp;
      });
      console.log(`[FIREBASE] Transfiriendo Cartera Completa del cliente ${clientId} a ${newOwnerId}`);
    } else {
      // Reasignación individual
      updates[`projects/${projectId}/ownerId`] = newOwnerId;
      updates[`projects/${projectId}/updatedAt`] = timestamp;
      console.log(`[FIREBASE] Reasignando ODT ${projectId} a ${newOwnerId}`);
    }

    try {
      await update(ref(db), updates);
    } catch (error: any) {
      console.error("Error en transferencia:", error);
      alert(`Error en transferencia ISO: ${error.message}`);
    }
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject,
      manageUser, toggleUserStatus
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState, useEffect } from 'react';
import { useODT } from './ODTContext';
import { UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ref, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';

const Login: React.FC = () => {
  const { login } = useODT();
  const [u, setU] = useState('');
  const [p, setP] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  useEffect(() => {
    if (db) {
      const testRef = ref(db, 'conexion_test');
      set(testRef, { fecha: new Date().toISOString() }).catch(() => {});
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);
    const result = await login(u, p);
    if (!result.success) {
      setErrorMsg(result.error || 'Error al iniciar sesión.');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 p-6">
      <div className="w-full max-w-md animate-fadeIn">
        <div className="bg-white rounded-2xl shadow-2xl overflow-hidden">
          <div className="bg-blue-600 p-8 text-center">
            <div className="w-16 h-16 bg-white/20 rounded-2xl mx-auto flex items-center justify-center text-white text-3xl font-black mb-4">ISO</div>
            <h1 className="text-white text-2xl font-bold tracking-tight">ODT Manager</h1>
            <p className="text-blue-100 text-sm mt-1">Gestión Normativa APC</p>
          </div>
          <form className="p-8 space-y-6" onSubmit={handleSubmit}>
            {errorMsg && (
              <div className="p-3 bg-rose-50 text-rose-600 text-xs font-bold rounded-lg border border-rose-100 flex items-center gap-2">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                {errorMsg}
              </div>
            )}
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Usuario</label>
              <input value={u} onChange={e => setU(e.target.value)} type="text" className="w-full px-4 py-3 bg-slate-50 border rounded-xl outline-none transition-all font-medium" placeholder="ID de Usuario" required />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Contraseña</label>
              <input value={p} onChange={e => setP(e.target.value)} type="password" className="w-full px-4 py-3 bg-slate-50 border rounded-xl outline-none transition-all font-medium" placeholder="••••••••" required />
            </div>
            <button type="submit" className="w-full py-4 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-xl">
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export const AppRouter: React.FC<{ renderView: (view: ViewState) => React.ReactNode }> = ({ renderView }) => {
  const { user, logout } = useODT();
  const [view, setView] = useState<ViewState>('dashboard');

  useEffect(() => {
    if (!user) return;
    if (user.role === UserRole.Correccion) setView('qa-box');
    else if (user.department === 'Finanzas') setView('finances');
    else if (user.role === UserRole.Lider_Operativo) setView('leader-dashboard');
    else if (user.role === UserRole.Operativo) setView('my-projects');
    else if (user.role === UserRole.Cuentas_Opera || user.role === UserRole.Cuentas_Lider) setView('clients');
    else setView('dashboard');
  }, [user]);

  if (!user) return <Login />;

  const canSee = (roles: UserRole[]) => roles.includes(user.role) || user.role === UserRole.Admin;

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 fixed h-full p-6 flex flex-col gap-8 shadow-2xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl">ISO</div>
          <h2 className="text-white font-bold tracking-tighter">ODT Manager</h2>
        </div>
        <nav className="flex flex-col gap-2 flex-1">
          {canSee([UserRole.Admin, UserRole.Cuentas_Lider]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Adm." active={view === 'dashboard'} onClick={() => setView('dashboard')} />}
          {canSee([UserRole.Lider_Operativo]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Lider" active={view === 'leader-dashboard'} onClick={() => setView('leader-dashboard')} />}
          {canSee([UserRole.Cuentas_Opera, UserRole.Cuentas_Lider, UserRole.Admin]) && <SidebarItem icon={<Icons.Clients />} label="Clientes / Archivo" active={view === 'clients'} onClick={() => setView('clients')} />}
          {canSee([UserRole.Operativo, UserRole.Lider_Operativo, UserRole.Cuentas_Lider, UserRole.Admin]) && <SidebarItem icon={<Icons.Project />} label="Bandeja Operativa" active={view === 'my-projects'} onClick={() => setView('my-projects')} />}
          {canSee([UserRole.Correccion, UserRole.Admin, UserRole.Cuentas_Lider]) && <SidebarItem icon={<Icons.Ai />} label="Caja de QA" active={view === 'qa-box'} onClick={() => setView('qa-box')} />}
          {user.department === 'Finanzas' || user.role === UserRole.Admin || user.role === UserRole.Cuentas_Lider ? <SidebarItem icon={<Icons.Clients />} label="Facturación" active={view === 'finances'} onClick={() => setView('finances')} /> : null}
          {user.role === UserRole.Admin && <SidebarItem icon={<Icons.Users />} label="Usuarios" active={view === 'users'} onClick={() => setView('users')} />}
        </nav>
        <div className="p-4 bg-slate-800/50 rounded-xl border border-slate-700/50">
          <p className="text-xs font-bold text-white truncate">{user.name}</p>
          <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{user.role}</p>
          <button onClick={logout} className="w-full mt-4 py-2 text-[10px] uppercase font-bold text-slate-400 hover:text-white border border-slate-700 rounded-md transition-colors">Salir</button>
        </div>
      </aside>
      <main className="flex-1 ml-64 p-8">{renderView(view)}</main>
    </div>
  );
};

const SidebarItem: React.FC<{ icon: any, label: string, active: boolean, onClick: () => void }> = ({ icon: Icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${active ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
    {typeof Icon === 'function' ? <Icon /> : Icon} <span className="font-medium text-sm">{label}</span>
  </button>
);

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ODTProvider, useODT } from './ODTContext';
import { AppRouter } from './AppRouter';
import AdminDashboard from './AdminDashboard';
import LeaderDashboard from './LeaderDashboard';
import ProjectDetail from './ProjectDetail';
import ClientsView from './ClientsView';
import UsersView from './UsersView';
import { db } from './firebase';

const AppContent: React.FC = () => {
  const { user, projects, checkSLA, updateBilling, updatePaymentStatus, loading } = useODT();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  if (!db || loading) {
    return (
      <div className="bg-[#0f172a] h-screen w-screen flex flex-col items-center justify-center gap-6">
        <div className="w-16 h-16 border-4 border-t-blue-500 border-slate-700 rounded-full animate-spin"></div>
        <div className="text-center animate-pulse">
          <h1 className="text-white font-black text-xl tracking-[0.3em] uppercase">Iniciando Servicios APC...</h1>
          <p className="text-slate-500 text-xs mt-2 font-bold tracking-widest uppercase">Estableciendo conexión con Realtime Database</p>
        </div>
      </div>
    );
  }

  const renderMyInbox = () => {
    // Si es Admin o Líder de Cuentas, ve TODO el universo de proyectos
    const isGlobalLead = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;

    const myProjects = projects?.filter(p => {
      if (isGlobalLead) return true; // Ver todo
      const isAreaLead = user?.role.endsWith('_Lider');
      if (isAreaLead) return p.ownerId === user?.id || p.asignaciones?.some(a => a.usuarioId === user?.id);
      return p.asignaciones?.some(a => a.usuarioId === user?.id);
    }) || [];

    return (
      <div className="space-y-6">
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-black">Bandeja Operativa</h1>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
              {isGlobalLead ? 'VISTA GLOBAL DE CARTERA APC' : 'Tareas técnicas asignadas a su perfil'}
            </p>
          </div>
        </header>
        <div className="bg-white p-6 rounded-xl border-2 border-dashed border-slate-200">
           {myProjects.length === 0 ? (
             <p className="text-slate-400 italic text-center py-10">No hay tareas pendientes en esta vista.</p>
           ) : (
             <ProjectTable projects={myProjects} onView={setSelectedProject} checkSLA={checkSLA} />
           )}
        </div>
      </div>
    );
  };

  const renderQABox = () => {
    const qaProjects = projects?.filter(p => p?.status === 'QA') || [];
    return (
      <div className="space-y-6">
        <header><h1 className="text-3xl font-black">Caja de Corrección (QA)</h1></header>
        {qaProjects.length === 0 ? (
           <div className="p-12 text-center bg-white rounded-2xl border border-dashed text-slate-400 italic">No hay proyectos pendientes de QA.</div>
        ) : (
           <ProjectTable projects={qaProjects} onView={setSelectedProject} checkSLA={checkSLA} />
        )}
      </div>
    );
  };

  const renderFinances = () => {
    const now = new Date();
    return (
      <div className="space-y-6">
        <header>
          <h1 className="text-3xl font-black text-slate-900">Gestión de Cobranza</h1>
          <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">Supervisión de Facturación y Pagos</p>
        </header>
        <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
              <tr>
                <th className="px-6 py-4">ODT</th>
                <th className="px-6 py-4">Cliente / Entrega</th>
                <th className="px-6 py-4">Monto</th>
                <th className="px-6 py-4 text-center">Fact.</th>
                <th className="px-6 py-4 text-center">Pagado</th>
                <th className="px-6 py-4">Alerta de Riesgo</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {projects?.filter(p => p.status === 'Finalizado' || p.monto_proyectado > 0).map(p => {
                const finishedAt = p.fecha_finalizado ? new Date(p.fecha_finalizado) : null;
                const daysDiff = finishedAt ? Math.floor((now.getTime() - finishedAt.getTime()) / (1000 * 60 * 60 * 24)) : 0;
                const isLatePayment = p.status === 'Finalizado' && daysDiff > 3 && !p.pagado;

                return (
                  <tr key={p?.id} className={`hover:bg-slate-50/50 transition-colors ${isLatePayment ? 'bg-rose-50 animate-pulse border-l-4 border-l-rose-500' : ''}`}>
                    <td className="px-6 py-4 font-mono font-black text-blue-600">{p?.id}</td>
                    <td className="px-6 py-4">
                      <div className="font-bold text-slate-800">{p?.empresa}</div>
                      <div className="text-[10px] text-slate-400 font-bold uppercase">Finalizado: {finishedAt ? finishedAt.toLocaleDateString() : 'N/A'}</div>
                    </td>
                    <td className="px-6 py-4 font-black text-slate-900">${p?.monto_proyectado?.toLocaleString()}</td>
                    <td className="px-6 py-4 text-center">
                      <input type="checkbox" checked={p?.facturado} onChange={e => updateBilling(p?.id, e.target.checked)} className="w-5 h-5 accent-blue-600 cursor-pointer" />
                    </td>
                    <td className="px-6 py-4 text-center">
                      <input type="checkbox" checked={p?.pagado} onChange={e => updatePaymentStatus(p?.id, e.target.checked)} className="w-5 h-5 accent-emerald-600 cursor-pointer" />
                    </td>
                    <td className="px-6 py-4">
                      {isLatePayment ? (
                        <span className="bg-rose-600 text-white text-[9px] font-black px-2 py-1 rounded flex items-center gap-1 w-fit">
                          <Icons.Plus /> RIESGO DE COBRO (+3 DÍAS)
                        </span>
                      ) : (
                        <span className="text-[9px] text-slate-400 font-bold uppercase">Sin Alertas</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    );
  };

  const renderView = (view: ViewState) => {
    if (selectedProject) return <ProjectDetail project={selectedProject} onBack={() => setSelectedProject(null)} />;
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'clients': return <ClientsView />;
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      case 'users': return <UsersView />;
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

const ProjectTable = ({ projects, onView, checkSLA }: any) => (
  <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
    <table className="w-full text-sm text-left">
      <thead className="bg-slate-50 text-slate-500 font-black text-[10px] uppercase tracking-widest">
        <tr>
          <th className="px-6 py-5">ODT ID</th>
          <th className="px-6 py-5">Proyecto / Cliente</th>
          <th className="px-6 py-5">Status</th>
          <th className="px-6 py-5">SLA</th>
          <th className="px-6 py-5">Acciones</th>
        </tr>
      </thead>
      <tbody className="divide-y divide-slate-100">
        {projects?.map((p: Project) => {
          const sla = checkSLA(p);
          return (
            <tr key={p?.id} className={`hover:bg-slate-50/50 transition-all ${sla?.isAlert ? 'bg-pink-50/20' : ''}`}>
              <td className="px-6 py-4 font-mono font-black text-blue-600 text-xs">{p?.id}</td>
              <td className="px-6 py-4">
                <div className="font-bold text-slate-800">{p?.empresa}</div>
                <div className="text-[10px] text-slate-400 font-medium uppercase">{p?.producto}</div>
              </td>
              <td className="px-6 py-4">
                <span className={`px-2.5 py-1 rounded text-[10px] font-black uppercase tracking-tighter ${p?.status === 'QA' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-600'}`}>
                  {p?.status}
                </span>
              </td>
              <td className="px-6 py-4">
                {sla?.isAlert ? (
                  <span className="text-pink-600 text-[10px] font-black animate-pulse flex items-center gap-1">
                    <Icons.Plus /> CRÍTICO
                  </span>
                ) : (
                  <span className="text-emerald-500 text-[10px] font-bold uppercase tracking-widest">OK</span>
                )}
              </td>
              <td className="px-6 py-4">
                <button onClick={() => onView(p)} className="text-blue-600 font-black hover:text-blue-800 transition-colors text-xs border-b-2 border-transparent hover:border-blue-800 pb-0.5">DETALLE</button>
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  </div>
);

const App: React.FC = () => (
  <ODTProvider>
    <AppContent />
  </ODTProvider>
);

export default App;

import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, users, checkSLA, updateProjectStatus, updateBrief, processQA, reassignProjectAndFolder } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [auditResult, setAuditResult] = useState<any>(null);
  const [isAuditing, setIsAuditing] = useState(false);
  const [showReassignModal, setShowReassignModal] = useState(false);
  const [targetOwner, setTargetOwner] = useState('');

  const sla = checkSLA(project);

  const handleSaveBrief = () => {
    updateBrief(project.id, briefContent);
    alert("Brief Maestro guardado exitosamente.");
  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  const handleReassign = async (portfolio: boolean) => {
    if (!targetOwner) return;
    await reassignProjectAndFolder(project.id, project.clientId, targetOwner, portfolio);
    setShowReassignModal(false);
    alert(portfolio ? "Cartera completa transferida con éxito." : "ODT reasignada correctamente.");
  };

  const isQAUser = user?.role === UserRole.Correccion;
  const isAdminOrLead = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;

  const accountsUsers = useMemo(() => 
    users.filter(u => u.role === UserRole.Cuentas_Opera || u.role === UserRole.Cuentas_Lider),
    [users]
  );

  const roadmapStages = ['Briefing', 'Producción', 'QA / Revisión', 'Facturación', 'Finalizado'];
  const getCurrentStageIndex = () => {
    if (project.status === 'Finalizado') return 4;
    if (project.status === 'QA') return 2;
    if (project.status === 'Borrador') return 0;
    return 1;
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-20">
      <header className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500">
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
          </button>
          <div>
            <h1 className="text-2xl font-black text-slate-900">{project.id}</h1>
            <p className="text-sm text-slate-500 font-medium">{project.empresa} - {project.producto}</p>
          </div>
        </div>
        {isAdminOrLead && (
          <button 
            onClick={() => setShowReassignModal(true)}
            className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all flex items-center gap-2"
          >
            <Icons.Users /> Reasignar Propietario
          </button>
        )}
      </header>

      <div className="bg-white p-6 rounded-2xl border shadow-sm">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Trazabilidad de Etapas</h3>
        <div className="relative flex justify-between items-center">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-100 -translate-y-1/2 -z-10"></div>
          {roadmapStages.map((stage, idx) => {
            const currentIdx = getCurrentStageIndex();
            const isActive = idx === currentIdx;
            const isCompleted = idx < currentIdx;
            return (
              <div key={stage} className="flex flex-col items-center gap-2 bg-white px-2">
                <div className={`w-8 h-8 rounded-full border-4 flex items-center justify-center transition-all ${
                  isActive ? 'bg-blue-600 border-blue-200 shadow-lg scale-110' : 
                  isCompleted ? 'bg-emerald-500 border-emerald-100' : 'bg-slate-100 border-white'
                }`}>
                  {isCompleted ? (
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                  ) : <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white' : 'bg-slate-300'}`}></div>}
                </div>
                <span className={`text-[9px] font-black uppercase tracking-tighter ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>{stage}</span>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Icons.Project /> Brief Maestro
              </h3>
              <button onClick={handleSaveBrief} className="px-4 py-2 bg-blue-600 text-white text-xs font-bold rounded-lg hover:bg-blue-700 transition-all">
                GUARDAR BRIEF
              </button>
            </div>
            <ReactQuill 
              theme="snow" 
              value={briefContent} 
              onChange={(content) => setBriefContent(typeof content === 'string' ? content : '')} 
            />
          </div>

          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs ISO 9001</h3>
            <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
              {project.comentarios.map(c => (
                <div key={c.id} className={`p-4 rounded-xl text-xs border ${c.isSystemEvent ? 'bg-slate-50 border-dashed border-slate-200' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between mb-2">
                    <span className="font-black uppercase text-[9px] text-blue-500">{c.authorName}</span>
                    <span className="text-slate-400 font-mono text-[9px]">{new Date(c.createdAt).toLocaleString()}</span>
                  </div>
                  <p className="text-slate-700 font-medium">{c.text}</p>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {(isQAUser || (isAdminOrLead && project.status === 'QA')) && (
            <div className="bg-white p-6 rounded-2xl border-2 border-amber-200 shadow-xl space-y-4">
              <h3 className="font-black text-amber-600 text-xs uppercase tracking-widest flex items-center gap-2">
                <Icons.Ai /> Caja de Corrección (QA)
              </h3>
              <p className="text-xs text-slate-500 font-medium leading-tight italic">
                "Ninguna ODT debe avanzar a etapa final sin auditoría técnica de corrección."
              </p>
              <textarea 
                placeholder="Indique hallazgos o feedback detallado..."
                className="w-full bg-slate-50 border rounded-xl p-3 text-xs outline-none focus:ring-2 focus:ring-amber-500 h-24 font-medium"
                value={qaFeedback}
                onChange={(e) => setQaFeedback(e.target.value)}
              />
              <div className="grid grid-cols-2 gap-3">
                <button 
                  disabled={!qaFeedback}
                  onClick={() => { processQA(project.id, true, qaFeedback); setQaFeedback(''); }}
                  className="py-3 bg-emerald-600 text-white font-black text-xs rounded-xl hover:bg-emerald-700 disabled:opacity-50 transition-all shadow-lg shadow-emerald-200"
                >DAR OK (APROBAR)</button>
                <button 
                  disabled={!qaFeedback}
                  onClick={() => { processQA(project.id, false, qaFeedback); setQaFeedback(''); }}
                  className="py-3 bg-rose-600 text-white font-black text-xs rounded-xl hover:bg-rose-700 disabled:opacity-50 transition-all shadow-lg shadow-rose-200"
                >RECHAZAR</button>
              </div>
            </div>
          )}

          {!isQAUser && (
