import React, { useState, useMemo } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Client } from './types';
import { Icons } from './constants';
import NewODTForm from './NewODTForm';

const ClientsView: React.FC = () => {
  const { user, clients, projects, users, addClient, reassignProjectAndFolder } = useODT();
  const [isCreatingClient, setIsCreatingClient] = useState(false);
  const [newClientName, setNewClientName] = useState('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [transferClient, setTransferClient] = useState<Client | null>(null);
  const [targetOwner, setTargetOwner] = useState('');

  const canCreateClient = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider || user?.role === UserRole.Cuentas_Opera;
  const isLeader = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;

  const accountsUsers = useMemo(() => 
    users.filter(u => u.role === UserRole.Cuentas_Opera || u.role === UserRole.Cuentas_Lider),
    [users]
  );

  const handleCreateClient = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClientName) return;
    await addClient(newClientName);
    setNewClientName('');
    setIsCreatingClient(false);
    alert(`Carpeta "${newClientName}" creada correctamente.`);
  };

  const handleQuickTransfer = async () => {
    if (!transferClient || !targetOwner) return;
    if (confirm(`¿Transferir toda la cartera de "${transferClient.name}" a este nuevo ejecutivo?`)) {
      await reassignProjectAndFolder('', transferClient.id, targetOwner, true);
      setTransferClient(null);
      alert("Cartera transferida exitosamente.");
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Archivo de Clientes</h1>
          <p className="text-slate-500 font-medium text-sm flex items-center gap-2">
            <span className="w-2 h-2 bg-blue-500 rounded-full"></span>
            Gestión de Carpetas Maestras ISO 9001
          </p>
        </div>

        {canCreateClient && (
          <button 
            onClick={() => setIsCreatingClient(true)}
            className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white font-black text-xs rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-200"
          >
            <Icons.Plus /> NUEVA CARPETA DE CLIENTE
          </button>
        )}
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {clients.map(client => {
          const clientODTs = projects.filter(p => p.clientId === client.id);
          const activeODTs = clientODTs.filter(p => p.status !== 'Finalizado' && p.status !== 'Cancelado').length;
          const owner = users.find(u => u.id === client.ownerId);

          return (
            <div key={client.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/30 hover:shadow-2xl hover:border-blue-100 transition-all group flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-6">
                  <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-white group-hover:bg-blue-600 transition-colors">
                    <Icons.Clients />
                  </div>
                  {isLeader && (
                    <button 
                      onClick={() => setTransferClient(client)}
                      title="Transferir Cartera"
                      className="p-2 hover:bg-slate-100 rounded-xl text-slate-400 hover:text-slate-900 transition-all"
                    >
                      <Icons.Users />
                    </button>
                  )}
                </div>
                <h3 className="text-xl font-black text-slate-800 leading-tight mb-1 truncate">{client.name}</h3>
                <p className="text-[10px] text-slate-400 font-black mb-4 uppercase truncate">Ejecutivo: {owner?.name || 'SISTEMA'}</p>

                <div className="flex gap-4 mb-8">
                   <div>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Activas</p>
                     <p className="text-lg font-black text-slate-900">{activeODTs}</p>
                   </div>
                   <div className="w-px h-8 bg-slate-100"></div>
                   <div>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Histórico</p>
                     <p className="text-lg font-black text-slate-400">{clientODTs.length}</p>
                   </div>
                </div>
              </div>

              <button 
                onClick={() => setSelectedClient(client)}
                className="w-full py-3 bg-slate-50 text-slate-900 font-black text-[10px] uppercase tracking-widest rounded-xl border border-slate-100 hover:bg-slate-900 hover:text-white transition-all flex items-center justify-center gap-2"
              >
                <Icons.Plus /> ABRIR ODT MASTER
              </button>
            </div>
          );
        })}
      </div>

      {isCreatingClient && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl animate-fadeIn">
            <h2 className="text-2xl font-black text-slate-900 mb-2">Nueva Carpeta</h2>
            <p className="text-xs text-slate-500 font-medium mb-6">El nombre debe coincidir exactamente con el nombre legal o comercial de la empresa.</p>
            <form onSubmit={handleCreateClient} className="space-y-4">
               <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Nombre de Empresa</label>
                  <input autoFocus value={newClientName} onChange={e => setNewClientName(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold" placeholder="Ejem: Laboratorios Roche S.A." />
               </div>
               <div className="flex gap-3 pt-4">
                  <button type="button" onClick={() => setIsCreatingClient(false)} className="flex-1 py-3 text-xs font-black text-slate-400 uppercase hover:text-slate-600">Cancelar</button>
                  <button type="submit" className="flex-1 py-3 bg-slate-900 text-white font-black text-xs rounded-xl hover:bg-slate-800 transition-all shadow-xl shadow-slate-200">CREAR CARPETA</button>
               </div>
            </form>
          </div>
        </div>
      )}

      {transferClient && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
           <div className="bg-white p-8 rounded-3xl w-full max-w-md border-t-8 border-slate-900 animate-fadeIn">
              <h2 className="text-xl font-black mb-1">Transferir Cartera</h2>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-6">Cliente: {transferClient.name}</p>

              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-2 block">Nuevo Dueño de Cuenta</label>
                  <select 
                    value={targetOwner} 
                    onChange={e => setTargetOwner(e.target.value)}
                    className="w-full px-4 py-3 bg-slate-50 border-2 rounded-xl font-bold outline-none appearance-none"
                  >
                    <option value="">-- Seleccione Ejecutivo --</option>
                    {accountsUsers.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                  </select>
                </div>

                <p className="text-[10px] text-slate-500 italic bg-slate-50 p-4 rounded-xl">
                  * Al transferir, el nuevo ejecutivo será dueño de la carpeta y de TODAS sus ODTs históricas y activas.
                </p>

                <div className="flex gap-3">
                  <button onClick={() => setTransferClient(null)} className="flex-1 py-3 text-xs font-black text-slate-400 uppercase">Cerrar</button>
                  <button 
                    disabled={!targetOwner}
                    onClick={handleQuickTransfer} 
                    className="flex-2 px-8 py-3 bg-slate-900 text-white font-black text-xs rounded-xl hover:bg-slate-800 disabled:opacity-50 transition-all"
                  >EJECUTAR TRASPASO</button>
                </div>
              </div>
           </div>
        </div>
      )}

      {selectedClient && (
        <NewODTForm client={selectedClient} onClose={() => setSelectedClient(null)} />
      )}
    </div>
  );
};

export default ClientsView;

export enum UserRole {
  Admin = 'Admin',
  Cuentas_Lider = 'Cuentas_Lider',
  Cuentas_Opera = 'Cuentas_Opera',
  Lider_Operativo = 'Lider_Operativo',
  Operativo = 'Operativo',
  Correccion = 'Correccion'
}

export interface User {
  id: string; // Key sanitizada en Firebase
  name: string;
  username: string;
  password?: string;
  department: string;
  role: UserRole;
  active: boolean;
  createdAt?: string;
}

export interface ProjectComment {
  id: string;
  authorId: string;
  authorName: string;
  text: string;
  createdAt: string;
  isSystemEvent?: boolean;
}

export interface ProjectAssignment {
  area: string;
  usuarioId: string;
  status: 'pendiente' | 'en_progreso' | 'completado';
}

export interface Project {
  id: string;
  clientId: string;
  empresa: string;
  marca: string;
  producto: string;
  etapa_actual: string;
  category: string;
  subCategory: string;
  referenceLinks: string[];
  status: 'Borrador' | 'En Proceso' | 'Correcciones' | 'QA' | 'Finalizado' | 'Cancelado';
  correccion_ok: boolean;
  areas_seleccionadas: string[];
  asignaciones: ProjectAssignment[];
  tracking: any[];
  comentarios: ProjectComment[];
  monto_proyectado: number;
  brief: string;
  facturado?: boolean;
  pagado?: boolean;
  justificacion_no_facturado?: string;
  ownerId?: string;
  createdAt: string;
  updatedAt: string;
  fecha_finalizado?: string;
}

export interface Client {
  id: string;
  name: string;
  notes?: string;
  ownerId: string;
  createdAt: string;
}

export type ViewState = 
  | 'login' 
  | 'dashboard' 
  | 'leader-dashboard'
  | 'my-projects' 
  | 'clients' 
  | 'users' 
  | 'qa-box' 
  | 'finances' 
  | 'project-detail';

export interface LoginResult {
  success: boolean;
  error?: string;
}

export interface ODTContextType {
  user: User | null;
  projects: Project[];
  clients: Client[];
  users: User[];
  loading: boolean;
  login: (username: string, pass: string) => Promise<LoginResult>;
  logout: () => void;
  updateProjectStatus: (projectId: string, newStatus: Project['status'], comment: string) => Promise<void>;
  updateBrief: (projectId: string, content: string) => Promise<void>;
  processQA: (projectId: string, approved: boolean, feedback: string) => Promise<void>;
  updateBilling: (projectId: string, facturado: boolean, justification?: string) => Promise<void>;
  updatePaymentStatus: (projectId: string, pagado: boolean) => Promise<void>;
  checkSLA: (project: Project) => { isAlert: boolean; reason?: string };
  delegateProject: (projectId: string, area: string, userId: string) => Promise<void>;
  // Fix: Added the optional 'portfolio' argument to match the actual implementation in ODTContext.tsx
  reassignProjectAndFolder: (projectId: string, clientId: string, newOwnerId: string, portfolio?: boolean) => Promise<void>;
  addClient: (name: string, notes?: string) => Promise<void>;
  addProject: (project: Partial<Project>) => Promise<void>;
  manageUser: (userData: Partial<User>) => Promise<void>;
  toggleUserStatus: (userId: string, active: boolean) => Promise<void>;
}

import React, { useState } from 'react';
