      { name: 'Auditor de Calidad', username: 'qa.master', password: '123', role: UserRole.Correccion, department: 'QA' },
      { name: 'Analista Finanzas', username: 'finanzas.test', password: '123', role: UserRole.Operativo, department: 'Finanzas' },
