import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';
import { Project, User, ODTContextType, UserRole, LoginResult, Client } from './types';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

const escapeFirebaseKey = (key: string) => key.toLowerCase().trim().replace(/[\.\#\$\/\[\]]/g, '_');

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión", e);
      }
    }
  }, []);

  useEffect(() => {
    if (!db) {
      setLoading(false);
      return;
    }
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
    });

    onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
    });

    onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      setLoading(false);
    });
  }, []);

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    const dbKey = escapeFirebaseKey(cleanUsername);
    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', name: 'Admin Bypass', username: 'admin', department: 'Sistemas', role: UserRole.Admin, active: true };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }
    try {
      const userRef = ref(db, `users/${dbKey}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `Usuario no encontrado.` };
      const userData = snapshot.val();
      if (!userData.active) return { success: false, error: 'Cuenta inactiva.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };
      const authUser: User = { ...userData, id: dbKey };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const addProject = async (projectData: Partial<Project>) => {
    if (!db || !user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    await set(ref(db, `projects/${projectId}`), {
      ...projectData,
      status: 'Borrador',
      current_stage_index: 0,
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: 'SISTEMA', text: `ODT INICIADA EN CUENTAS (GESTIÓN)`, createdAt: new Date().toISOString(), isSystemEvent: true }],
      asignaciones: [],
      pagado: false
    });
  };

  const advanceProjectStage = async (projectId: string, comment: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const newIndex = (project.current_stage_index || 0) + 1;
    const updates: any = {
      current_stage_index: newIndex,
      updatedAt: new Date().toISOString(),
      comentarios: [{ 
        id: `step-${Date.now()}`, 
        authorId: user.id, 
        authorName: user.name, 
        text: `AVANCE DE ETAPA: ${comment}`, 
        createdAt: new Date().toISOString(), 
        isSystemEvent: true 
      }, ...(project.comentarios || [])]
    };

    // Actualizar status general para filtros de bandeja
    if (newIndex > 0) updates.status = 'En Proceso';

    await update(ref(db, `projects/${projectId}`), updates);
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    if (approved) {
      const newIndex = (project.current_stage_index || 0) + 1;
      const updates: any = {
        current_stage_index: newIndex,
        correccion_ok: true,
        updatedAt: new Date().toISOString(),
        comentarios: [{ 
          id: `qa-${Date.now()}`, 
          authorId: user.id, 
          authorName: 'SISTEMA (QA)', 
          text: `APROBADO: ${feedback}`, 
          createdAt: new Date().toISOString(), 
          isSystemEvent: true 
        }, ...(project.comentarios || [])]
      };

      // Si es el último paso, marcar como finalizado
      const totalStages = 1 + (project.areas_seleccionadas.length * 2) + 2;
      if (newIndex >= totalStages - 1) {
        updates.status = 'Finalizado';
        updates.fecha_finalizado = new Date().toISOString();
      }

      await update(ref(db, `projects/${projectId}`), updates);
    } else {
      // Si es rechazado, retroceder al área operativa anterior
      const updates: any = {
        current_stage_index: project.current_stage_index - 1,
        correccion_ok: false,
        updatedAt: new Date().toISOString(),
        comentarios: [{ 
          id: `qa-${Date.now()}`, 
          authorId: user.id, 
          authorName: 'SISTEMA (QA)', 
          text: `RECHAZADO: ${feedback}. Volviendo a etapa de producción.`, 
          createdAt: new Date().toISOString(), 
          isSystemEvent: true 
        }, ...(project.comentarios || [])]
      };
      await update(ref(db, `projects/${projectId}`), updates);
    }
  };

  const manageUser = async (userData: Partial<User>) => {
    if (!db || !userData.username) throw new Error("Datos incompletos.");
    const dbKey = escapeFirebaseKey(userData.username);
    await set(ref(db, `users/${dbKey}`), { ...userData, username: userData.username.toLowerCase(), createdAt: new Date().toISOString() });
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    if (!db) return;
    await update(ref(db, `users/${userId}`), { active });
  };

  const addClient = async (name: string, notes?: string) => {
    if (!db) return;
    const clientId = `CL-${Date.now()}`;
    await set(ref(db, `clients/${clientId}`), { id: clientId, name: name.trim(), notes: notes || '', ownerId: user?.id || 'system', createdAt: new Date().toISOString() });
  };

  const updateProjectStatus = async (projectId: string, newStatus: Project['status'], commentText: string) => {
    if (!db || !user) return;
    await update(ref(db, `projects/${projectId}`), { status: newStatus, updatedAt: new Date().toISOString() });
  };

  const updateBrief = async (projectId: string, content: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { brief: content, updatedAt: new Date().toISOString() });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { facturado, justificacion_no_facturado: justification || "", updatedAt: new Date().toISOString() });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    if (!db) return;
    await update(ref(db, `projects/${projectId}`), { pagado, updatedAt: new Date().toISOString() });
  };

  const checkSLA = (project: Project) => {
    const lastUpdate = new Date(project.updatedAt || project.createdAt);
    const hours = (new Date().getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    return { isAlert: project.status !== 'Finalizado' && hours > 72, reason: hours > 72 ? 'Estancado > 72h' : undefined };
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'pendiente' }];
    await update(ref(db, `projects/${projectId}`), { asignaciones: newAsignaciones, updatedAt: new Date().toISOString() });
  };

  const reassignProjectAndFolder = async (projectId: string, clientId: string, newOwnerId: string, portfolio: boolean = false) => {
    if (!db || !user) return;
    const updates: any = {};
    if (portfolio) {
      updates[`clients/${clientId}/ownerId`] = newOwnerId;
      projects.filter(p => p.clientId === clientId).forEach(p => updates[`projects/${p.id}/ownerId`] = newOwnerId);
    } else {
      updates[`projects/${projectId}/ownerId`] = newOwnerId;
    }
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus, updateBrief, processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient, addProject,
      manageUser, toggleUserStatus, advanceProjectStage
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, users, advanceProjectStage, updateBrief, processQA, reassignProjectAndFolder } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [auditResult, setAuditResult] = useState<any>(null);
  const [isAuditing, setIsAuditing] = useState(false);
  const [showReassignModal, setShowReassignModal] = useState(false);
  const [targetOwner, setTargetOwner] = useState('');

  // CONSTRUCCIÓN DINÁMICA DE LA RUTA ISO 9001
  const roadmapStages = useMemo(() => {
    const stages = ["CUENTAS (Gestión)"];
    project.areas_seleccionadas.forEach(area => {
      stages.push(area);
      stages.push(`REVISIÓN QA (${area})`);
    });
    stages.push("CUENTAS (Cierre)");
    stages.push("ADMINISTRACIÓN (Facturación)");
    return stages;
  }, [project.areas_seleccionadas]);

  const currentIdx = project.current_stage_index || 0;
  const currentStageName = roadmapStages[currentIdx];
  const isQAStage = currentStageName.includes('REVISIÓN QA');

  const canAdvance = useMemo(() => {
    if (!user) return false;
    if (user.role === UserRole.Admin) return true;

    // Si es QA Gate, solo Corrección puede avanzar
    if (isQAStage) return user.role === UserRole.Correccion;

    // Si es área operativa, el líder o el operativo asignado puede avanzar
    if (currentIdx > 0 && currentIdx < roadmapStages.length - 2) {
      const currentArea = roadmapStages[currentIdx];
      return user.department === currentArea || user.role.endsWith('_Lider');
    }

    // Cuentas gestiona el inicio y cierre
    if (currentStageName.includes('CUENTAS')) return user.department === 'Cuentas';

    // Administración gestiona el final
    if (currentStageName.includes('ADMINISTRACIÓN')) return user.department === 'Finanzas';

    return false;
  }, [user, currentIdx, isQAStage, currentStageName]);

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  const handleAdvance = async () => {
    if (!confirm(`¿Confirmas el cumplimiento de la etapa "${currentStageName}"?`)) return;
    await advanceProjectStage(project.id, `Fase ${currentStageName} completada satisfactoriamente.`);
  };

  const isAdminOrLead = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;
  const accountsUsers = useMemo(() => users.filter(u => u.role === UserRole.Cuentas_Opera || u.role === UserRole.Cuentas_Lider), [users]);

  return (
    <div className="space-y-6 animate-fadeIn pb-20">
      <header className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500">
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
          </button>
          <div>
            <h1 className="text-2xl font-black text-slate-900">{project.id}</h1>
            <p className="text-sm text-slate-500 font-medium">{project.empresa} - {project.producto}</p>
          </div>
        </div>
        {isAdminOrLead && (
          <button onClick={() => setShowReassignModal(true)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all flex items-center gap-2">
            <Icons.Users /> Reasignar Propietario
          </button>
        )}
      </header>

      {/* TIMELINE DINÁMICO ADAPTATIVO */}
      <div className="bg-white p-6 rounded-2xl border shadow-sm overflow-x-auto">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">Trazabilidad de Etapas (ISO 9001)</h3>
        <div className="min-w-max px-4 relative flex justify-between items-center gap-8">
          <div className="absolute top-4 left-0 w-full h-1 bg-slate-100 -z-10"></div>
          {roadmapStages.map((stage, idx) => {
            const isActive = idx === currentIdx;
            const isCompleted = idx < currentIdx;
            const isQA = stage.includes('REVISIÓN QA');
            return (
              <div key={idx} className="flex flex-col items-center gap-3 relative">
                <div className={`w-9 h-9 rounded-full border-4 flex items-center justify-center transition-all duration-500 ${
                  isActive ? 'bg-blue-600 border-blue-200 shadow-xl scale-125 z-10' : 
                  isCompleted ? 'bg-emerald-500 border-emerald-100' : 'bg-slate-100 border-white'
                }`}>
                  {isCompleted ? (
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                  ) : isQA ? (
                    <Icons.Ai />
                  ) : <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white animate-pulse' : 'bg-slate-300'}`}></div>}
                </div>
                <div className="text-center max-w-[100px]">
                  <p className={`text-[9px] font-black uppercase tracking-tighter leading-none ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>
                    {stage}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Icons.Project /> Brief Maestro
              </h3>
              <button onClick={() => updateBrief(project.id, briefContent)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black rounded-lg hover:bg-slate-800 transition-all">
                ACTUALIZAR BRIEF
              </button>
            </div>
            <ReactQuill theme="snow" value={briefContent} onChange={setBriefContent} />
          </div>

          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad</h3>
            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2">
              {project.comentarios.map(c => (
                <div key={c.id} className={`p-4 rounded-xl text-xs border ${c.isSystemEvent ? 'bg-slate-50 border-dashed border-slate-200' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between mb-2">
                    <span className="font-black uppercase text-[9px] text-blue-500">{c.authorName}</span>
                    <span className="text-slate-400 font-mono text-[9px]">{new Date(c.createdAt).toLocaleString()}</span>
                  </div>
                  <p className="text-slate-700 font-medium">{c.text}</p>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {/* CONTROL DE AVANCE DE ETAPA */}
          <div className={`p-6 rounded-2xl shadow-xl space-y-4 border-2 ${isQAStage ? 'bg-amber-50 border-amber-200' : 'bg-slate-900 border-slate-800 text-white'}`}>
             <h3 className={`font-black text-xs uppercase tracking-widest flex items-center gap-2 ${isQAStage ? 'text-amber-700' : 'text-blue-400'}`}>
               {isQAStage ? <Icons.Ai /> : <Icons.Plus />} 
               {isQAStage ? 'Gate de Calidad (QA)' : 'Avance de Producción'}
             </h3>
             <p className={`text-[10px] font-medium leading-tight ${isQAStage ? 'text-amber-600' : 'text-slate-400'}`}>
               Etapa Actual: <span className="font-black uppercase underline">{currentStageName}</span>
             </p>

             {isQAStage ? (
               <div className="space-y-4">
                  <textarea 
                    placeholder="Feedback de revisión técnica..."
                    className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs outline-none font-medium h-24"
                    value={qaFeedback}
                    onChange={(e) => setQaFeedback(e.target.value)}
                  />
                  <div className="grid grid-cols-2 gap-3">
                    <button 
                      disabled={!canAdvance || !qaFeedback}
                      onClick={() => processQA(project.id, true, qaFeedback)}
                      className="py-3 bg-emerald-600 text-white font-black text-[10px] rounded-xl hover:bg-emerald-700 disabled:opacity-50 transition-all"
                    >APROBAR GATE</button>
                    <button 
                      disabled={!canAdvance || !qaFeedback}
                      onClick={() => processQA(project.id, false, qaFeedback)}
                      className="py-3 bg-rose-600 text-white font-black text-[10px] rounded-xl hover:bg-rose-700 disabled:opacity-50 transition-all"
                    >RECHAZAR</button>
                  </div>
               </div>
             ) : (
               <button 
                 disabled={!canAdvance || project.status === 'Finalizado'}
                 onClick={handleAdvance}
                 className="w-full py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-900/40 disabled:bg-slate-800 disabled:text-slate-600 text-[10px] uppercase tracking-widest"
               >
                 {project.status === 'Finalizado' ? 'PROYECTO CERRADO' : `COMPLETAR: ${currentStageName}`}
               </button>
             )}

             {!canAdvance && !isQAStage && project.status !== 'Finalizado' && (
               <p className="text-[9px] text-rose-400 font-bold text-center animate-pulse">
                 SOLO PERSONAL DE "{currentStageName}" PUEDE AVANZAR ESTA FASE.
               </p>
             )}
          </div>

          {/* AUDITOR DE AI */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="flex items-center gap-2 font-black text-[10px] mb-4 text-blue-600 uppercase tracking-widest"><Icons.Ai /> AI Auditor (ISO 9001)</h3>
            <button 
              onClick={handleAudit}
              disabled={isAuditing}
              className="w-full py-3 bg-slate-100 text-slate-900 rounded-xl font-black text-[10px] hover:bg-slate-200 transition-all flex items-center justify-center gap-2 uppercase tracking-widest"
            >
              {isAuditing ? <div className="w-4 h-4 border-2 border-slate-400 border-t-slate-900 rounded-full animate-spin"></div> : 'VALIDAR CUMPLIMIENTO'}
            </button>
            {auditResult && (
              <div className="mt-4 p-4 bg-slate-50 rounded-xl border border-dashed space-y-3 animate-fadeIn">
                <div className="flex justify-between items-center">
                  <span className="font-black text-[9px] text-slate-400 uppercase">Audit Score:</span> 
                  <span className={`text-xl font-black ${auditResult.score > 80 ? 'text-emerald-600' : 'text-amber-600'}`}>{auditResult.score}%</span>
                </div>
                <div className="text-[9px] text-slate-500 font-bold uppercase leading-tight bg-white p-2 rounded-lg border border-slate-100">
                  Ref: {auditResult.isoClause}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

