                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Justificación de Gratuidad</label>
                <textarea required value={justification} onChange={e => setJustification(e.target.value)} className="w-full px-4 py-3 bg-white border rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-sm h-24" placeholder="Indique motivo: Error interno, cortesía, etc..." />
              </div>
            )}
          </section>

          <section className="space-y-4">
             <div className="flex justify-between items-center">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Brief Maestro y Requerimientos</label>
                <span className="text-[9px] bg-emerald-50 text-emerald-600 px-2 py-1 rounded font-black">SOPORTA TABLAS EXCEL/WORD</span>
             </div>
             <div className="bg-white rounded-xl border">
               <ReactQuill theme="snow" value={brief} onChange={setBrief} className="h-64 mb-12" />
             </div>

             <div className="space-y-3 pt-6">
                <div className="flex justify-between items-center">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Enlaces de Referencia / Assets</label>
                  <button type="button" onClick={handleAddLink} className="p-1 text-blue-600 hover:bg-blue-50 rounded-lg transition-all"><Icons.Plus /></button>
                </div>
                {links.map((link, idx) => (
                  <input key={idx} value={link} onChange={e => handleLinkChange(idx, e.target.value)} className="w-full px-4 py-2 bg-slate-50 border border-dashed rounded-lg text-xs font-medium outline-none focus:border-blue-500 transition-all" placeholder="https://drive.google.com/..." />
                ))}
             </div>
          </section>

          <footer className="pt-8 border-t flex justify-end gap-3">
             <button type="button" onClick={onClose} className="px-6 py-3 text-xs font-black text-slate-500 hover:text-slate-900 transition-all uppercase">Cancelar</button>
             <button disabled={loading} type="submit" className="px-10 py-3 bg-slate-900 text-white text-xs font-black rounded-xl hover:bg-slate-800 transition-all shadow-xl disabled:opacity-50">
               {loading ? 'REGISTRANDO...' : 'CREAR ODT MASTER'}
             </button>
          </footer>
        </form>
      </div>
    </div>
  );
};

