            <h1 className="text-white text-2xl font-bold tracking-tight">ODT Manager</h1>
            <p className="text-blue-100 text-sm mt-1">Gestión Normativa APC</p>
          </div>
          <form className="p-8 space-y-6" onSubmit={handleSubmit}>
            {errorMsg && (
              <div className="p-3 bg-rose-50 text-rose-600 text-xs font-bold rounded-lg border border-rose-100 flex items-center gap-2">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                {errorMsg}
              </div>
            )}
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Usuario</label>
              <input value={u} onChange={e => setU(e.target.value)} type="text" className="w-full px-4 py-3 bg-slate-50 border rounded-xl outline-none transition-all font-medium" placeholder="ID de Usuario" required />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Contraseña</label>
              <input value={p} onChange={e => setP(e.target.value)} type="password" className="w-full px-4 py-3 bg-slate-50 border rounded-xl outline-none transition-all font-medium" placeholder="••••••••" required />
            </div>
            <button type="submit" className="w-full py-4 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-xl">
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export const AppRouter: React.FC<{ renderView: (view: ViewState) => React.ReactNode }> = ({ renderView }) => {
  const { user, logout } = useODT();
  const [view, setView] = useState<ViewState>('dashboard');

  useEffect(() => {
    if (!user) return;
    if (user.role === UserRole.Correccion || user.role === UserRole.QA_Opera) setView('qa-box');
    else if (user.department === 'Finanzas') setView('finances');
    else if (user.role === UserRole.Lider_Operativo) setView('leader-dashboard');
    else if (user.role === UserRole.Operativo) setView('my-projects');
    else if (user.role === UserRole.Cuentas_Opera || user.role === UserRole.Cuentas_Lider) setView('clients');
    else setView('dashboard');
  }, [user]);

  if (!user) return <Login />;

  const canSee = (roles: UserRole[]) => roles.includes(user.role) || user.role === UserRole.Admin;

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 fixed h-full p-6 flex flex-col gap-8 shadow-2xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl">ISO</div>
          <h2 className="text-white font-bold tracking-tighter">ODT Manager</h2>
        </div>
        <nav className="flex flex-col gap-2 flex-1">
          {canSee([UserRole.Admin, UserRole.Cuentas_Lider]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Adm." active={view === 'dashboard'} onClick={() => setView('dashboard')} />}
          {canSee([UserRole.Lider_Operativo]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Lider" active={view === 'leader-dashboard'} onClick={() => setView('leader-dashboard')} />}
          {canSee([UserRole.Cuentas_Opera, UserRole.Cuentas_Lider, UserRole.Admin]) && <SidebarItem icon={<Icons.Clients />} label="Clientes / Archivo" active={view === 'clients'} onClick={() => setView('clients')} />}
          {canSee([UserRole.Operativo, UserRole.Lider_Operativo, UserRole.Cuentas_Lider, UserRole.Admin, UserRole.QA_Opera]) && <SidebarItem icon={<Icons.Project />} label="Bandeja Operativa" active={view === 'my-projects'} onClick={() => setView('my-projects')} />}
          {canSee([UserRole.Correccion, UserRole.Admin, UserRole.Cuentas_Lider, UserRole.QA_Opera]) && <SidebarItem icon={<Icons.Ai />} label="Caja de QA" active={view === 'qa-box'} onClick={() => setView('qa-box')} />}
          {(user.department === 'Finanzas' || user.role === UserRole.Admin || user.role === UserRole.Cuentas_Lider) ? <SidebarItem icon={<Icons.Clients />} label="Facturación" active={view === 'finances'} onClick={() => setView('finances')} /> : null}
          {user.role === UserRole.Admin && <SidebarItem icon={<Icons.Users />} label="Usuarios" active={view === 'users'} onClick={() => setView('users')} />}
        </nav>
        <div className="p-4 bg-slate-800/50 rounded-xl border border-slate-700/50">
          <p className="text-xs font-bold text-white truncate">{user.name}</p>
          <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{user.role}</p>
          <button onClick={logout} className="w-full mt-4 py-2 text-[10px] uppercase font-bold text-slate-400 hover:text-white border border-slate-700 rounded-md transition-colors">Salir</button>
        </div>
      </aside>
      <main className="flex-1 ml-64 p-8">{renderView(view)}</main>
    </div>
  );
};

const SidebarItem: React.FC<{ icon: any, label: string, active: boolean, onClick: () => void }> = ({ icon: Icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${active ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
    {typeof Icon === 'function' ? <Icon /> : Icon} <span className="font-medium text-sm">{label}</span>
  </button>
);

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ODTProvider, useODT } from './ODTContext';
import { AppRouter } from './AppRouter';
import AdminDashboard from './AdminDashboard';
import LeaderDashboard from './LeaderDashboard';
import ProjectDetail from './ProjectDetail';
import ClientsView from './ClientsView';
import UsersView from './UsersView';
import { db } from './firebase';

const AppContent: React.FC = () => {
  const { user, projects, checkSLA, updateBilling, updatePaymentStatus, loading, getRoadmapStages } = useODT();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  if (!db || loading) {
    return (
      <div className="bg-[#0f172a] h-screen w-screen flex flex-col items-center justify-center gap-6">
        <div className="w-16 h-16 border-4 border-t-blue-500 border-slate-700 rounded-full animate-spin"></div>
        <div className="text-center animate-pulse">
          <h1 className="text-white font-black text-xl tracking-[0.3em] uppercase">Iniciando Servicios APC...</h1>
          <p className="text-slate-500 text-xs mt-2 font-bold tracking-widest uppercase">Estableciendo conexión con Realtime Database</p>
        </div>
      </div>
    );
  }

  const exportMasterCSV = () => {
    const headers = ["ID ODT", "Cliente", "Marca", "Producto", "Fecha Creación", "Fecha Entrega", "Monto", "Facturado", "Pagado", "Días en Sistema"];
    const rows = projects.map(p => {
      const created = new Date(p.createdAt);
      const finished = p.fecha_finalizado ? new Date(p.fecha_finalizado) : new Date();
      const daysInSystem = Math.floor((finished.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));

      return [
        p.id,
        p.empresa,
        p.marca,
        p.producto,
        created.toLocaleDateString(),
        p.fecha_finalizado ? new Date(p.fecha_finalizado).toLocaleDateString() : "Pte",
        p.monto_proyectado,
        p.facturado ? "SÍ" : "NO",
        p.pagado ? "SÍ" : "NO",
        daysInSystem
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `APC_Master_Report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const renderMyInbox = () => {
    const isGlobalLead = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;
    const myProjects = projects?.filter(p => {
      if (isGlobalLead) return true;

      // Los operativos (técnicos o de QA) solo ven lo que tienen asignado directamente
      const isDirectlyAssigned = p.asignaciones?.some(a => a.usuarioId === user?.id);

      const isAreaLead = user?.role === UserRole.Lider_Operativo;
      if (isAreaLead) {
        const stages = getRoadmapStages(p);
        const currentStage = stages[p.current_stage_index || 0];
        return currentStage === user?.department;
      }

      return isDirectlyAssigned;
    }) || [];

    return (
      <div className="space-y-6">
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-black">Bandeja Operativa</h1>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
              {isGlobalLead ? 'VISTA GLOBAL DE CARTERA APC' : 'Tareas técnicas asignadas directamente'}
            </p>
          </div>
        </header>
        <div className="bg-white p-6 rounded-xl border-2 border-dashed border-slate-200">
           {myProjects.length === 0 ? (
             <p className="text-slate-400 italic text-center py-10">No tiene tareas asignadas en este momento.</p>
           ) : (
             <ProjectTable projects={myProjects} onView={setSelectedProject} checkSLA={checkSLA} />
           )}
        </div>
      </div>
    );
  };

  const renderQABox = () => {
    const qaProjects = projects?.filter(p => {
      const stages = getRoadmapStages(p);
      const currentStage = stages[p.current_stage_index || 0] || '';
      const inQAStage = currentStage.includes('REVISIÓN QA');

      if (!inQAStage) return false;

      // Si es el Líder de QA o Admin, ve todas las revisiones
      if (user?.role === UserRole.Correccion || user?.role === UserRole.Admin) return true;

      // Si es QA Operativo, solo ve lo asignado
      if (user?.role === UserRole.QA_Opera) {
        return p.asignaciones?.some(a => a.usuarioId === user?.id);
      }

      return false;
    }) || [];

    return (
      <div className="space-y-6">
        <header>
          <h1 className="text-3xl font-black text-slate-900">Caja de QA</h1>
          <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">Control de Calidad ISO 9001</p>
        </header>
        <div className="bg-white p-6 rounded-xl border-2 border-dashed border-slate-200">
           {qaProjects.length === 0 ? (
             <p className="text-slate-400 italic text-center py-10">No hay revisiones técnicas pendientes o asignadas.</p>
           ) : (
             <ProjectTable projects={qaProjects} onView={setSelectedProject} checkSLA={checkSLA} />
           )}
        </div>
      </div>
    );
  };

  const renderFinances = () => {
    const now = new Date();
    const billingProjects = projects?.filter(p => {
      const stages = getRoadmapStages(p);
      const closingIndex = stages.indexOf("CUENTAS (Cierre)");
      return p.current_stage_index >= closingIndex;
    }) || [];

    return (
      <div className="space-y-8 animate-fadeIn">
        <header className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Módulo de Facturación</h1>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1 italic">Control de Tesorería - APC Realtime</p>
          </div>
          <button 
            onClick={exportMasterCSV}
            className="px-6 py-3 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all flex items-center gap-2 shadow-xl"
          >
            <Icons.Dashboard /> EXPORTAR REPORTE MAESTRO (CSV)
          </button>
        </header>

        <div className="bg-white rounded-3xl border border-slate-100 shadow-2xl overflow-hidden">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
              <tr>
                <th className="px-6 py-5">Identificador ODT</th>
                <th className="px-6 py-5">Cliente / Producto</th>
                <th className="px-6 py-5">Monto Proyectado</th>
                <th className="px-6 py-5 text-center">Fact..</th>
                <th className="px-6 py-5 text-center">Pagado</th>
                <th className="px-6 py-5">Estatus de Cobro</th>
                <th className="px-6 py-5 text-right">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {billingProjects.map(p => {
                const stages = getRoadmapStages(p);
                const currentStage = stages[p.current_stage_index || 0];
                const lastUpdate = new Date(p.updatedAt);
                const daysInStage = Math.floor((now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60 * 24));
                const isLateBilling = currentStage === "CUENTAS (Cierre)" && daysInStage >= 3 && !p.facturado;

                return (
                  <tr key={p.id} className={`hover:bg-slate-50/80 transition-all ${isLateBilling ? 'bg-rose-50' : ''}`}>
                    <td className="px-6 py-4 font-mono font-black text-blue-600 text-xs">
                      {p.id}
                      {isLateBilling && (
                        <div className="text-[9px] text-rose-600 font-black animate-pulse flex items-center gap-1 mt-1">
                          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M12 2v10"/><path d="M12 16v.01"/></svg>
                          RIESGO DE FACTURACIÓN (+3D)
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4">
                      <div className="font-black text-slate-800 uppercase text-xs">{p.empresa}</div>
                      <div className="text-[10px] text-slate-400 font-bold">{p.producto}</div>
                    </td>
                    <td className="px-6 py-4 font-black text-slate-900">
                      ${p.monto_proyectado?.toLocaleString()}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <input 
                        type="checkbox" 
                        checked={p.facturado} 
                        onChange={e => updateBilling(p.id, e.target.checked)}
                        className="w-6 h-6 accent-blue-600 cursor-pointer rounded-lg" 
                      />
                    </td>
                    <td className="px-6 py-4 text-center">
                      <input 
                        type="checkbox" 
                        checked={p.pagado} 
                        onChange={e => updatePaymentStatus(p.id, e.target.checked)}
                        className="w-6 h-6 accent-emerald-600 cursor-pointer rounded-lg" 
                      />
                    </td>
                    <td className="px-6 py-4">
                       <span className={`px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                         p.pagado ? 'bg-emerald-100 text-emerald-700' : 
                         p.facturado ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-500'
                       }`}>
                         {p.pagado ? 'CONCILIADO' : p.facturado ? 'FACTURADO' : 'POR FACTURAR'}
                       </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                       <button onClick={() => setSelectedProject(p)} className="p-2 hover:bg-slate-200 rounded-xl transition-all">
                          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>
                       </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {billingProjects.length === 0 && (
            <div className="p-20 text-center text-slate-300 font-black uppercase tracking-[0.3em] text-xs">
              No hay proyectos en ciclo de cierre financiero
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderView = (view: ViewState) => {
    if (selectedProject) return <ProjectDetail project={selectedProject} onBack={() => setSelectedProject(null)} />;
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'clients': return <ClientsView />;
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      case 'users': return <UsersView />;
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

const ProjectTable = ({ projects, onView, checkSLA }: any) => (
  <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
    <table className="w-full text-sm text-left">
      <thead className="bg-slate-50 text-slate-500 font-black text-[10px] uppercase tracking-widest">
        <tr>
          <th className="px-6 py-5">ODT ID</th>
          <th className="px-6 py-5">Proyecto / Cliente</th>
          <th className="px-6 py-5">Status</th>
          <th className="px-6 py-5">SLA</th>
          <th className="px-6 py-5">Acciones</th>
        </tr>
      </thead>
      <tbody className="divide-y divide-slate-100">
        {projects?.map((p: Project) => {
          const sla = checkSLA(p);
          return (
            <tr key={p?.id} className={`hover:bg-slate-50/50 transition-all ${sla?.isAlert ? 'bg-pink-50/20' : ''}`}>
              <td className="px-6 py-4 font-mono font-black text-blue-600 text-xs">{p?.id}</td>
              <td className="px-6 py-4">
                <div className="font-bold text-slate-800">{p?.empresa}</div>
                <div className="text-[10px] text-slate-400 font-medium uppercase">{p?.producto}</div>
              </td>
              <td className="px-6 py-4">
                <span className={`px-2.5 py-1 rounded text-[10px] font-black uppercase tracking-tighter ${p?.status === 'QA' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-600'}`}>
                  {p?.status}
                </span>
              </td>
              <td className="px-6 py-4">
                {sla?.isAlert ? (
                  <span className="text-pink-600 text-[10px] font-black animate-pulse flex items-center gap-1">
                    <Icons.Plus /> CRÍTICO
                  </span>
                ) : (
                  <span className="text-emerald-500 text-[10px] font-bold uppercase tracking-widest">OK</span>
                )}
              </td>
              <td className="px-6 py-4">
                <button onClick={() => onView(p)} className="text-blue-600 font-black hover:text-blue-800 transition-colors text-xs border-b-2 border-transparent hover:border-blue-800 pb-0.5">DETALLE</button>
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  </div>
);

const App: React.FC = () => (
  <ODTProvider>
    <AppContent />
  </ODTProvider>
);

export default App;

import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, users, advanceProjectStage, updateBrief, processQA, reassignProjectAndFolder } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [auditResult, setAuditResult] = useState<any>(null);
  const [isAuditing, setIsAuditing] = useState(false);
  const [showReassignModal, setShowReassignModal] = useState(false);

  const roadmapStages = useMemo(() => {
    const stages = ["CUENTAS (Gestión)"];
    project.areas_seleccionadas.forEach(area => {
      stages.push(area);
      stages.push(`REVISIÓN QA (${area})`);
    });
    stages.push("CUENTAS (Cierre)");
    stages.push("ADMINISTRACIÓN (Facturación)");
    return stages;
  }, [project.areas_seleccionadas]);

  const currentIdx = project.current_stage_index || 0;
  const currentStageName = roadmapStages[currentIdx];
  const isQAStage = currentStageName.includes('REVISIÓN QA');

  const canAdvance = useMemo(() => {
    if (!user) return false;
    if (user.role === UserRole.Admin) return true;

    // Si es QA Gate
    if (isQAStage) {
      const isQaLider = user.role === UserRole.Correccion;
      const isQaOperaAssigned = user.role === UserRole.QA_Opera && project.asignaciones?.some(a => a.usuarioId === user.id);
      return isQaLider || isQaOperaAssigned;
    }

    // Si es área operativa, el líder o el operativo asignado puede avanzar
    if (currentIdx > 0 && currentIdx < roadmapStages.length - 2) {
      const currentArea = roadmapStages[currentIdx];
      const isAreaLead = user.role.endsWith('_Lider') && user.department === currentArea;
      const isDirectlyAssigned = project.asignaciones?.some(a => a.usuarioId === user.id);
      return isAreaLead || isDirectlyAssigned;
    }

    // Cuentas gestiona el inicio y cierre
    if (currentStageName.includes('CUENTAS')) return user.department === 'Cuentas';

    // Administración gestiona el final
    if (currentStageName.includes('ADMINISTRACIÓN')) return user.department === 'Finanzas';

    return false;
  }, [user, currentIdx, isQAStage, currentStageName, project.asignaciones]);

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  const handleAdvance = async () => {
    if (!confirm(`¿Confirmas el cumplimiento de la etapa "${currentStageName}"?`)) return;
    await advanceProjectStage(project.id, `Fase ${currentStageName} completada satisfactoriamente.`);
  };

  // Restricción: Solo Admin o Lider Cuentas pueden reasignar
  const canReassign = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;

  return (
    <div className="space-y-6 animate-fadeIn pb-20">
      <header className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500">
             <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
          </button>
          <div>
            <h1 className="text-2xl font-black text-slate-900">{project.id}</h1>
            <p className="text-sm text-slate-500 font-medium">{project.empresa} - {project.producto}</p>
          </div>
        </div>
        {canReassign && (
          <button onClick={() => setShowReassignModal(true)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all flex items-center gap-2">
            <Icons.Users /> Reasignar Propietario
          </button>
        )}
      </header>

      {/* TIMELINE DINÁMICO ADAPTATIVO */}
      <div className="bg-white p-6 rounded-2xl border shadow-sm overflow-x-auto">
        <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">Trazabilidad de Etapas (ISO 9001)</h3>
        <div className="min-w-max px-4 relative flex justify-between items-center gap-8">
          <div className="absolute top-4 left-0 w-full h-1 bg-slate-100 -z-10"></div>
          {roadmapStages.map((stage, idx) => {
            const isActive = idx === currentIdx;
            const isCompleted = idx < currentIdx;
            const isQA = stage.includes('REVISIÓN QA');
            return (
              <div key={idx} className="flex flex-col items-center gap-3 relative">
                <div className={`w-9 h-9 rounded-full border-4 flex items-center justify-center transition-all duration-500 ${
                  isActive ? 'bg-blue-600 border-blue-200 shadow-xl scale-125 z-10' : 
                  isCompleted ? 'bg-emerald-500 border-emerald-100' : 'bg-slate-100 border-white'
                }`}>
                  {isCompleted ? (
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                  ) : isQA ? (
                    <Icons.Ai />
                  ) : <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white animate-pulse' : 'bg-slate-300'}`}></div>}
                </div>
                <div className="text-center max-w-[100px]">
                  <p className={`text-[9px] font-black uppercase tracking-tighter leading-none ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>
                    {stage}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
                <Icons.Project /> Brief Maestro
              </h3>
              <button onClick={() => updateBrief(project.id, briefContent)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black rounded-lg hover:bg-slate-800 transition-all">
                ACTUALIZAR BRIEF
              </button>
            </div>
            <ReactQuill theme="snow" value={briefContent} onChange={setBriefContent} />
          </div>

          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad</h3>
            <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2">
              {project.comentarios.map(c => (
                <div key={c.id} className={`p-4 rounded-xl text-xs border ${c.isSystemEvent ? 'bg-slate-50 border-dashed border-slate-200' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between mb-2">
                    <span className="font-black uppercase text-[9px] text-blue-500">{c.authorName}</span>
                    <span className="text-slate-400 font-mono text-[9px]">{new Date(c.createdAt).toLocaleString()}</span>
                  </div>
                  <p className="text-slate-700 font-medium">{c.text}</p>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          {/* CONTROL DE AVANCE DE ETAPA */}
          <div className={`p-6 rounded-2xl shadow-xl space-y-4 border-2 ${isQAStage ? 'bg-amber-50 border-amber-200' : 'bg-slate-900 border-slate-800 text-white'}`}>
             <h3 className={`font-black text-xs uppercase tracking-widest flex items-center gap-2 ${isQAStage ? 'text-amber-700' : 'text-blue-400'}`}>
               {isQAStage ? <Icons.Ai /> : <Icons.Plus />} 
               {isQAStage ? 'Gate de Calidad (QA)' : 'Avance de Producción'}
             </h3>
             <p className={`text-[10px] font-medium leading-tight ${isQAStage ? 'text-amber-600' : 'text-slate-400'}`}>
               Etapa Actual: <span className="font-black uppercase underline">{currentStageName}</span>
             </p>

             {isQAStage ? (
               <div className="space-y-4">
                  <textarea 
                    placeholder="Feedback de revisión técnica..."
                    className="w-full bg-white border border-amber-200 rounded-xl p-3 text-xs outline-none font-medium h-24"
                    value={qaFeedback}
                    onChange={(e) => setQaFeedback(e.target.value)}
                  />
                  <div className="grid grid-cols-2 gap-3">
                    <button 
                      disabled={!canAdvance || !qaFeedback}
                      onClick={() => processQA(project.id, true, qaFeedback)}
                      className="py-3 bg-emerald-600 text-white font-black text-[10px] rounded-xl hover:bg-emerald-700 disabled:opacity-50 transition-all"
                    >APROBAR GATE</button>
                    <button 
                      disabled={!canAdvance || !qaFeedback}
                      onClick={() => processQA(project.id, false, qaFeedback)}
                      className="py-3 bg-rose-600 text-white font-black text-[10px] rounded-xl hover:bg-rose-700 disabled:opacity-50 transition-all"
                    >RECHAZAR</button>
                  </div>
               </div>
             ) : (
               <button 
                 disabled={!canAdvance || project.status === 'Finalizado'}
                 onClick={handleAdvance}
                 className="w-full py-4 bg-blue-600 text-white font-black rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-900/40 disabled:bg-slate-800 disabled:text-slate-600 text-[10px] uppercase tracking-widest"
               >
                 {project.status === 'Finalizado' ? 'PROYECTO CERRADO' : `COMPLETAR: ${currentStageName}`}
               </button>
             )}

             {!canAdvance && !isQAStage && project.status !== 'Finalizado' && (
               <p className="text-[9px] text-rose-400 font-bold text-center animate-pulse">
                 SOLO PERSONAL ASIGNADO A "{currentStageName}" PUEDE AVANZAR ESTA FASE.
               </p>
             )}

             {user?.role === UserRole.QA_Opera && !canAdvance && isQAStage && (
               <p className="text-[9px] text-rose-400 font-bold text-center">
                 ESTA REVISIÓN NO LE HA SIDO ASIGNADA DIRECTAMENTE.
               </p>
             )}
          </div>

          {/* AUDITOR DE AI */}
          <div className="bg-white p-6 rounded-2xl border shadow-sm">
            <h3 className="flex items-center gap-2 font-black text-[10px] mb-4 text-blue-600 uppercase tracking-widest"><Icons.Ai /> AI Auditor (ISO 9001)</h3>
            <button 
              onClick={handleAudit}
              disabled={isAuditing}
              className="w-full py-3 bg-slate-100 text-slate-900 rounded-xl font-black text-[10px] hover:bg-slate-200 transition-all flex items-center justify-center gap-2 uppercase tracking-widest"
            >
              {isAuditing ? <div className="w-4 h-4 border-2 border-slate-400 border-t-slate-900 rounded-full animate-spin"></div> : 'VALIDAR CUMPLIMIENTO'}
            </button>
            {auditResult && (
              <div className="mt-4 p-4 bg-slate-50 rounded-xl border border-dashed space-y-3 animate-fadeIn">
                <div className="flex justify-between items-center">
                  <span className="font-black text-[9px] text-slate-400 uppercase">Audit Score:</span> 
                  <span className={`text-xl font-black ${auditResult.score > 80 ? 'text-emerald-600' : 'text-amber-600'}`}>{auditResult.score}%</span>
                </div>
                <div className="text-[9px] text-slate-500 font-bold uppercase leading-tight bg-white p-2 rounded-lg border border-slate-100">
                  Ref: {auditResult.isoClause}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

