import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, advanceProjectStage, updateBrief, processQA } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);
  const [deliveryLink, setDeliveryLink] = useState('');
  const [deliveryComment, setDeliveryComment] = useState('');
  const [isAuditing, setIsAuditing] = useState(false);
  const [auditResult, setAuditResult] = useState<any>(null);

  const roadmapStages = useMemo(() => {
    const stages = ["CUENTAS (Gestión)"];
    (project.areas_seleccionadas || []).forEach(area => {
      stages.push(area);
      stages.push(`REVISIÓN QA (${area})`);
    });
    stages.push("CUENTAS (Cierre)");
    stages.push("ADMINISTRACIÓN (Facturación)");
    return stages;
  }, [project.areas_seleccionadas]);

  const currentIdx = project.current_stage_index || 0;
  const currentStageName = roadmapStages[currentIdx];
  const isQAStage = currentStageName.includes('REVISIÓN QA');

  // Identificar si la etapa actual es una etapa de producción (donde el operativo debe entregar)
  const isProductionStage = currentIdx > 0 && currentIdx < roadmapStages.length - 2 && !isQAStage;

  const canOperate = useMemo(() => {
    if (!user) return false;
    if (user.role === UserRole.Admin) return true;

    if (isQAStage) {
      const isQaLider = user.role === UserRole.Correccion;
      const isQaOperaAssigned = user.role === UserRole.QA_Opera && project.asignaciones?.some(a => a.usuarioId === user.id);
      return isQaLider || isQaOperaAssigned;
    }

    if (isProductionStage) {
      const currentArea = roadmapStages[currentIdx];
      const isAreaLead = user.role === UserRole.Lider_Operativo && user.department === currentArea;
      const isDirectlyAssigned = project.asignaciones?.some(a => a.usuarioId === user.id);
      return isAreaLead || isDirectlyAssigned;
    }

    if (currentStageName.includes('CUENTAS')) return user.department === 'Cuentas';
    if (currentStageName.includes('ADMINISTRACIÓN')) return user.department === 'Finanzas';

    return false;
  }, [user, currentIdx, isQAStage, isProductionStage, currentStageName, project.asignaciones]);

  const handleDelivery = async () => {
    if (!deliveryLink || !deliveryComment) {
      alert("Para ISO 9001, es obligatorio adjuntar el link del material y un comentario de entrega.");
      return;
    }
    const fullComment = `ENTREGA TÉCNICA: ${deliveryComment} | Link: ${deliveryLink}`;
    await advanceProjectStage(project.id, fullComment);
    setDeliveryLink('');
    setDeliveryComment('');
  };

  const handleQAAction = async (approved: boolean) => {
    if (!approved && !qaFeedback) {
      setIsRejecting(true);
      return;
    }
    await processQA(project.id, approved, qaFeedback);
    setQaFeedback('');
    setIsRejecting(false);
  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn pb-20">
      {/* COLUMNA IZQUIERDA: CONTENIDO PRINCIPAL */}
      <div className="flex-1 space-y-6">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500 shadow-sm">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight">{project.id}</h1>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{project.empresa} - {project.producto}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${project.status === 'Finalizado' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>
              {project.status}
            </span>
          </div>
        </header>

        {/* PANEL DE ENTREGA (Solo para operativos en su turno) */}
        {isProductionStage && canOperate && project.status !== 'Finalizado' && (
          <div className="bg-blue-600 rounded-3xl p-8 text-white shadow-xl shadow-blue-200">
            <h3 className="font-black text-sm uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Icons.Plus /> Panel de Entrega Técnica
            </h3>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase mb-1 block opacity-70">URL del Material (Drive/Dropbox/Veeva)</label>
                <input 
                  type="text" 
                  value={deliveryLink}
                  onChange={e => setDeliveryLink(e.target.value)}
                  className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 outline-none focus:bg-white/20 transition-all font-medium text-sm placeholder:text-white/30"
                  placeholder="https://..."
                />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase mb-1 block opacity-70">Comentarios de Entrega</label>
                <textarea 
                  value={deliveryComment}
                  onChange={e => setDeliveryComment(e.target.value)}
                  className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 outline-none focus:bg-white/20 transition-all font-medium text-sm h-24 placeholder:text-white/30"
                  placeholder="Explique detalles técnicos de la entrega..."
                />
              </div>
              <button 
                onClick={handleDelivery}
                className="w-full py-4 bg-white text-blue-600 font-black rounded-xl hover:bg-slate-100 transition-all text-xs uppercase tracking-widest shadow-lg"
              >
                ENVIAR A REVISIÓN DE QA
              </button>
            </div>
          </div>
        )}

        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
              <Icons.Project /> Brief Maestro
            </h3>
            <button onClick={() => updateBrief(project.id, briefContent)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black rounded-lg hover:bg-slate-800 transition-all uppercase tracking-widest">
              Guardar Cambios
            </button>
          </div>
          <ReactQuill theme="snow" value={briefContent} onChange={setBriefContent} />
        </div>

        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad ISO 9001</h3>
          <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2">
            {project.comentarios.map(c => {
              const isQAFeedback = c.text.includes('RECHAZADO') || c.text.includes('APROBADO');
              return (
                <div key={c.id} className={`p-5 rounded-2xl text-xs border-l-4 transition-all ${
                  c.text.includes('RECHAZADO') ? 'bg-rose-50 border-rose-500' : 
                  c.text.includes('APROBADO') ? 'bg-emerald-50 border-emerald-500' :
                  c.isSystemEvent ? 'bg-slate-50 border-slate-300' : 'bg-white border-blue-400 shadow-sm'
                }`}>
                  <div className="flex justify-between items-center mb-3">
                    <span className="font-black uppercase text-[9px] text-slate-400">
                      {c.authorName} <span className="mx-1 text-slate-300">|</span> {new Date(c.createdAt).toLocaleString()}
                    </span>
                    {isQAFeedback && <span className="px-2 py-0.5 bg-white rounded text-[8px] font-black border uppercase">Audit Log</span>}
                  </div>
                  <p className={`text-slate-800 font-medium leading-relaxed ${isQAFeedback ? 'text-sm font-bold' : ''}`}>
                    {c.text}
                  </p>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* COLUMNA DERECHA: TIMELINE VERTICAL Y CONTROL */}
      <div className="w-full lg:w-80 space-y-6">
        {/* LÍNEA DE TIEMPO VERTICAL */}
        <div className="bg-white p-8 rounded-3xl border shadow-xl">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8 border-b pb-4">Ruta Dinámica ISO</h3>
          <div className="relative space-y-10">
            <div className="absolute top-0 left-[18px] w-0.5 h-full bg-slate-100 -z-0"></div>
            {roadmapStages.map((stage, idx) => {
              const isActive = idx === currentIdx;
              const isCompleted = idx < currentIdx;
              const isQA = stage.includes('REVISIÓN QA');

              return (
                <div key={idx} className="flex gap-6 items-start relative z-10">
                  <div className={`w-9 h-9 rounded-full flex items-center justify-center border-4 transition-all duration-500 shrink-0 ${
