      {isEditing && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-10 w-full max-w-md shadow-2xl animate-fadeIn border-t-8 border-blue-600">
            <h2 className="text-2xl font-black text-slate-900 mb-2">Configurar Usuario</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-8">Contrato de Dato ISO 9001</p>

            <form onSubmit={handleSave} className="space-y-5">
               <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Nombre Completo</label>
                  <input required value={isEditing.name} onChange={e => setIsEditing({...isEditing, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 transition-all font-bold text-sm" placeholder="Nombre completo" />
               </div>

               <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Username (ID)</label>
                    <input required value={isEditing.username} onChange={e => setIsEditing({...isEditing, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 transition-all font-mono text-xs font-bold" placeholder="usuario.id" />
                 </div>
                 <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Password</label>
                    <input required type="text" value={isEditing.password} onChange={e => setIsEditing({...isEditing, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 transition-all font-bold text-sm" placeholder="••••••••" />
                 </div>
               </div>

               <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Rol en Sistema</label>
                  <select value={isEditing.role} onChange={e => setIsEditing({...isEditing, role: e.target.value as UserRole})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 font-black text-xs appearance-none cursor-pointer">
                    <option value={UserRole.Admin}>Administrador</option>
                    <option value={UserRole.Cuentas_Lider}>Líder Cuentas</option>
                    <option value={UserRole.Cuentas_Opera}>Ejecutivo Cuentas</option>
                    <option value={UserRole.Lider_Operativo}>Líder Operativo</option>
                    <option value={UserRole.Operativo}>Operativo</option>
                    <option value={UserRole.Correccion}>Líder de QA</option>
                    <option value={UserRole.QA_Opera}>QA Operativo</option>
                  </select>
               </div>

               <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Departamento</label>
                  <select value={isEditing.department} onChange={e => setIsEditing({...isEditing, department: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 font-black text-xs appearance-none cursor-pointer">
                    {DEPARTMENTS.map(dept => <option key={dept} value={dept}>{dept.toUpperCase()}</option>)}
                  </select>
               </div>

               <div className="flex gap-4 pt-6">
                  <button type="button" onClick={() => setIsEditing(null)} className="flex-1 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-slate-600 transition-colors">Cerrar</button>
                  <button type="submit" className="flex-2 px-8 py-4 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all shadow-xl">Guardar Cambios</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersView;

import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, advanceProjectStage, updateBrief, processQA } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);
  const [deliveryLink, setDeliveryLink] = useState('');
  const [deliveryComment, setDeliveryComment] = useState('');
  const [isAuditing, setIsAuditing] = useState(false);
  const [auditResult, setAuditResult] = useState<any>(null);

  const roadmapStages = useMemo(() => {
    const stages = ["CUENTAS (Gestión)"];
    (project.areas_seleccionadas || []).forEach(area => {
      stages.push(area);
      stages.push(`REVISIÓN QA (${area})`);
    });
    stages.push("CUENTAS (Cierre)");
    stages.push("ADMINISTRACIÓN (Facturación)");
    return stages;
  }, [project.areas_seleccionadas]);

  const currentIdx = project.current_stage_index || 0;
  const currentStageName = roadmapStages[currentIdx];
  const isQAStage = currentStageName.includes('REVISIÓN QA');

  // Identificar si la etapa actual es de producción o gestión inicial (donde se puede entregar/enviar)
  const isProductionOrManagement = currentIdx < roadmapStages.length - 2 && !isQAStage;

  const canOperate = useMemo(() => {
    if (!user) return false;
    if (user.role === UserRole.Admin) return true;

    if (isQAStage) {
      const isQaLider = user.role === UserRole.Correccion;
      const isQaOperaAssigned = user.role === UserRole.QA_Opera && project.asignaciones?.some(a => a.usuarioId === user.id);
      return isQaLider || isQaOperaAssigned;
    }

    if (currentIdx > 0 && currentIdx < roadmapStages.length - 2 && !isQAStage) {
      const currentArea = roadmapStages[currentIdx];
      const isAreaLead = user.role === UserRole.Lider_Operativo && user.department === currentArea;
      const isDirectlyAssigned = project.asignaciones?.some(a => a.usuarioId === user.id);
      return isAreaLead || isDirectlyAssigned;
    }

    if (currentStageName.includes('CUENTAS')) return user.department === 'Cuentas' || user.role === UserRole.Cuentas_Lider || user.role === UserRole.Cuentas_Opera;
    if (currentStageName.includes('ADMINISTRACIÓN')) return user.department === 'Finanzas';

    return false;
  }, [user, currentIdx, isQAStage, currentStageName, project.asignaciones, roadmapStages]);

  const handleDelivery = async () => {
    const isInitial = currentIdx === 0;

    if (isInitial) {
        // En la fase inicial, el comentario y link son opcionales pero recomendados
        if (!confirm("¿Deseas finalizar el briefing y enviar el proyecto a la primera área de producción?")) return;
        const fullComment = deliveryLink || deliveryComment 
            ? `INICIO DE PRODUCCIÓN: ${deliveryComment} | Referencias: ${deliveryLink}` 
            : "INICIO DE PRODUCCIÓN: Briefing validado por Cuentas.";
        await advanceProjectStage(project.id, fullComment);
    } else {
        if (!deliveryLink || !deliveryComment) {
            alert("Para ISO 9001, es obligatorio adjuntar el link del material y un comentario de entrega.");
            return;
        }
        const fullComment = `ENTREGA TÉCNICA: ${deliveryComment} | Link: ${deliveryLink}`;
        await advanceProjectStage(project.id, fullComment);
    }

    setDeliveryLink('');
    setDeliveryComment('');
  };

  const handleQAAction = async (approved: boolean) => {
    if (!approved && !qaFeedback) {
      setIsRejecting(true);
      return;
    }
    await processQA(project.id, approved, qaFeedback);
    setQaFeedback('');
    setIsRejecting(false);
  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn pb-20">
      {/* COLUMNA IZQUIERDA: CONTENIDO PRINCIPAL */}
      <div className="flex-1 space-y-6">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500 shadow-sm">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight">{project.id}</h1>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{project.empresa} - {project.producto}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${project.status === 'Finalizado' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'}`}>
              {project.status}
            </span>
          </div>
        </header>

        {/* PANEL DE ENTREGA / GESTIÓN INICIAL */}
        {isProductionOrManagement && canOperate && project.status !== 'Finalizado' && (
          <div className="bg-blue-600 rounded-3xl p-8 text-white shadow-xl shadow-blue-200">
            <h3 className="font-black text-sm uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Icons.Plus /> {currentIdx === 0 ? 'Gestión de Inicio de Proyecto' : 'Panel de Entrega Técnica'}
            </h3>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase mb-1 block opacity-70">
                  {currentIdx === 0 ? 'Documentos de Referencia (Links)' : 'URL del Material Final'}
                </label>
                <input 
                  type="text" 
                  value={deliveryLink}
                  onChange={e => setDeliveryLink(e.target.value)}
                  className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 outline-none focus:bg-white/20 transition-all font-medium text-sm placeholder:text-white/30"
                  placeholder="https://..."
                />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase mb-1 block opacity-70">
                  {currentIdx === 0 ? 'Instrucciones para Producción' : 'Comentarios de Entrega'}
                </label>
                <textarea 
                  value={deliveryComment}
                  onChange={e => setDeliveryComment(e.target.value)}
                  className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 outline-none focus:bg-white/20 transition-all font-medium text-sm h-24 placeholder:text-white/30"
                  placeholder={currentIdx === 0 ? "Escriba instrucciones clave para las áreas operativas..." : "Explique detalles técnicos de la entrega..."}
                />
              </div>
              <button 
                onClick={handleDelivery}
                className="w-full py-4 bg-white text-blue-600 font-black rounded-xl hover:bg-slate-100 transition-all text-xs uppercase tracking-widest shadow-lg"
              >
                {currentIdx === 0 ? 'FINALIZAR BRIEFING Y ENVIAR A PRODUCCIÓN' : 'ENVIAR A REVISIÓN DE QA'}
              </button>
            </div>
          </div>
        )}

        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
              <Icons.Project /> Brief Maestro
            </h3>
            <button onClick={() => updateBrief(project.id, briefContent)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black rounded-lg hover:bg-slate-800 transition-all uppercase tracking-widest">
              Guardar Cambios
            </button>
          </div>
          <ReactQuill theme="snow" value={briefContent} onChange={setBriefContent} />
        </div>

        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad ISO 9001</h3>
          <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2">
            {project.comentarios.map(c => {
              const isQAFeedback = c.text.includes('RECHAZADO') || c.text.includes('APROBADO');
              const isDelivery = c.text.includes('ENTREGA TÉCNICA') || c.text.includes('INICIO DE PRODUCCIÓN');
              return (
                <div key={c.id} className={`p-5 rounded-2xl text-xs border-l-4 transition-all ${
                  c.text.includes('RECHAZADO') ? 'bg-rose-50 border-rose-500' : 
                  c.text.includes('APROBADO') ? 'bg-emerald-50 border-emerald-500' :
                  isDelivery ? 'bg-blue-50 border-blue-500' :
                  c.isSystemEvent ? 'bg-slate-50 border-slate-300' : 'bg-white border-blue-400 shadow-sm'
                }`}>
                  <div className="flex justify-between items-center mb-3">
                    <span className="font-black uppercase text-[9px] text-slate-400">
                      {c.authorName} <span className="mx-1 text-slate-300">|</span> {new Date(c.createdAt).toLocaleString()}
                    </span>
                    {(isQAFeedback || isDelivery) && <span className="px-2 py-0.5 bg-white rounded text-[8px] font-black border uppercase">Audit Log</span>}
                  </div>
                  <p className={`text-slate-800 font-medium leading-relaxed ${isQAFeedback || isDelivery ? 'text-sm font-bold' : ''}`}>
                    {c.text}
                  </p>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* COLUMNA DERECHA: TIMELINE VERTICAL Y CONTROL */}
      <div className="w-full lg:w-80 space-y-6">
        {/* LÍNEA DE TIEMPO VERTICAL */}
        <div className="bg-white p-8 rounded-3xl border shadow-xl">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8 border-b pb-4">Ruta Dinámica ISO</h3>
          <div className="relative space-y-10">
            <div className="absolute top-0 left-[18px] w-0.5 h-full bg-slate-100 -z-0"></div>
            {roadmapStages.map((stage, idx) => {
              const isActive = idx === currentIdx;
              const isCompleted = idx < currentIdx;
              const isQA = stage.includes('REVISIÓN QA');

              return (
                <div key={idx} className="flex gap-6 items-start relative z-10">
                  <div className={`w-9 h-9 rounded-full flex items-center justify-center border-4 transition-all duration-500 shrink-0 ${
                    isActive ? 'bg-blue-600 border-blue-100 shadow-lg scale-110' : 
                    isCompleted ? 'bg-emerald-500 border-emerald-50' : 'bg-slate-50 border-white'
                  }`}>
                    {isCompleted ? (
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>
                    ) : isQA ? (
                      <div className={isActive ? 'text-white' : 'text-slate-300'}><Icons.Ai /></div>
                    ) : (
                      <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-white animate-pulse' : 'bg-slate-300'}`}></div>
                    )}
                  </div>
                  <div>
                    <p className={`text-[10px] font-black uppercase tracking-tighter leading-tight ${isActive ? 'text-blue-600' : isCompleted ? 'text-emerald-600' : 'text-slate-400'}`}>
                      {stage}
                    </p>
                    {isActive && <p className="text-[9px] font-bold text-slate-400 mt-1 animate-pulse">EN CURSO</p>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* PANEL DE QA (Solo en etapas de QA y con permisos) */}
        {isQAStage && canOperate && project.status !== 'Finalizado' && (
          <div className="bg-slate-900 rounded-3xl p-6 text-white shadow-2xl border-t-4 border-amber-500">
            <h3 className="font-black text-[10px] uppercase tracking-widest text-amber-500 mb-4 flex items-center gap-2">
              <Icons.Ai /> Control de Calidad
            </h3>
            <div className="space-y-4">
              <textarea 
                placeholder="Feedback técnico detallado..."
                className={`w-full bg-white/10 border rounded-xl p-4 text-xs outline-none font-medium h-32 transition-all ${isRejecting ? 'border-rose-500 ring-2 ring-rose-500/20' : 'border-white/20'}`}
                value={qaFeedback}
                onChange={(e) => setQaFeedback(e.target.value)}
              />
              {isRejecting && (
                <p className="text-[9px] font-black text-rose-400 uppercase text-center animate-bounce">
                  Comentario obligatorio para rechazar
                </p>
              )}
              <div className="grid grid-cols-1 gap-3">
                <button 
                  onClick={() => handleQAAction(true)}
                  className="py-3 bg-emerald-600 text-white font-black text-[10px] rounded-xl hover:bg-emerald-700 transition-all uppercase tracking-widest"
                >APROBAR ETAPA</button>
                <button 
                  onClick={() => handleQAAction(false)}
                  className="py-3 bg-rose-600 text-white font-black text-[10px] rounded-xl hover:bg-rose-700 transition-all uppercase tracking-widest"
                >RECHAZAR Y DEVOLVER</button>
              </div>
            </div>
          </div>
        )}

        {/* AI AUDITOR */}
        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <h3 className="flex items-center gap-2 font-black text-[10px] mb-4 text-blue-600 uppercase tracking-widest"><Icons.Ai /> AI Auditor</h3>
          <button 
            onClick={handleAudit}
            disabled={isAuditing}
            className="w-full py-3 bg-slate-50 text-slate-900 rounded-xl font-black text-[10px] hover:bg-slate-100 transition-all flex items-center justify-center gap-2 uppercase tracking-widest border"
          >
            {isAuditing ? <div className="w-4 h-4 border-2 border-slate-400 border-t-slate-900 rounded-full animate-spin"></div> : 'Audit Realtime'}
          </button>
          {auditResult && (
            <div className="mt-4 p-4 bg-blue-50/30 rounded-2xl border border-blue-100 space-y-3 animate-fadeIn">
              <div className="flex justify-between items-center">
                <span className="font-black text-[9px] text-slate-400 uppercase">ISO Score:</span> 
                <span className={`text-xl font-black ${auditResult.score > 80 ? 'text-emerald-600' : 'text-amber-600'}`}>{auditResult.score}%</span>
              </div>
              <p className="text-[9px] text-blue-800 font-bold leading-tight">{auditResult.findings[0]}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProjectDetail;

import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, advanceProjectStage, updateBrief, processQA } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);
  const [deliveryLink, setDeliveryLink] = useState('');
  const [deliveryComment, setDeliveryComment] = useState('');
  const [isAuditing, setIsAuditing] = useState(false);
  const [auditResult, setAuditResult] = useState<any>(null);

  const roadmapStages = useMemo(() => {
    const stages = ["CUENTAS (Gestión)"];
    (project.areas_seleccionadas || []).forEach(area => {
      stages.push(area);
      stages.push(`REVISIÓN QA (${area})`);
    });
    stages.push("CUENTAS (Cierre)");
    stages.push("ADMINISTRACIÓN (Facturación)");
    return stages;
  }, [project.areas_seleccionadas]);

  const currentIdx = project.current_stage_index || 0;
  const currentStageName = roadmapStages[currentIdx];
  const nextStageName = roadmapStages[currentIdx + 1];
  const isQAStage = currentStageName.includes('REVISIÓN QA');

  // Identificar si la etapa actual es de producción o gestión inicial
  const isInitialStage = currentIdx === 0;
  const isProductionStage = currentIdx > 0 && currentIdx < roadmapStages.length - 2 && !isQAStage;

  const canOperate = useMemo(() => {
    if (!user) return false;
    if (user.role === UserRole.Admin) return true;

    if (isQAStage) {
      const isQaLider = user.role === UserRole.Correccion;
      const isQaOperaAssigned = user.role === UserRole.QA_Opera && project.asignaciones?.some(a => a.usuarioId === user.id);
      return isQaLider || isQaOperaAssigned;
    }

    if (isProductionStage) {
      const currentArea = roadmapStages[currentIdx];
      const isAreaLead = user.role === UserRole.Lider_Operativo && user.department === currentArea;
      const isDirectlyAssigned = project.asignaciones?.some(a => a.usuarioId === user.id);
      return isAreaLead || isDirectlyAssigned;
    }

    if (isInitialStage) return user.department === 'Cuentas' || user.role === UserRole.Cuentas_Lider || user.role === UserRole.Cuentas_Opera;
    if (currentStageName.includes('CUENTAS')) return user.department === 'Cuentas';
    if (currentStageName.includes('ADMINISTRACIÓN')) return user.department === 'Finanzas';

    return false;
  }, [user, currentIdx, isQAStage, isProductionStage, isInitialStage, currentStageName, project.asignaciones, roadmapStages]);

  const handleAdvance = async () => {
    if (!canOperate) return;

    let comment = "";
    if (isInitialStage) {
      comment = "Briefing validado y envío a producción.";
    } else {
      if (!deliveryLink && !isQAStage) {
        alert("Por favor, incluya al menos el link del material antes de completar la etapa.");
        return;
      }
      comment = `Entrega: ${deliveryComment} | Link: ${deliveryLink}`;
    }

    try {
      await advanceProjectStage(project.id, comment);
      alert(`Éxito: ODT enviada a ${nextStageName}`);
      setDeliveryLink('');
      setDeliveryComment('');
    } catch (e) {
      alert("Error al procesar el avance.");
    }
  };

  const handleQAAction = async (approved: boolean) => {
    if (!approved && !qaFeedback) {
      setIsRejecting(true);
      return;
    }
    const actionLabel = approved ? 'APROBADO' : 'RECHAZADO';
    await processQA(project.id, approved, qaFeedback);
    alert(`QA Gate Finalizado: Proyecto ${actionLabel}`);
    setQaFeedback('');
    setIsRejecting(false);
  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  // El botón principal cambia según la etapa
  const getButtonLabel = () => {
    if (isInitialStage) return "FINALIZAR BRIEFING Y ENVIAR A PRODUCCIÓN";
    if (nextStageName?.includes('REVISIÓN QA')) return "ENVIAR A CORRECCIÓN";
    return "COMPLETAR ETAPA ACTUAL";
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn pb-20">
      {/* COLUMNA IZQUIERDA: CONTENIDO PRINCIPAL */}
      <div className="flex-1 space-y-6">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500 shadow-sm">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <div>
