                         <span className={`text-xs font-bold uppercase ${isAssignedToMe ? 'text-blue-700' : 'text-slate-600'}`}>
                           {teamMembers.find(m => m.id === currentAssignment?.usuarioId)?.name || 'SIN RESPONSABLE'}
                         </span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      {/* Fixed line 126: Comparison of Project['status'] with 'En Revisión QA' */}
                      <span className={`text-[9px] font-black px-2 py-1 rounded uppercase tracking-tighter ${p.status === 'En Revisión QA' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-500'}`}>
                        {p.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                       <select 
                         className={`border-none rounded-lg px-3 py-1.5 text-[10px] font-black uppercase tracking-widest cursor-pointer transition-all outline-none ${
                           isAssignedToMe ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-slate-900 text-white hover:bg-slate-800'
                         }`} 
                         onChange={(e) => {
                           if (e.target.value) delegateProject(p.id, leaderArea, e.target.value);
                         }}
                         value={currentAssignment?.usuarioId || ''}
                       >
                         <option value="">ASIGNAR A...</option>
                         {teamMembers.map(m => (
                           <option key={m.id} value={m.id}>
                             {m.id === user?.id ? `ASIGNARME A MÍ` : m.name.toUpperCase()}
                           </option>
                         ))}
                       </select>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

