import React, { useState, useMemo } from 'react';
import ReactQuill from 'react-quill';
import { useODT } from './ODTContext';
import { Project, UserRole } from './types';
import { Icons } from './constants';
import { auditProjectISO } from './services/geminiService';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  const { user, advanceProjectStage, updateBrief, processQA, deleteProject } = useODT();
  const [briefContent, setBriefContent] = useState(project.brief);
  const [qaFeedback, setQaFeedback] = useState('');
  const [isRejecting, setIsRejecting] = useState(false);
  const [deliveryLink, setDeliveryLink] = useState('');
  const [deliveryComment, setDeliveryComment] = useState('');
  const [validationError, setValidationError] = useState<string | null>(null);
  const [isAuditing, setIsAuditing] = useState(false);
  const [auditResult, setAuditResult] = useState<any>(null);

  const roadmapStages = useMemo(() => {
    const stages = ["CUENTAS (Gestión)"];
    (project.areas_seleccionadas || []).forEach(area => {
      stages.push(area);
      stages.push(`REVISIÓN QA (${area})`);
    });
    stages.push("CUENTAS (Cierre)");
    stages.push("ADMINISTRACIÓN (Facturación)");
    return stages;
  }, [project.areas_seleccionadas]);

  const currentIdx = project.current_stage_index || 0;
  const currentStageName = roadmapStages[currentIdx];
  const nextStageName = roadmapStages[currentIdx + 1];

  const isQAStage = currentStageName.includes('REVISIÓN QA');
  const isCierreStage = currentStageName === "CUENTAS (Cierre)";
  const isLocked = currentStageName.includes('ADMINISTRACIÓN') || project.status === 'Finalizado';
  const isAdmin = user?.role === UserRole.Admin;

  const isInitialStage = currentIdx === 0;
  const isProductionStage = currentIdx > 0 && !isQAStage && !isCierreStage && !isLocked;

  const canOperate = useMemo(() => {
    if (!user || isLocked) return false;
    if (isAdmin) return true;

    if (isQAStage) {
      if (project.status !== 'En Revisión QA') return false;
      const isQaLider = user.role === UserRole.Correccion;
      const isQaOperaAssigned = user.role === UserRole.QA_Opera && project.asignaciones?.some(a => a.usuarioId === user.id);
      return isQaLider || isQaOperaAssigned;
    }

    if (isProductionStage) {
      const currentArea = roadmapStages[currentIdx];
      const isAreaLead = user.role === UserRole.Lider_Operativo && user.department === currentArea;
      const isDirectlyAssigned = project.asignaciones?.some(a => a.usuarioId === user.id);
      return isAreaLead || isDirectlyAssigned;
    }

    if (isInitialStage || isCierreStage) return user.department === 'Cuentas' || user.role === UserRole.Cuentas_Lider;

    return false;
  }, [user, currentIdx, isQAStage, isProductionStage, isInitialStage, isCierreStage, isLocked, project.asignaciones, project.status, roadmapStages, isAdmin]);

  const handleAdvance = async () => {
    if (!canOperate) return;
    setValidationError(null);

    if (isProductionStage && (!deliveryLink.trim() || !deliveryComment.trim())) {
      setValidationError("Error: Link y Comentarios son obligatorios para enviar a QA.");
      return;
    }

    try {
      if (isInitialStage) {
        await advanceProjectStage(project.id, "Briefing validado.");
      } else if (isCierreStage) {
        await advanceProjectStage(project.id, "Proyecto listo para facturación.");
        alert("ODT enviada a ADMINISTRACIÓN exitosamente.");
      } else {
        await advanceProjectStage(project.id, "", { link: deliveryLink, comment: deliveryComment });
        alert('Material enviado exitosamente a Corrección');
      }

      setDeliveryLink('');
      setDeliveryComment('');
      setValidationError(null);
    } catch (e) {
      alert("Error de conexión con Firebase.");
    }
  };

  const handleQAAction = async (approved: boolean) => {
    if (!approved && !qaFeedback.trim()) {
      setIsRejecting(true);
      return;
    }
    await processQA(project.id, approved, qaFeedback);
    alert(`Control de Calidad: Proyecto ${approved ? 'APROBADO' : 'DEVUELTO A PRODUCCIÓN'}`);
    setQaFeedback('');
    setIsRejecting(false);
  };

  const handleDeleteODT = async () => {
    if (confirm(`¿Está seguro de eliminar permanentemente la ODT ${project.id}? Esta acción no se puede deshacer.`)) {
      await deleteProject(project.id);
      alert("ODT eliminada del sistema.");
      onBack();
    }
  };

  const getButtonLabel = () => {
    if (isInitialStage) return "INICIAR PRODUCCIÓN";
    if (isCierreStage) return "ENVIAR A FACTURACIÓN";
    if (nextStageName?.includes('REVISIÓN QA')) return "ENVIAR A CORRECCIÓN";
    return "COMPLETAR ETAPA";
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 animate-fadeIn pb-20">
      {/* COLUMNA IZQUIERDA: CONTENIDO */}
      <div className="flex-1 space-y-6">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 bg-white border rounded-xl hover:bg-slate-50 transition-all text-slate-500 shadow-sm">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <div>
              <h1 className="text-2xl font-black text-slate-900 tracking-tight">{project.id}</h1>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{project.empresa} - {project.producto}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
              project.status === 'En Revisión QA' ? 'bg-amber-100 text-amber-700' : 
              project.status === 'Finalizado' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
            }`}>
              {project.status}
            </span>
          </div>
        </header>

        {/* MURO DE LA ODT: REPOSITORIO DE ENTREGABLES */}
        <div className="bg-slate-900 rounded-3xl p-6 text-white shadow-2xl">
          <h3 className="font-black text-[10px] uppercase tracking-widest text-blue-400 mb-6 flex items-center gap-2">
            <Icons.Ai /> Repositorio de Entregables (Muro de la ODT)
          </h3>
          <div className="space-y-4">
            {(!project.materialesEntregados || project.materialesEntregados.length === 0) ? (
              <p className="text-slate-500 text-[10px] font-bold uppercase text-center py-4 border border-dashed border-slate-700 rounded-2xl italic">No hay entregas registradas aún.</p>
            ) : (
              project.materialesEntregados.map((m) => (
                <div key={m.id} className="bg-white/5 border border-white/10 p-4 rounded-2xl flex items-center justify-between gap-4">
                  <div className="min-w-0 flex-1">
                    <p className="text-[9px] font-black text-blue-400 uppercase tracking-tighter mb-1">{m.area} • {m.authorName}</p>
                    <p className="text-xs font-bold truncate mb-1">{m.comment}</p>
                    <p className="text-[8px] text-slate-500 font-medium">{new Date(m.createdAt).toLocaleString()}</p>
                  </div>
                  <a href={m.link} target="_blank" rel="noopener noreferrer" className="px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded-xl text-[10px] font-black uppercase transition-all whitespace-nowrap">Ver Archivo</a>
                </div>
              ))
            )}
          </div>
        </div>

        {/* BRIEF MAESTRO */}
        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-slate-800 text-lg flex items-center gap-2">
              <Icons.Project /> Brief Maestro
            </h3>
            {canOperate && !isLocked && (
              <button onClick={() => updateBrief(project.id, briefContent)} className="px-4 py-2 bg-slate-900 text-white text-[10px] font-black rounded-lg hover:bg-slate-800 transition-all uppercase tracking-widest">
                Guardar Cambios
              </button>
            )}
          </div>
          <ReactQuill theme="snow" value={briefContent} onChange={setBriefContent} readOnly={!canOperate || isLocked} />
        </div>

        {/* FORMULARIO DE ENTREGA */}
        {isProductionStage && canOperate && (
          <div className={`bg-white rounded-2xl p-6 border-2 transition-all ${validationError ? 'border-rose-500 bg-rose-50/30' : 'border-dashed border-slate-200'}`}>
            <h4 className="font-black text-[10px] uppercase text-slate-500 tracking-[0.2em] mb-4">Insumos de Entrega (Requerido para QA)</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input 
                type="text" 
                placeholder="Link del material final..."
                value={deliveryLink}
                onChange={e => setDeliveryLink(e.target.value)}
                className="w-full bg-slate-50 border rounded-xl px-4 py-3 text-xs outline-none focus:ring-2 focus:ring-blue-500 font-medium"
              />
              <input 
                type="text" 
                placeholder="Comentarios de esta versión..."
                value={deliveryComment}
                onChange={e => setDeliveryComment(e.target.value)}
                className="w-full bg-slate-50 border rounded-xl px-4 py-3 text-xs outline-none focus:ring-2 focus:ring-blue-500 font-medium"
              />
            </div>
            {validationError && (
              <p className="text-[10px] text-rose-600 font-black mt-3 flex items-center gap-2">
                 <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                 {validationError}
              </p>
            )}
          </div>
        )}

        {/* TRAZABILIDAD ISO */}
        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <h3 className="font-black text-slate-400 text-[10px] uppercase mb-6 tracking-widest border-b pb-2">Logs de Trazabilidad ISO 9001</h3>
          <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2">
            {project.comentarios.map(c => {
              return (
                <div key={c.id} className={`p-4 rounded-2xl text-xs border-l-4 ${
                  c.text.includes('RECHAZADO') ? 'bg-rose-50 border-rose-500' : 
                  c.text.includes('APROBADO') ? 'bg-emerald-50 border-emerald-500' :
                  c.isSystemEvent ? 'bg-slate-50 border-slate-300' : 'bg-white border-blue-400 shadow-sm'
                }`}>
                  <p className="font-black uppercase text-[8px] text-slate-400 mb-1">{c.authorName} • {new Date(c.createdAt).toLocaleString()}</p>
                  <p className="text-slate-700 font-medium">{c.text}</p>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* COLUMNA DERECHA */}
      <div className="w-full lg:w-80 space-y-6">

        {!isQAStage && !isLocked && (
          <div className="bg-white p-6 rounded-3xl border shadow-xl border-t-8 border-blue-600">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Acción de Etapa</p>
            <button 
              onClick={handleAdvance}
              disabled={!canOperate}
              className={`w-full py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg transition-all ${
                canOperate ? 'bg-blue-600 text-white hover:bg-blue-700 hover:scale-[1.02]' : 'bg-slate-100 text-slate-300 cursor-not-allowed'
              }`}
            >
              {getButtonLabel()}
            </button>
            {!canOperate && (
              <p className="text-[9px] text-rose-500 font-bold mt-3 text-center uppercase tracking-tighter italic">
                {isLocked ? 'ODT BLOQUEADA POR ADMINISTRACIÓN' : `Solo el responsable de ${currentStageName} puede avanzar.`}
              </p>
            )}
          </div>
        )}

        {isQAStage && canOperate && (
          <div className="bg-slate-900 rounded-3xl p-6 text-white shadow-2xl border-t-4 border-amber-500">
            <h3 className="font-black text-[10px] uppercase tracking-widest text-amber-500 mb-4 flex items-center gap-2">
              <Icons.Ai /> QA Gate Control
            </h3>
            <textarea 
              placeholder="Feedback técnico..."
              className={`w-full bg-white/10 border rounded-xl p-4 text-xs outline-none font-medium h-24 mb-4 ${isRejecting ? 'border-rose-500' : 'border-white/20'}`}
              value={qaFeedback}
              onChange={(e) => setQaFeedback(e.target.value)}
            />
            <div className="grid grid-cols-1 gap-2">
              <button onClick={() => handleQAAction(true)} className="py-3 bg-emerald-600 text-white font-black text-[10px] rounded-xl hover:bg-emerald-700 uppercase tracking-widest">APROBAR VERSIÓN</button>
              <button onClick={() => handleQAAction(false)} className="py-3 bg-rose-600 text-white font-black text-[10px] rounded-xl hover:bg-rose-700 uppercase tracking-widest">RECHAZAR Y DEVOLVER</button>
            </div>
          </div>
        )}

        <div className="bg-white p-6 rounded-3xl border shadow-sm">
          <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Ruta de Calidad ISO</h3>
          <div className="relative space-y-8">
            <div className="absolute top-0 left-[14px] w-0.5 h-full bg-slate-100 -z-0"></div>
            {roadmapStages.map((stage, idx) => {
              const isActive = idx === currentIdx;
              const isCompleted = idx < currentIdx;
              return (
                <div key={idx} className="flex gap-4 items-start relative z-10">
                  <div className={`w-7 h-7 rounded-full flex items-center justify-center border-2 transition-all shrink-0 ${
                    isActive ? 'bg-blue-600 border-blue-100 scale-110 shadow-lg' : 
                    isCompleted ? 'bg-emerald-500 border-emerald-50' : 'bg-slate-50 border-white'
                  }`}>
                    {isCompleted && <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>}
                    {isActive && <div className="w-1.5 h-1.5 bg-white rounded-full animate-pulse"></div>}
                  </div>
                  <p className={`text-[10px] font-black uppercase tracking-tighter leading-tight mt-1 ${isActive ? 'text-blue-600' : isCompleted ? 'text-emerald-600' : 'text-slate-300'}`}>
                    {stage}
                  </p>
                </div>
              );
            })}
          </div>
        </div>

        {/* BOTÓN DE ELIMINACIÓN PARA ADMIN */}
        {isAdmin && (
          <div className="pt-6 border-t border-dashed border-slate-200">
            <button 
              onClick={handleDeleteODT}
              className="w-full py-3 bg-rose-50 text-rose-600 font-black text-[10px] uppercase tracking-widest rounded-xl border border-rose-100 hover:bg-rose-600 hover:text-white transition-all flex items-center justify-center gap-2"
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
              ELIMINAR ODT PERMANENTEMENTE
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProjectDetail;

import React, { useState, useEffect } from 'react';
import { useODT } from './ODTContext';
import { UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ref, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';

const Login: React.FC = () => {
  const { login } = useODT();
  const [u, setU] = useState('');
  const [p, setP] = useState('');
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  useEffect(() => {
    if (db) {
      const testRef = ref(db, 'conexion_test');
      set(testRef, { fecha: new Date().toISOString() }).catch(() => {});
    }
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);
    const result = await login(u, p);
    if (!result.success) {
      setErrorMsg(result.error || 'Error al iniciar sesión.');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-900 p-6">
      <div className="w-full max-w-md animate-fadeIn">
        <div className="bg-white rounded-2xl shadow-2xl overflow-hidden">
          <div className="bg-blue-600 p-8 text-center">
            <div className="w-16 h-16 bg-white/20 rounded-2xl mx-auto flex items-center justify-center text-white text-3xl font-black mb-4">ISO</div>
            <h1 className="text-white text-2xl font-bold tracking-tight">ODT Manager</h1>
            <p className="text-blue-100 text-sm mt-1">Gestión Normativa APC</p>
          </div>
          <form className="p-8 space-y-6" onSubmit={handleSubmit}>
            {errorMsg && (
              <div className="p-3 bg-rose-50 text-rose-600 text-xs font-bold rounded-lg border border-rose-100 flex items-center gap-2">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                {errorMsg}
              </div>
            )}
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Usuario</label>
              <input value={u} onChange={e => setU(e.target.value)} type="text" className="w-full px-4 py-3 bg-slate-50 border rounded-xl outline-none transition-all font-medium" placeholder="ID de Usuario" required />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Contraseña</label>
              <input value={p} onChange={e => setP(e.target.value)} type="password" className="w-full px-4 py-3 bg-slate-50 border rounded-xl outline-none transition-all font-medium" placeholder="••••••••" required />
            </div>
            <button type="submit" className="w-full py-4 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition-all shadow-xl">
              Entrar al Sistema
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export const AppRouter: React.FC<{ renderView: (view: ViewState) => React.ReactNode }> = ({ renderView }) => {
  const { user, logout } = useODT();
  const [view, setView] = useState<ViewState>('dashboard');

  useEffect(() => {
    if (!user) return;
    // Si es Líder de Corrección, ahora va al Dashboard de Líder por defecto para gestionar su área
    if (user.role === UserRole.Correccion) setView('leader-dashboard');
    else if (user.role === UserRole.QA_Opera) setView('qa-box');
    else if (user.department === 'Finanzas') setView('finances');
    else if (user.role === UserRole.Lider_Operativo) setView('leader-dashboard');
    else if (user.role === UserRole.Operativo) setView('my-projects');
    else if (user.role === UserRole.Cuentas_Opera || user.role === UserRole.Cuentas_Lider) setView('clients');
    else setView('dashboard');
  }, [user]);

  if (!user) return <Login />;

  const canSee = (roles: UserRole[]) => roles.includes(user.role) || user.role === UserRole.Admin;

  return (
    <div className="flex min-h-screen bg-slate-50">
      <aside className="w-64 bg-slate-900 fixed h-full p-6 flex flex-col gap-8 shadow-2xl z-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl">ISO</div>
          <h2 className="text-white font-bold tracking-tighter">ODT Manager</h2>
        </div>
        <nav className="flex flex-col gap-2 flex-1">
          {canSee([UserRole.Admin, UserRole.Cuentas_Lider]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Adm." active={view === 'dashboard'} onClick={() => setView('dashboard')} />}
          {canSee([UserRole.Lider_Operativo, UserRole.Correccion]) && <SidebarItem icon={<Icons.Dashboard />} label="Dashboard Lider" active={view === 'leader-dashboard'} onClick={() => setView('leader-dashboard')} />}
          {canSee([UserRole.Cuentas_Opera, UserRole.Cuentas_Lider, UserRole.Admin]) && <SidebarItem icon={<Icons.Clients />} label="Clientes / Archivo" active={view === 'clients'} onClick={() => setView('clients')} />}
          {canSee([UserRole.Operativo, UserRole.Lider_Operativo, UserRole.Cuentas_Lider, UserRole.Admin, UserRole.QA_Opera]) && <SidebarItem icon={<Icons.Project />} label="Bandeja Operativa" active={view === 'my-projects'} onClick={() => setView('my-projects')} />}
          {canSee([UserRole.Correccion, UserRole.Admin, UserRole.Cuentas_Lider, UserRole.QA_Opera]) && <SidebarItem icon={<Icons.Ai />} label="Caja de QA" active={view === 'qa-box'} onClick={() => setView('qa-box')} />}
          {(user.department === 'Finanzas' || user.role === UserRole.Admin || user.role === UserRole.Cuentas_Lider) ? <SidebarItem icon={<Icons.Clients />} label="Facturación" active={view === 'finances'} onClick={() => setView('finances')} /> : null}
          {user.role === UserRole.Admin && <SidebarItem icon={<Icons.Users />} label="Usuarios" active={view === 'users'} onClick={() => setView('users')} />}
        </nav>
        <div className="p-4 bg-slate-800/50 rounded-xl border border-slate-700/50">
          <p className="text-xs font-bold text-white truncate">{user.name}</p>
          <p className="text-[10px] text-slate-500 font-bold uppercase truncate">{user.role}</p>
          <button onClick={logout} className="w-full mt-4 py-2 text-[10px] uppercase font-bold text-slate-400 hover:text-white border border-slate-700 rounded-md transition-colors">Salir</button>
        </div>
      </aside>
      <main className="flex-1 ml-64 p-8">{renderView(view)}</main>
    </div>
  );
};

const SidebarItem: React.FC<{ icon: any, label: string, active: boolean, onClick: () => void }> = ({ icon: Icon, label, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${active ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
    {typeof Icon === 'function' ? <Icon /> : Icon} <span className="font-medium text-sm">{label}</span>
  </button>
);

import React, { useMemo, useState } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Project } from './types';

const LeaderDashboard: React.FC = () => {
  const { user, projects, users, checkSLA, delegateProject } = useODT();
  const [memberFilter, setMemberFilter] = useState('all');

  const leaderArea = useMemo(() => {
    // Si el departamento es QA, el líder puede delegar revisiones
    if (user?.department === 'QA' || user?.role === UserRole.Correccion) return 'QA';
    if (user?.department === 'Creativo') return 'Creativo';
    if (user?.department === 'Diseño') return 'Diseño';
    if (user?.department === 'Digital') return 'Digital';
    // Fallback dinámico para otros departamentos
    return user?.department || '';
  }, [user]);

  const teamMembers = useMemo(() => {
    if (!user) return [];
    // Incluimos a todos los miembros del departamento, incluido el propio líder
    return users.filter(u => u.department === user.department);
  }, [user, users]);

  const areaProjects = useMemo(() => {
    if (!leaderArea) return [];

    let filtered: Project[] = [];

    // Si es Líder de QA, ve todos los proyectos que están en etapa de revisión QA, sin importar el área de origen
    if (leaderArea === 'QA' || user?.role === UserRole.Correccion) {
      filtered = projects.filter(p => p.status === 'En Revisión QA' || p.etapa_actual?.includes('REVISIÓN QA'));
    } else {
      // Líderes operativos ven proyectos de su área ISO
      filtered = projects.filter(p => p.areas_seleccionadas?.includes(leaderArea));
    }

    if (memberFilter !== 'all') {
      filtered = filtered.filter(p => p.asignaciones?.some(a => a.usuarioId === memberFilter));
    }

    return filtered;
  }, [projects, leaderArea, memberFilter, user]);

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex justify-between items-center border-b pb-6">
        <div>
          <h1 className="text-2xl font-black uppercase tracking-tight">Control de Área: {user?.department || 'CALIDAD'}</h1>
          <p className="text-sm text-slate-500 font-bold uppercase tracking-widest mt-1">Supervisión Técnica Operativa (ISO 9001)</p>
        </div>
        <div className="flex flex-col items-end">
          <label className="text-[9px] font-black text-slate-400 uppercase mb-1 mr-1">Filtrar por Colaborador</label>
          <select className="bg-white border rounded-xl px-4 py-2 text-xs font-bold outline-none shadow-sm focus:ring-2 focus:ring-blue-500" value={memberFilter} onChange={(e) => setMemberFilter(e.target.value)}>
            <option value="all">TODO EL EQUIPO</option>
            {teamMembers.map(m => <option key={m.id} value={m.id}>{m.id === user?.id ? `YO (${m.name.toUpperCase()})` : m.name.toUpperCase()}</option>)}
          </select>
        </div>
      </header>

      {/* Tarjetas de Carga del Equipo */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {teamMembers.map(m => {
          const load = projects.filter(p => p.asignaciones?.some(a => a.usuarioId === m.id) && p.status !== 'Finalizado').length;
          const isMe = m.id === user?.id;

          return (
            <div key={m.id} className={`p-5 rounded-2xl border transition-all shadow-sm hover:shadow-md ${isMe ? 'bg-blue-50/50 border-blue-200' : 'bg-white border-slate-100'}`}>
              <div className="flex justify-between items-start mb-3">
                <p className={`text-xs font-black truncate pr-2 ${isMe ? 'text-blue-700' : 'text-slate-800'}`}>
                  {isMe ? 'Mi Carga (Líder)' : m.name}
                </p>
                <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase ${
                  m.role.includes('Lider') || m.role === UserRole.Correccion ? 'bg-blue-600 text-white' :
                  m.role === UserRole.QA_Opera ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-500'
                }`}>
                  {m.role.includes('Lider') || m.role === UserRole.Correccion ? 'LÍDER' : m.role === UserRole.QA_Opera ? 'QA' : 'OP'}
                </span>
              </div>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">Carga: {load} ODTs Activas</p>
              <div className="w-full bg-slate-200/50 h-2 rounded-full mt-3 overflow-hidden border border-slate-100">
                <div 
                  className={`h-full transition-all duration-500 ${load > 5 ? 'bg-rose-500' : load > 3 ? 'bg-amber-500' : 'bg-blue-500'}`} 
                  style={{width: `${Math.min((load/8)*100, 100)}%`}}
                ></div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Tabla de Gestión de ODTs */}
      <div className="bg-white rounded-3xl border border-slate-100 shadow-xl overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-400 uppercase text-[10px] font-black tracking-widest">
            <tr>
              <th className="px-6 py-5">ODT / Empresa</th>
              <th className="px-6 py-5">Responsable Asignado</th>
              <th className="px-6 py-5">Estado de Fase</th>
              <th className="px-6 py-5 text-right">Delegar Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {areaProjects.length === 0 ? (
              <tr>
                <td colSpan={4} className="px-6 py-10 text-center text-slate-300 italic font-medium uppercase text-[10px] tracking-widest">No hay proyectos activos requiriendo gestión en esta área.</td>
              </tr>
            ) : (
              areaProjects.map(p => {
                // Para el Líder de QA, buscamos la asignación en el área 'QA'
                const currentAssignmentArea = (user?.role === UserRole.Correccion || user?.department === 'QA') ? 'QA' : leaderArea;
                const currentAssignment = p.asignaciones?.find(a => a.area === currentAssignmentArea);
                const isAssignedToMe = currentAssignment?.usuarioId === user?.id;

                return (
                  <tr key={p.id} className={`hover:bg-slate-50/80 transition-colors ${isAssignedToMe ? 'bg-blue-50/20' : ''}`}>
