  const ROLE_LABELS: Record<string, string> = {
    [UserRole.Admin]: 'Administrador',
    [UserRole.Cuentas_Lider]: 'Líder Cuentas',
    [UserRole.Cuentas_Opera]: 'Ejecutivo Cuentas',
    [UserRole.Lider_Operativo]: 'Líder Operativo',
    [UserRole.Operativo]: 'Operativo',
    [UserRole.Correccion]: 'Líder de QA',
    [UserRole.QA_Opera]: 'QA Operativo'
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestión de Usuarios</h1>
          <p className="text-slate-500 font-medium text-sm italic">Estructura Oficial APC - Protocolo ISO 9001</p>
        </div>
        <div className="flex gap-3">
          <button 
            disabled={isSeeding}
            onClick={seedTestUsers}
            className="bg-slate-100 text-slate-600 px-6 py-3 rounded-xl font-black text-xs hover:bg-slate-200 transition-all flex items-center gap-2"
          >
            {isSeeding ? 'GENERANDO...' : 'RE-SEMBRAR ESTRUCTURA APC'}
          </button>
          <button 
            onClick={() => setIsEditing({ name: '', username: '', password: '', department: 'Cuentas', role: UserRole.Cuentas_Opera, active: true })}
            className="bg-blue-600 text-white px-6 py-3 rounded-xl font-black text-xs hover:bg-blue-700 transition-all shadow-lg flex items-center gap-2"
          >
            <Icons.Plus /> NUEVO USUARIO
          </button>
        </div>
      </header>

      <div className="bg-white rounded-3xl border border-slate-100 shadow-xl overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
            <tr>
              <th className="px-6 py-5">Colaborador</th>
              <th className="px-6 py-5">ID (Username)</th>
              <th className="px-6 py-5">Departamento</th>
              <th className="px-6 py-5">Rol</th>
              <th className="px-6 py-5">Estatus</th>
              <th className="px-6 py-5 text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {users.map(u => (
              <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-black text-slate-800">{u.name}</td>
                <td className="px-6 py-4 font-mono text-xs font-bold text-blue-600">@{u.username}</td>
                <td className="px-6 py-4 font-bold text-slate-500 uppercase text-[10px]">{u.department}</td>
                <td className="px-6 py-4">
                  <span className={`text-[9px] px-2 py-1 rounded-md font-black uppercase tracking-tight ${u.role === UserRole.QA_Opera ? 'bg-amber-100 text-amber-700' : 'bg-slate-900 text-white'}`}>
                    {ROLE_LABELS[u.role] || u.role}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-md ${u.active ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                    {u.active ? 'ACTIVO' : 'INACTIVO'}
                  </span>
                </td>
                <td className="px-6 py-4 text-right space-x-2">
                   <button onClick={() => setIsEditing(u)} className="p-2 hover:bg-blue-50 rounded-lg text-slate-400 hover:text-blue-600 transition-all">
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
                   </button>
                   <button onClick={() => toggleUserStatus(u.id, !u.active)} className={`p-2 rounded-lg transition-all ${u.active ? 'hover:bg-rose-50 text-slate-300 hover:text-rose-500' : 'hover:bg-emerald-50 text-slate-300 hover:text-emerald-500'}`}>
                      {u.active ? <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/></svg> : <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2v20"/><path d="m5 15 7 7 7-7"/></svg>}
                   </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {isEditing && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[110] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-10 w-full max-w-md shadow-2xl animate-fadeIn border-t-8 border-blue-600">
            <h2 className="text-2xl font-black text-slate-900 mb-2">Configurar Usuario</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mb-8">Gestión de Perfiles APC</p>

            <form onSubmit={handleSave} className="space-y-5">
               <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Nombre Completo</label>
                  <input required value={isEditing.name} onChange={e => setIsEditing({...isEditing, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 transition-all font-bold text-sm" placeholder="Nombre completo" />
               </div>

               <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Username (ID)</label>
                    <input required value={isEditing.username} onChange={e => setIsEditing({...isEditing, username: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 transition-all font-mono text-xs font-bold" placeholder="usuario.id" />
                 </div>
                 <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Password</label>
                    <input required type="text" value={isEditing.password} onChange={e => setIsEditing({...isEditing, password: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 transition-all font-bold text-sm" placeholder="••••••••" />
                 </div>
               </div>

               <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Rol en Sistema</label>
                  <select value={isEditing.role} onChange={e => setIsEditing({...isEditing, role: e.target.value as UserRole})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 font-black text-xs appearance-none cursor-pointer">
                    <option value={UserRole.Admin}>Administrador</option>
                    <option value={UserRole.Cuentas_Lider}>Líder Cuentas</option>
                    <option value={UserRole.Cuentas_Opera}>Ejecutivo Cuentas</option>
                    <option value={UserRole.Lider_Operativo}>Líder Operativo</option>
                    <option value={UserRole.Operativo}>Operativo</option>
                    <option value={UserRole.Correccion}>Líder de QA</option>
                    <option value={UserRole.QA_Opera}>QA Operativo</option>
                  </select>
               </div>

               <div>
                  <label className="text-[10px] font-black text-slate-500 uppercase mb-1.5 block ml-1">Departamento</label>
                  <select value={isEditing.department} onChange={e => setIsEditing({...isEditing, department: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-xl outline-none focus:border-blue-500 font-black text-xs appearance-none cursor-pointer">
                    {ALL_DEPARTMENTS.map(dept => <option key={dept} value={dept}>{dept.toUpperCase()}</option>)}
                  </select>
               </div>

               <div className="flex gap-4 pt-6">
                  <button type="button" onClick={() => setIsEditing(null)} className="flex-1 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-slate-600 transition-colors">Cerrar</button>
                  <button type="submit" className="flex-2 px-8 py-4 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all shadow-xl">Guardar Cambios</button>
