export const GLOBAL_STAGES = {
  START: 'CUENTAS (Gestión)',
  CLOSING: 'CUENTAS (Cierre)',
  BILLING: 'ADMINISTRACIÓN (Facturación)'
} as const;

export const CATEGORIES_CONFIG: Record<string, string[]> = {
