  };

  const handleAudit = async () => {
    setIsAuditing(true);
    const res = await auditProjectISO(project);
    setAuditResult(res);
    setIsAuditing(false);
  };

  const getButtonLabel = () => {
    if (isInitialStage) return `VALIDAR BRIEFING Y ENVIAR A ${roadmapStages[1]}`;
