import React, { createContext, useContext, useState, useEffect } from 'react';
import { ref, onValue, update, get, set } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";
import { db } from './firebase';
import { Project, User, ODTContextType, UserRole, LoginResult, Client } from './types';
import { GLOBAL_STAGES, calculateRoadmap } from './workflowConfig';

const ODTContext = createContext<ODTContextType | undefined>(undefined);

const escapeFirebaseKey = (key: string) => key.toLowerCase().trim().replace(/[\.\#\$\/\[\]]/g, '_');

export const ODTProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('apc_session');
    if (savedSession) {
      try {
        const parsedUser = JSON.parse(savedSession);
        setUser(parsedUser);
      } catch (e) {
        console.error("Error al recuperar sesión", e);
      }
    }
  }, []);

  useEffect(() => {
    if (!db) {
      setLoading(false);
      return;
    }
    const projectsRef = ref(db, 'projects');
    const usersRef = ref(db, 'users');
    const clientsRef = ref(db, 'clients');

    onValue(projectsRef, (s) => {
      const d = s.val();
      setProjects(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
    });

    onValue(usersRef, (s) => {
      const d = s.val();
      setUsers(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
    });

    onValue(clientsRef, (s) => {
      const d = s.val();
      setClients(d ? Object.keys(d).map(k => ({ ...d[k], id: k })) : []);
      setLoading(false);
    });
  }, []);

  const getRoadmapStages = (project: Project) => {
    return calculateRoadmap(project.areas_seleccionadas || []);
  };

  const login = async (username: string, pass: string): Promise<LoginResult> => {
    const cleanUsername = username.toLowerCase().trim();
    const dbKey = escapeFirebaseKey(cleanUsername);
    if (cleanUsername === 'admin' && pass === 'admin') {
      const adminBypass: User = { id: 'admin', name: 'Admin Bypass', username: 'admin', department: 'Sistemas', role: UserRole.Admin, active: true };
      setUser(adminBypass);
      localStorage.setItem('apc_session', JSON.stringify(adminBypass));
      return { success: true };
    }
    try {
      const userRef = ref(db, `users/${dbKey}`);
      const snapshot = await get(userRef);
      if (!snapshot.exists()) return { success: false, error: `Usuario no encontrado.` };
      const userData = snapshot.val();
      if (!userData.active) return { success: false, error: 'Cuenta inactiva.' };
      if (userData.password !== pass) return { success: false, error: 'Contraseña incorrecta.' };
      const authUser: User = { ...userData, id: dbKey };
      setUser(authUser);
      localStorage.setItem('apc_session', JSON.stringify(authUser));
      return { success: true };
    } catch (error: any) {
      return { success: false, error: 'Error de conexión.' };
    }
  };

  const logout = () => { setUser(null); localStorage.removeItem('apc_session'); };

  const addProject = async (projectData: Partial<Project>) => {
    if (!db || !user) return;
    const projectId = projectData.id;
    if (!projectId) return;
    await set(ref(db, `projects/${projectId}`), {
      ...projectData,
      status: 'Borrador',
      current_stage_index: 0,
      etapa_actual: GLOBAL_STAGES.START,
      etapaActual: GLOBAL_STAGES.START,
      ownerId: user.id,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      comentarios: [{ id: `sys-${Date.now()}`, authorId: user.id, authorName: user.name, text: `ODT INICIADA EN ${GLOBAL_STAGES.START.toUpperCase()}`, createdAt: new Date().toISOString(), isSystemEvent: true }],
      asignaciones: [],
      pagado: false,
      facturado: false
    });
  };

  const removeProject = async (projectId: string) => {
    if (!db || user?.role !== UserRole.Admin) return;
    try {
      await set(ref(db, `projects/${projectId}`), null);
    } catch (error) {
      console.error("Fallo al purgar ODT en Firebase:", error);
      throw error;
    }
  };

  const advanceProjectStage = async (projectId: string, comment: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const stages = getRoadmapStages(project);
    const oldStage = stages[project.current_stage_index || 0];
    const newIndex = (project.current_stage_index || 0) + 1;
    const proximaArea = stages[newIndex] || 'Finalizado';

    const linkMatch = comment.match(/Link: (https?:\/\/[^\s|]+)/);
    const link = linkMatch ? linkMatch[1] : (project.last_delivery_link || "");

    let newStatus: Project['status'] = 'En Proceso';
    if (newIndex >= stages.length - 1) newStatus = 'Finalizado';
    else if (proximaArea.toUpperCase().includes('REVISIÓN QA')) newStatus = 'QA';

    const updates: any = {
      current_stage_index: newIndex,
      etapa_actual: proximaArea,
      etapaActual: proximaArea, // Sync for visibility
      status: newStatus,
      last_delivery_link: link,
      last_delivery_comment: comment,
      updatedAt: new Date().toISOString(),
      comentarios: [{ 
        id: `step-${Date.now()}`, 
        authorId: user.id, 
        authorName: user.name, 
        text: comment.includes('Entrega Técnica') ? comment : `Etapa [${oldStage}] completada. Enviado a [${proximaArea}]. Nota: ${comment}`, 
        createdAt: new Date().toISOString(), 
        isSystemEvent: true 
      }, ...(project.comentarios || [])]
    };

    if (newIndex >= stages.length - 1) {
      updates.fecha_finalizado = new Date().toISOString();
    }

    await update(ref(db, `projects/${projectId}`), updates);
  };

  const processQA = async (projectId: string, approved: boolean, feedback: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    const stages = getRoadmapStages(project);
    const qaStageName = stages[project.current_stage_index || 0];

    if (approved) {
      const newIndex = (project.current_stage_index || 0) + 1;
      const proximaAreaCalculada = stages[newIndex] || GLOBAL_STAGES.CLOSING;

      let newStatus: Project['status'] = 'En Proceso';
      if (newIndex >= stages.length - 1) newStatus = 'Finalizado';
      else if (proximaAreaCalculada.toUpperCase().includes('REVISIÓN QA')) newStatus = 'QA';

      const updates: any = {
        current_stage_index: newIndex,
        etapa_actual: proximaAreaCalculada,
        etapaActual: proximaAreaCalculada,
        status: newStatus,
        correccion_ok: true,
        ultimoComentarioQA: 'Aprobado por ' + user.name + (feedback ? ': ' + feedback : ''),
        fechaAprobacionQA: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        comentarios: [{ 
          id: `qa-${Date.now()}`, 
          authorId: user.id, 
          authorName: user.name, 
          text: `APROBADO en [${qaStageName}]. Feedback: ${feedback}`, 
          createdAt: new Date().toISOString(), 
          isSystemEvent: true 
        }, ...(project.comentarios || [])]
      };

      if (newIndex >= stages.length - 1) {
        updates.fecha_finalizado = new Date().toISOString();
      }

      await update(ref(db, `projects/${projectId}`), updates);
      return proximaAreaCalculada;
    } else {
      const newIndex = project.current_stage_index - 1;
      const areaAnterior = stages[newIndex];
      const updates: any = {
        current_stage_index: newIndex,
        etapa_actual: areaAnterior,
        etapaActual: areaAnterior,
        correccion_ok: false,
        status: 'Correcciones',
        ultimoComentarioQA: 'Rechazado por ' + user.name + ': ' + feedback,
        updatedAt: new Date().toISOString(),
        comentarios: [{ 
          id: `qa-${Date.now()}`, 
          authorId: user.id, 
          authorName: user.name, 
          text: `RECHAZADO en [${qaStageName}]. Feedback: ${feedback}. Regresando a [${areaAnterior}].`, 
          createdAt: new Date().toISOString(), 
          isSystemEvent: true 
        }, ...(project.comentarios || [])]
      };
      await update(ref(db, `projects/${projectId}`), updates);
      return areaAnterior;
    }
  };

  const manageUser = async (userData: Partial<User>) => {
    if (!db || !userData.username) throw new Error("Datos incompletos.");
    const dbKey = escapeFirebaseKey(userData.username);
    await set(ref(db, `users/${dbKey}`), { ...userData, username: userData.username.toLowerCase(), createdAt: new Date().toISOString() });
  };

  const toggleUserStatus = async (userId: string, active: boolean) => {
    if (!db) return;
    await update(ref(db, `users/${userId}`), { active });
  };

  const updateBilling = async (projectId: string, facturado: boolean, justification?: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    const newComment = {
      id: `bill-${Date.now()}`,
      authorId: user.id,
      authorName: user.name,
      text: `Facturación: ${facturado ? "SÍ" : "NO"}. Nota: ${justification || 'Sin detalle'}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    await update(ref(db, `projects/${projectId}`), { 
      facturado, 
      justificacion_no_facturado: justification || "", 
      updatedAt: new Date().toISOString(),
      comentarios: [newComment, ...(project?.comentarios || [])]
    });
  };

  const updatePaymentStatus = async (projectId: string, pagado: boolean) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    const newComment = {
      id: `pay-${Date.now()}`,
      authorId: user.id,
      authorName: user.name,
      text: `Pago marcado como: ${pagado ? "PAGADO" : "PENDIENTE"}`,
      createdAt: new Date().toISOString(),
      isSystemEvent: true
    };
    await update(ref(db, `projects/${projectId}`), { 
      pagado, 
      updatedAt: new Date().toISOString(),
      comentarios: [newComment, ...(project?.comentarios || [])]
    });
  };

  const checkSLA = (project: Project) => {
    const lastUpdate = new Date(project.updatedAt || project.createdAt);
    const hours = (new Date().getTime() - lastUpdate.getTime()) / (1000 * 60 * 60);
    return { isAlert: project.status !== 'Finalizado' && hours > 72, reason: hours > 72 ? 'Estancado > 72h' : undefined };
  };

  const delegateProject = async (projectId: string, area: string, userId: string) => {
    if (!db || !user) return;
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const newAsignaciones = [...(project.asignaciones || []).filter(a => a.area !== area), { area, usuarioId: userId, status: 'en_progreso' }];
    await update(ref(db, `projects/${projectId}`), { asignaciones: newAsignaciones, updatedAt: new Date().toISOString() });
  };

  const reassignProjectAndFolder = async (projectId: string, clientId: string, newOwnerId: string, portfolio: boolean = false) => {
    if (!db || !user) return;
    const updates: any = {};
    if (portfolio) {
      updates[`clients/${clientId}/ownerId`] = newOwnerId;
      projects.filter(p => p.clientId === clientId).forEach(p => updates[`projects/${p.id}/ownerId`] = newOwnerId);
    } else {
      updates[`projects/${projectId}/ownerId`] = newOwnerId;
    }
    await update(ref(db), updates);
  };

  return (
    <ODTContext.Provider value={{ 
      user, projects, clients, users, loading, login, logout, 
      updateProjectStatus: async () => {}, updateBrief: async (p, c) => { await update(ref(db, `projects/${p}`), { brief: c, updatedAt: new Date().toISOString() }) }, 
      processQA, updateBilling, updatePaymentStatus,
      checkSLA, delegateProject, reassignProjectAndFolder, addClient: async (n, notes) => {
        const clientId = `CL-${Date.now()}`;
        await set(ref(db, `clients/${clientId}`), { id: clientId, name: n.trim(), notes: notes || '', ownerId: user?.id || 'system', createdAt: new Date().toISOString() });
      }, 
      addProject, removeProject, manageUser, toggleUserStatus, advanceProjectStage, getRoadmapStages
    }}>
      {children}
    </ODTContext.Provider>
  );
};

export const useODT = () => {
  const context = useContext(ODTContext);
  if (!context) throw new Error('useODT error');
  return context;
};

import React, { useState } from 'react';
import { Project, UserRole, ViewState } from './types';
import { Icons } from './constants';
import { ODTProvider, useODT } from './ODTContext';
import { AppRouter } from './AppRouter';
import AdminDashboard from './AdminDashboard';
import LeaderDashboard from './LeaderDashboard';
import ProjectDetail from './ProjectDetail';
import ClientsView from './ClientsView';
import UsersView from './UsersView';
import { db } from './firebase';

const AppContent: React.FC = () => {
  const { user, projects, users, checkSLA, updateBilling, updatePaymentStatus, loading, getRoadmapStages } = useODT();
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  if (!db || loading) {
    return (
      <div className="bg-[#0f172a] h-screen w-screen flex flex-col items-center justify-center gap-6">
        <div className="w-16 h-16 border-4 border-t-blue-500 border-slate-700 rounded-full animate-spin"></div>
        <div className="text-center animate-pulse">
          <h1 className="text-white font-black text-xl tracking-[0.3em] uppercase">Iniciando Servicios APC...</h1>
          <p className="text-slate-500 text-xs mt-2 font-bold tracking-widest uppercase">Estableciendo conexión con Realtime Database</p>
        </div>
      </div>
    );
  }

  const exportMasterCSV = () => {
    const headers = ["ID ODT", "Cliente", "Marca", "Producto", "Fecha Creación", "Fecha Entrega", "Monto", "Facturado", "Pagado", "Días en Sistema"];
    const rows = projects.map(p => {
      const created = new Date(p.createdAt);
      const finished = p.fecha_finalizado ? new Date(p.fecha_finalizado) : new Date();
      const daysInSystem = Math.floor((finished.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));

      return [
        p.id,
        p.empresa,
        p.marca,
        p.producto,
        created.toLocaleDateString(),
        p.fecha_finalizado ? new Date(p.fecha_finalizado).toLocaleDateString() : "Pte",
        p.monto_proyectado,
        p.facturado ? "SÍ" : "NO",
        p.pagado ? "SÍ" : "NO",
        daysInSystem
      ].join(",");
    });

    const csvContent = "data:text/csv;charset=utf-8," + [headers.join(","), ...rows].join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `APC_Master_Report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const renderMyInbox = () => {
    const isGlobalLead = user?.role === UserRole.Admin || user?.role === UserRole.Cuentas_Lider;
    const myProjects = projects?.filter(p => {
      if (isGlobalLead) return true;
      const isDirectlyAssigned = p.asignaciones?.some(a => a.usuarioId === user?.id);
      const isAreaLead = user?.role === UserRole.Lider_Operativo;
      if (isAreaLead) {
        const stages = getRoadmapStages(p);
        const currentStage = stages[p.current_stage_index || 0];
        return currentStage === user?.department;
      }
      return isDirectlyAssigned;
    }) || [];

    return (
      <div className="space-y-6">
        <header className="flex justify-between items-end">
          <div>
            <h1 className="text-3xl font-black">Bandeja Operativa</h1>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
              {isGlobalLead ? 'VISTA GLOBAL DE CARTERA APC' : 'Tareas técnicas asignadas directamente'}
            </p>
          </div>
        </header>
        <div className="bg-white p-6 rounded-xl border-2 border-dashed border-slate-200">
           {myProjects.length === 0 ? (
             <p className="text-slate-400 italic text-center py-10">No tiene tareas asignadas en este momento.</p>
           ) : (
             <ProjectTable projects={myProjects} onView={setSelectedProject} checkSLA={checkSLA} users={users} />
           )}
        </div>
      </div>
    );
  };

  const renderQABox = () => {
    const qaProjects = projects?.filter(p => {
      // Detección robusta de etapa QA por texto (snake y camel case)
      const currentE = (p.etapa_actual || (p as any).etapaActual || '').toUpperCase();
      const inQAStage = currentE.includes('REVISIÓN QA') || p.status === 'QA';

      if (!inQAStage) return false;

      // Líder de QA y Admin: Ven TODO lo que está en etapa de QA
      if (user?.role === UserRole.Correccion || user?.role === UserRole.Admin) return true;

      // QA Operativo: Solo ve lo que tiene asignado expresamente bajo el área 'QA'
      if (user?.role === UserRole.QA_Opera) {
        return p.asignaciones?.some(a => a.usuarioId === user?.id && a.area === 'QA');
      }

      return false;
    }) || [];

    return (
      <div className="space-y-6 animate-fadeIn">
        <header>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Caja de QA</h1>
          <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1 italic">
            {user?.role === UserRole.Correccion || user?.role === UserRole.Admin ? 'Supervisión Global de Calidad (Todas las Revisiones)' : 'Tareas de Revisión Delegadas a su Perfil'}
          </p>
        </header>
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl">
           {qaProjects.length === 0 ? (
             <div className="text-center py-20">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
                   <Icons.Ai />
                </div>
                <p className="text-slate-400 italic font-medium">No hay revisiones técnicas pendientes en este momento.</p>
             </div>
           ) : (
             <ProjectTable 
               projects={qaProjects} 
               onView={setSelectedProject} 
               checkSLA={checkSLA} 
               users={users}
               highlightUnassigned={user?.role === UserRole.Correccion || user?.role === UserRole.Admin} 
             />
           )}
        </div>
      </div>
    );
  };

  const renderFinances = () => {
    const now = new Date();
    const billingProjects = projects?.filter(p => {
      const stages = getRoadmapStages(p);
      const closingIndex = stages.indexOf("CUENTAS (Cierre)");
      return p.current_stage_index >= closingIndex;
    }) || [];

    return (
      <div className="space-y-8 animate-fadeIn">
        <header className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Módulo de Facturación</h1>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1 italic">Control de Tesorería - APC Realtime</p>
          </div>
          <button 
            onClick={exportMasterCSV}
            className="px-6 py-3 bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-slate-800 transition-all flex items-center gap-2 shadow-xl"
          >
            <Icons.Dashboard /> EXPORTAR REPORTE MAESTRO (CSV)
          </button>
        </header>

        <div className="bg-white rounded-3xl border border-slate-100 shadow-2xl overflow-hidden">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-black tracking-widest">
              <tr>
                <th className="px-6 py-5">Identificador ODT</th>
                <th className="px-6 py-5">Cliente / Producto</th>
                <th className="px-6 py-5">Monto Proyectado</th>
                <th className="px-6 py-5 text-center">Fact..</th>
                <th className="px-6 py-5 text-center">Pagado</th>
                <th className="px-6 py-5">Estatus de Cobro</th>
                <th className="px-6 py-5 text-right">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {billingProjects.map(p => {
                const stages = getRoadmapStages(p);
                const currentStage = stages[p.current_stage_index || 0];
                const lastUpdate = new Date(p.updatedAt);
                const daysInStage = Math.floor((now.getTime() - lastUpdate.getTime()) / (1000 * 60 * 60 * 24));
                const isLateBilling = currentStage === "CUENTAS (Cierre)" && daysInStage >= 3 && !p.facturado;

                return (
                  <tr key={p.id} className={`hover:bg-slate-50/80 transition-all ${isLateBilling ? 'bg-rose-50' : ''}`}>
                    <td className="px-6 py-4 font-mono font-black text-blue-600 text-xs">
                      {p.id}
                      {isLateBilling && (
                        <div className="text-[9px] text-rose-600 font-black animate-pulse flex items-center gap-1 mt-1">
                          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M12 2v10"/><path d="M12 16v.01"/></svg>
                          RIESGO DE FACTURACIÓN (+3D)
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4">
                      <div className="font-black text-slate-800 uppercase text-xs">{p.empresa}</div>
                      <div className="text-[10px] text-slate-400 font-bold">{p.producto}</div>
                    </td>
                    <td className="px-6 py-4 font-black text-slate-900">
                      ${p.monto_proyectado?.toLocaleString()}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <input 
                        type="checkbox" 
                        checked={p.facturado} 
                        onChange={e => updateBilling(p.id, e.target.checked)}
                        className="w-6 h-6 accent-blue-600 cursor-pointer rounded-lg" 
                      />
                    </td>
                    <td className="px-6 py-4 text-center">
                      <input 
                        type="checkbox" 
                        checked={p.pagado} 
                        onChange={e => updatePaymentStatus(p.id, e.target.checked)}
                        className="w-6 h-6 accent-emerald-600 cursor-pointer rounded-lg" 
                      />
                    </td>
                    <td className="px-6 py-4">
                       <span className={`px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                         p.pagado ? 'bg-emerald-100 text-emerald-700' : 
                         p.facturado ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-500'
                       }`}>
                         {p.pagado ? 'CONCILIADO' : p.facturado ? 'FACTURADO' : 'POR FACTURAR'}
                       </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                       <button onClick={() => setSelectedProject(p)} className="p-2 hover:bg-slate-200 rounded-xl transition-all">
                          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>
                       </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {billingProjects.length === 0 && (
            <div className="p-20 text-center text-slate-300 font-black uppercase tracking-[0.3em] text-xs">
              No hay proyectos en ciclo de cierre financiero
            </div>
          )}
        </div>
      </div>
    );
  };

  const renderView = (view: ViewState) => {
    if (selectedProject) return <ProjectDetail project={selectedProject} onBack={() => setSelectedProject(null)} />;
    switch (view) {
      case 'dashboard': return <AdminDashboard />;
      case 'leader-dashboard': return <LeaderDashboard />;
      case 'my-projects': return renderMyInbox();
      case 'clients': return <ClientsView />;
      case 'qa-box': return renderQABox();
      case 'finances': return renderFinances();
      case 'users': return <UsersView />;
      default: return <AdminDashboard />;
    }
  };

  return <AppRouter renderView={renderView} />;
};

const ProjectTable = ({ projects, onView, checkSLA, highlightUnassigned, users }: any) => (
  <div className="bg-white rounded-xl border border-slate-200 overflow-hidden shadow-sm">
    <table className="w-full text-sm text-left">
      <thead className="bg-slate-50 text-slate-500 font-black text-[10px] uppercase tracking-widest">
        <tr>
          <th className="px-6 py-5">ODT ID</th>
          <th className="px-6 py-5">Proyecto / Cliente</th>
          <th className="px-6 py-5">Responsable</th>
          <th className="px-6 py-5">Status</th>
          <th className="px-6 py-5">SLA</th>
          <th className="px-6 py-5 text-right">Acciones</th>
        </tr>
      </thead>
      <tbody className="divide-y divide-slate-100">
        {projects?.map((p: Project) => {
          const sla = checkSLA(p);
          const qaAsignment = p.asignaciones?.find(a => a.area === 'QA');
          const responsible = users?.find((u: any) => u.id === qaAsignment?.usuarioId);
          const isUnassigned = highlightUnassigned && !responsible;

          return (
            <tr key={p?.id} className={`hover:bg-slate-50/50 transition-all ${isUnassigned ? 'bg-amber-50/30 font-bold' : sla?.isAlert ? 'bg-pink-50/20' : ''}`}>
              <td className="px-6 py-4 font-mono font-black text-blue-600 text-xs">
                {p?.id}
                {isUnassigned && (
                  <div className="text-[8px] text-amber-600 font-black animate-pulse mt-1 tracking-tighter uppercase">
                    Pendiente Asignar
                  </div>
                )}
              </td>
              <td className="px-6 py-4">
                <div className="font-bold text-slate-800 truncate max-w-[200px]">{p?.empresa}</div>
                <div className="text-[10px] text-slate-400 font-medium uppercase truncate max-w-[200px]">{p?.producto}</div>
              </td>
              <td className="px-6 py-4">
                 {responsible ? (
                    <div className="flex items-center gap-2">
                       <div className="w-6 h-6 rounded-full bg-slate-100 flex items-center justify-center text-[8px] font-black border border-slate-200">
                          {responsible.name.substring(0,2).toUpperCase()}
                       </div>
                       <span className="text-[10px] font-bold text-slate-600 uppercase">{responsible.name}</span>
                    </div>
                 ) : (
                    <span className="text-[10px] font-black text-rose-300 italic uppercase">Sin Asignar</span>
                 )}
              </td>
              <td className="px-6 py-4">
                <span className={`px-2.5 py-1 rounded text-[10px] font-black uppercase tracking-tighter ${p?.status === 'QA' ? 'bg-amber-100 text-amber-700 shadow-sm' : 'bg-slate-100 text-slate-600'}`}>
                  {p?.status}
                </span>
                <div className="text-[7px] font-black text-slate-400 mt-0.5 truncate max-w-[80px] uppercase">{(p?.etapa_actual || (p as any).etapaActual)}</div>
              </td>
              <td className="px-6 py-4">
                {sla?.isAlert ? (
                  <span className="text-pink-600 text-[10px] font-black animate-pulse flex items-center gap-1">
                    <Icons.Plus /> CRÍTICO
                  </span>
                ) : (
                  <span className="text-emerald-500 text-[10px] font-bold uppercase tracking-widest">OK</span>
                )}
              </td>
              <td className="px-6 py-4 text-right">
                <button onClick={() => onView(p)} className="text-blue-600 font-black hover:text-blue-800 transition-colors text-xs border-b-2 border-transparent hover:border-blue-800 pb-0.5">DETALLE</button>
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  </div>
);

const App: React.FC = () => (
  <ODTProvider>
    <AppContent />
  </ODTProvider>
);

export default App;

import React, { useMemo, useState } from 'react';
import { useODT } from './ODTContext';
import { UserRole, Project } from './types';

const LeaderDashboard: React.FC = () => {
  const { user, projects, users, checkSLA, delegateProject } = useODT();
  const [memberFilter, setMemberFilter] = useState('all');

  const leaderArea = useMemo(() => {
    if (user?.department === 'QA' || user?.role === UserRole.Correccion) return 'QA';
    if (user?.department === 'Creativo') return 'Creativo';
    if (user?.department === 'Diseño') return 'Diseño';
    if (user?.department === 'Digital') return 'Digital';
    return user?.department || '';
  }, [user]);

  const teamMembers = useMemo(() => {
    if (!user) return [];
    return users.filter(u => u.department === user.department);
  }, [user, users]);

  const areaProjects = useMemo(() => {
    if (!leaderArea) return [];

    let filtered: Project[] = [];

    // Filtro unificado para Líder de Calidad / Corrección
    if (leaderArea === 'QA' || user?.role === UserRole.Correccion) {
      filtered = projects.filter(p => {
        const stageStr = (p.etapa_actual || (p as any).etapaActual || '').toUpperCase();
        return stageStr.includes('REVISIÓN QA') || p.status === 'QA';
      });
    } else {
      // Otros líderes operativos ven ODTs activas de su área ISO
      filtered = projects.filter(p => p.areas_seleccionadas?.includes(leaderArea));
    }

    if (memberFilter !== 'all') {
      filtered = filtered.filter(p => p.asignaciones?.some(a => a.usuarioId === memberFilter));
    }

    return filtered;
  }, [projects, leaderArea, memberFilter, user]);

  return (
    <div className="space-y-8 animate-fadeIn">
      <header className="flex justify-between items-center border-b pb-6">
        <div>
          <h1 className="text-2xl font-black uppercase tracking-tight">Control de Área: {user?.department || 'CALIDAD'}</h1>
          <p className="text-sm text-slate-500 font-bold uppercase tracking-widest mt-1">Supervisión Técnica Operativa (ISO 9001)</p>
        </div>
        <div className="flex flex-col items-end">
          <label className="text-[9px] font-black text-slate-400 uppercase mb-1 mr-1">Filtrar por Colaborador</label>
          <select className="bg-white border rounded-xl px-4 py-2 text-xs font-bold outline-none shadow-sm focus:ring-2 focus:ring-blue-500" value={memberFilter} onChange={(e) => setMemberFilter(e.target.value)}>
            <option value="all">TODO EL EQUIPO</option>
            {teamMembers.map(m => <option key={m.id} value={m.id}>{m.id === user?.id ? `YO (${m.name.toUpperCase()})` : m.name.toUpperCase()}</option>)}
          </select>
        </div>
      </header>

      {/* Tarjetas de Carga del Equipo */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {teamMembers.map(m => {
          const load = projects.filter(p => p.asignaciones?.some(a => a.usuarioId === m.id) && p.status !== 'Finalizado').length;
          const isMe = m.id === user?.id;

          return (
            <div key={m.id} className={`p-5 rounded-2xl border transition-all shadow-sm hover:shadow-md ${isMe ? 'bg-blue-50/50 border-blue-200' : 'bg-white border-slate-100'}`}>
              <div className="flex justify-between items-start mb-3">
                <p className={`text-xs font-black truncate pr-2 ${isMe ? 'text-blue-700' : 'text-slate-800'}`}>
                  {isMe ? 'Mi Carga (Líder)' : m.name}
                </p>
                <span className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase ${
                  m.role.includes('Lider') || m.role === UserRole.Correccion ? 'bg-blue-600 text-white' :
                  m.role === UserRole.QA_Opera ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-500'
                }`}>
                  {m.role.includes('Lider') || m.role === UserRole.Correccion ? 'LÍDER' : m.role === UserRole.QA_Opera ? 'QA' : 'OP'}
                </span>
              </div>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">Carga: {load} ODTs Activas</p>
              <div className="w-full bg-slate-200/50 h-2 rounded-full mt-3 overflow-hidden border border-slate-100">
                <div 
                  className={`h-full transition-all duration-500 ${load > 5 ? 'bg-rose-500' : load > 3 ? 'bg-amber-500' : 'bg-blue-500'}`} 
                  style={{width: `${Math.min((load/8)*100, 100)}%`}}
                ></div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Tabla de Gestión de ODTs */}
      <div className="bg-white rounded-3xl border border-slate-100 shadow-xl overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-400 uppercase text-[10px] font-black tracking-widest">
            <tr>
              <th className="px-6 py-5">ODT / Empresa</th>
              <th className="px-6 py-5">Responsable Asignado</th>
              <th className="px-6 py-5">Estado de Fase</th>
              <th className="px-6 py-5 text-right">Delegar Gestión</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {areaProjects.length === 0 ? (
              <tr>
                <td colSpan={4} className="px-6 py-10 text-center text-slate-300 italic font-medium uppercase text-[10px] tracking-widest">No hay proyectos activos requiriendo gestión en esta área estratégica.</td>
              </tr>
            ) : (
              areaProjects.map(p => {
                const currentAssignmentArea = (user?.role === UserRole.Correccion || user?.department === 'QA') ? 'QA' : leaderArea;
                const currentAssignment = p.asignaciones?.find(a => a.area === 'QA'); // Siempre buscamos 'QA' para el líder de calidad
                const isAssignedToMe = currentAssignment?.usuarioId === user?.id;

                return (
                  <tr key={p.id} className={`hover:bg-slate-50/80 transition-colors ${isAssignedToMe ? 'bg-blue-50/20' : ''}`}>
                    <td className="px-6 py-4">
                      <p className="font-mono font-black text-blue-600 text-xs">{p.id}</p>
                      <p className="text-[10px] font-bold text-slate-800 uppercase truncate max-w-[200px]">{p.empresa}</p>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                         <div className={`w-2 h-2 rounded-full ${currentAssignment ? 'bg-blue-600 shadow-sm' : 'bg-rose-300 animate-pulse'}`}></div>
                         <span className={`text-xs font-bold uppercase ${currentAssignment ? 'text-slate-600' : 'text-rose-400 italic'}`}>
                           {users.find(m => m.id === currentAssignment?.usuarioId)?.name || 'PENDIENTE ASIGNAR'}
                         </span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`text-[9px] font-black px-2 py-1 rounded uppercase tracking-tighter ${p.status === 'QA' ? 'bg-amber-100 text-amber-700 shadow-sm' : 'bg-slate-100 text-slate-500'}`}>
                        {p.status}
                      </span>
                      <div className="text-[7px] font-black text-slate-400 mt-0.5 uppercase">{(p.etapa_actual || (p as any).etapaActual)}</div>
                    </td>
                    <td className="px-6 py-4 text-right">
                       <select 
                         className={`border-none rounded-lg px-3 py-1.5 text-[10px] font-black uppercase tracking-widest cursor-pointer transition-all outline-none ${
                           currentAssignment ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-slate-900 text-white hover:bg-slate-800 animate-bounce'
                         }`} 
                         onChange={(e) => {
                           if (e.target.value) delegateProject(p.id, 'QA', e.target.value);
                         }}
                         value={currentAssignment?.usuarioId || ''}
                       >
                         <option value="">-- ASIGNAR REVISOR --</option>
                         {teamMembers.map(m => (
                           <option key={m.id} value={m.id}>
                             {m.id === user?.id ? `MI PERSONA (${m.name.toUpperCase()})` : m.name.toUpperCase()}
                           </option>
                         ))}
                       </select>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default LeaderDashboard;
